-- Name: add_pending_leave_on_insert(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.add_pending_leave_on_insert() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    IF NEW.status = 'pending' THEN
        UPDATE leave_balances
        SET pending_days = pending_days + NEW.total_days
        WHERE employee_id = NEW.employee_id
        AND leave_type_id = NEW.leave_type_id
        AND year = EXTRACT(YEAR FROM NEW.start_date);
    END IF;
    RETURN NEW;
END;
$$;


--
-- Name: advance_transaction_stage(text, uuid, text, uuid, text, text, text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.advance_transaction_stage(p_type text, p_transaction_id uuid, p_new_stage text, p_user_id uuid, p_user_name text DEFAULT NULL::text, p_notes text DEFAULT NULL::text, p_cancellation_reason text DEFAULT NULL::text, p_ip_address text DEFAULT NULL::text, p_user_agent text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $_$
DECLARE
    v_current_stage TEXT;
    v_company_id UUID;
    v_tenant_id UUID;
    v_generated_no TEXT;
    v_number_field TEXT;
    v_date_field TEXT;
    v_user_field TEXT;
    v_user_name_field TEXT;
    v_at_field TEXT;
    v_sql TEXT;
BEGIN
    -- 1. قفل السجل وقراءة المرحلة الحالية
    IF p_type = 'purchase' THEN
        SELECT stage, company_id, tenant_id
        INTO v_current_stage, v_company_id, v_tenant_id
        FROM purchase_transactions
        WHERE id = p_transaction_id
        FOR UPDATE;
    ELSE
        SELECT stage, company_id, tenant_id
        INTO v_current_stage, v_company_id, v_tenant_id
        FROM sales_transactions
        WHERE id = p_transaction_id
        FOR UPDATE;
    END IF;

    IF v_current_stage IS NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'المعاملة غير موجودة');
    END IF;

    -- 2. التحقق من صلاحية التحويل
    IF NOT is_valid_stage_transition(p_type, v_current_stage, p_new_stage) THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', format('تحويل غير مسموح: %s → %s', v_current_stage, p_new_stage)
        );
    END IF;

    -- 3. تحديد حقول المستخدم لهذه المرحلة
    v_user_field := CASE p_new_stage
        WHEN 'quotation' THEN 'quoted_by'
        WHEN 'reservation' THEN 'reserved_by'
        WHEN 'order' THEN 'ordered_by'
        WHEN 'approved' THEN 'approved_by'
        WHEN 'receipt' THEN 'received_by'
        WHEN 'delivery' THEN 'delivered_by'
        WHEN 'invoice' THEN 'invoiced_by'
        WHEN 'posted' THEN 'posted_by'
        WHEN 'cancelled' THEN 'cancelled_by'
        ELSE NULL
    END;

    v_user_name_field := CASE WHEN v_user_field IS NOT NULL THEN v_user_field || '_name' ELSE NULL END;

    v_at_field := CASE p_new_stage
        WHEN 'quotation' THEN 'quoted_at'
        WHEN 'reservation' THEN 'reserved_at'
        WHEN 'order' THEN 'ordered_at'
        WHEN 'approved' THEN 'approved_at'
        WHEN 'receipt' THEN 'received_at'
        WHEN 'delivery' THEN 'delivered_at'
        WHEN 'invoice' THEN 'invoiced_at'
        WHEN 'posted' THEN 'posted_at'
        WHEN 'cancelled' THEN 'cancelled_at'
        ELSE NULL
    END;

    -- 4. توليد رقم
    IF p_new_stage IN ('quotation', 'reservation', 'order', 'receipt', 'delivery', 'invoice') THEN
        v_generated_no := generate_stage_number(v_tenant_id, v_company_id, p_type, p_new_stage);
        v_number_field := p_new_stage || '_no';
        v_date_field := p_new_stage || '_date';
    END IF;

    -- 5. تحديث السجل
    IF p_type = 'purchase' THEN
        v_sql := 'UPDATE purchase_transactions SET stage = $1, updated_at = NOW(), updated_by = $2';
    ELSE
        v_sql := 'UPDATE sales_transactions SET stage = $1, updated_at = NOW(), updated_by = $2';
    END IF;

    IF v_number_field IS NOT NULL AND v_generated_no IS NOT NULL THEN
        v_sql := v_sql || format(', %I = %L', v_number_field, v_generated_no);
        v_sql := v_sql || format(', %I = CURRENT_DATE', v_date_field);
    END IF;

    IF v_user_field IS NOT NULL THEN
        v_sql := v_sql || format(', %I = %L', v_user_field, p_user_id);
        IF p_user_name IS NOT NULL AND v_user_name_field IS NOT NULL THEN
            v_sql := v_sql || format(', %I = %L', v_user_name_field, p_user_name);
        END IF;
        IF v_at_field IS NOT NULL THEN
            v_sql := v_sql || format(', %I = NOW()', v_at_field);
        END IF;
    END IF;

    IF p_new_stage = 'posted' THEN
        v_sql := v_sql || ', is_posted = true';
    END IF;

    IF p_new_stage = 'cancelled' AND p_cancellation_reason IS NOT NULL THEN
        v_sql := v_sql || format(', cancellation_reason = %L', p_cancellation_reason);
    END IF;

    IF p_new_stage = 'approved' AND p_notes IS NOT NULL THEN
        v_sql := v_sql || format(', approval_notes = %L', p_notes);
    END IF;

    v_sql := v_sql || ' WHERE id = $3';

    EXECUTE v_sql USING p_new_stage, p_user_id, p_transaction_id;

    -- 6. تسجيل في سجل المراحل
    INSERT INTO transaction_stage_log (
        transaction_type, transaction_id,
        from_stage, to_stage,
        generated_number, notes,
        performed_by, performed_by_name, ip_address, user_agent
    ) VALUES (
        p_type, p_transaction_id,
        v_current_stage, p_new_stage,
        v_generated_no, COALESCE(p_notes, p_cancellation_reason),
        p_user_id, p_user_name, p_ip_address, p_user_agent
    );

    -- 7. النتيجة
    RETURN jsonb_build_object(
        'success', true,
        'from_stage', v_current_stage,
        'to_stage', p_new_stage,
        'generated_number', v_generated_no,
        'performed_by', p_user_id,
        'performed_by_name', p_user_name
    );
END;
$_$;


--
-- Name: apply_audit_trigger(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.apply_audit_trigger(p_table_name text) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_trigger_name TEXT;
BEGIN
    v_trigger_name := 'trg_audit_' || p_table_name;
    
    -- حذف Trigger القديم
    EXECUTE format('DROP TRIGGER IF EXISTS %I ON %I', v_trigger_name, p_table_name);
    
    -- إنشاء Trigger جديد
    EXECUTE format('
        CREATE TRIGGER %I
        AFTER INSERT OR UPDATE OR DELETE ON %I
        FOR EACH ROW
        EXECUTE FUNCTION auto_audit_log()
    ', v_trigger_name, p_table_name);
    
    RAISE NOTICE '✅ تم تطبيق Audit Trigger على %', p_table_name;
EXCEPTION
    WHEN OTHERS THEN
        RAISE NOTICE '⚠️ فشل تطبيق Audit على %: %', p_table_name, SQLERRM;
END;
$$;


--
-- Name: apply_chart_template_to_company(uuid, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.apply_chart_template_to_company(p_company_id uuid, p_template_code character varying) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    IF p_template_code IN ('extended', 'EXTENDED') THEN
        PERFORM create_extended_chart(p_company_id);
        RAISE NOTICE 'V6 — تم تطبيق الشجرة الموسعة V5.2 على الشركة %', p_company_id;
    ELSE
        PERFORM create_simple_chart(p_company_id);
        RAISE NOTICE 'V6 — تم تطبيق الشجرة القياسية V5.1 على الشركة %', p_company_id;
    END IF;
END;
$$;


--
-- Name: approve_delivery_note(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.approve_delivery_note(p_note_id uuid, p_approved_by uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_note RECORD;
BEGIN
    SELECT * INTO v_note FROM delivery_notes WHERE id = p_note_id;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'Delivery note not found');
    END IF;
    
    IF v_note.status != 'pending_approval' THEN
        RETURN jsonb_build_object('success', false, 'error', 'Note is not pending approval');
    END IF;
    
    UPDATE delivery_notes
    SET 
        status = 'approved',
        approved_by = p_approved_by,
        approved_at = NOW()
    WHERE id = p_note_id;
    
    RETURN jsonb_build_object(
        'success', true,
        'note_id', p_note_id,
        'status', 'approved'
    );
END;
$$;


--
-- Name: auto_audit_log(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.auto_audit_log() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_action VARCHAR(50);
    v_old_values JSONB;
    v_new_values JSONB;
    v_entity_name VARCHAR(255);
BEGIN
    -- تحديد نوع العملية
    IF TG_OP = 'INSERT' THEN
        v_action := 'create';
        v_new_values := to_jsonb(NEW);
        v_new_values := to_jsonb(NEW);
        v_entity_name := COALESCE(
            v_new_values ->> 'name',
            v_new_values ->> 'name_ar',
            v_new_values ->> 'name_en',
            v_new_values ->> 'code',
            v_new_values ->> 'id'
        );
    ELSIF TG_OP = 'UPDATE' THEN
        v_action := 'update';
        v_old_values := to_jsonb(OLD);
        v_new_values := to_jsonb(NEW);
        v_new_values := to_jsonb(NEW);
        v_entity_name := COALESCE(
            v_new_values ->> 'name',
            v_new_values ->> 'name_ar',
            v_new_values ->> 'name_en',
            v_new_values ->> 'code',
            v_new_values ->> 'id'
        );
    ELSIF TG_OP = 'DELETE' THEN
        v_action := 'delete';
        v_old_values := to_jsonb(OLD);
        v_old_values := to_jsonb(OLD);
        v_entity_name := COALESCE(
            v_old_values ->> 'name',
            v_old_values ->> 'name_ar',
            v_old_values ->> 'name_en',
            v_old_values ->> 'code',
            v_old_values ->> 'id'
        );
    END IF;
    
    -- تسجيل
    PERFORM log_audit(
        v_action::character varying,
        TG_TABLE_NAME::character varying,
        COALESCE(NEW.id, OLD.id),
        v_entity_name::character varying,
        v_old_values,
        v_new_values
    );
    
    RETURN COALESCE(NEW, OLD);
END;
$$;


--
-- Name: auto_calculate_invoice_commission(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.auto_calculate_invoice_commission() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_commission RECORD;
    v_period_start DATE;
    v_period_end DATE;
BEGIN
    -- فقط عند ترحيل الفاتورة
    IF NEW.status = 'posted' AND (OLD.status IS NULL OR OLD.status != 'posted') THEN
        -- تحديد فترة العمولة (الشهر الحالي)
        v_period_start := DATE_TRUNC('month', NEW.invoice_date)::DATE;
        v_period_end := (DATE_TRUNC('month', NEW.invoice_date) + INTERVAL '1 month' - INTERVAL '1 day')::DATE;
        
        -- حساب وإنشاء العمولات
        FOR v_commission IN 
            SELECT * FROM calculate_sales_commission(NEW.id, NEW.salesperson_id)
        LOOP
            INSERT INTO employee_commissions (
                tenant_id, company_id,
                employee_id, plan_id,
                period_start, period_end,
                source_type, source_id, source_number,
                base_amount, rate_applied, commission_amount,
                tier_number, net_amount,
                status
            )
            VALUES (
                NEW.tenant_id, NEW.company_id,
                v_commission.employee_id, v_commission.plan_id,
                v_period_start, v_period_end,
                'sales_invoice', NEW.id, NEW.invoice_number,
                v_commission.base_amount, v_commission.rate_applied, v_commission.commission_amount,
                v_commission.tier_applied, v_commission.commission_amount,
                'calculated'
            );
        END LOOP;
    END IF;
    
    RETURN NEW;
END;
$$;


--
-- Name: auto_create_customer_sub_account(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.auto_create_customer_sub_account() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_parent_id UUID;
    v_type_id UUID;
    v_tenant_id UUID;
    v_seq INT;
    v_new_code TEXT;
    v_new_id UUID;
    v_parent_code TEXT;
BEGIN
    -- ═══ تحديد الحساب الأب حسب نوع العميل ═══
    IF NEW.customer_type = 'exchange' THEN
        -- زبائن الصرافة → تحت 133
        SELECT id, account_type_id, account_code
        INTO v_parent_id, v_type_id, v_parent_code
        FROM chart_of_accounts
        WHERE company_id = NEW.company_id
          AND account_code = '133'
          AND (is_group = true OR is_detail = false)
        LIMIT 1;
    ELSE
        -- عملاء عاديون → تحت 1131 أو 113 أو 1130
        SELECT id, account_type_id, account_code
        INTO v_parent_id, v_type_id, v_parent_code
        FROM chart_of_accounts
        WHERE company_id = NEW.company_id
          AND account_code IN ('1131', '113', '1130', '1310', '1311')
          AND (is_group = true OR is_detail = false)
        ORDER BY CASE account_code WHEN '1131' THEN 1 WHEN '113' THEN 2 ELSE 3 END
        LIMIT 1;
    END IF;

    IF v_parent_id IS NULL THEN RETURN NEW; END IF;

    SELECT tenant_id INTO v_tenant_id FROM chart_of_accounts WHERE id = v_parent_id;

    SELECT COUNT(*) + 1 INTO v_seq
    FROM chart_of_accounts WHERE parent_id = v_parent_id AND is_party_account = true;

    v_new_code := v_parent_code || '-' || LPAD(v_seq::TEXT, 3, '0');

    INSERT INTO chart_of_accounts (
        id, account_code, name_ar, name_en,
        parent_id, company_id, tenant_id, account_type_id,
        is_group, is_detail, is_system, is_party_account,
        party_id, party_type, current_balance,
        currency
    ) VALUES (
        gen_random_uuid(), v_new_code, NEW.name_ar, NEW.name_en,
        v_parent_id, NEW.company_id, v_tenant_id, v_type_id,
        false, true, false, true, NEW.id, 'customer', 0,
        COALESCE(NEW.currency, 'USD')
    ) RETURNING id INTO v_new_id;

    NEW.receivable_account_id := v_new_id;
    RETURN NEW;
END;
$$;


--
-- Name: auto_create_employee_sub_account(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.auto_create_employee_sub_account() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_parent_id UUID;
    v_type_id UUID;
    v_tenant_id UUID;
    v_seq INT;
    v_new_code TEXT;
    v_new_id UUID;
    v_emp_name_ar TEXT;
    v_emp_name_en TEXT;
BEGIN
    -- البحث عن حساب الرواتب المستحقة
    SELECT id, account_type_id INTO v_parent_id, v_type_id
    FROM chart_of_accounts
    WHERE company_id = NEW.company_id
      AND account_code IN ('213', '2120', '2130', '214')
      AND (is_group = true OR is_detail = false)
    ORDER BY CASE account_code WHEN '213' THEN 1 WHEN '2120' THEN 2 WHEN '214' THEN 3 ELSE 4 END
    LIMIT 1;

    IF v_parent_id IS NULL THEN 
        RAISE NOTICE '⚠️ حساب الرواتب (213) غير موجود — تخطي';
        RETURN NEW; 
    END IF;

    SELECT tenant_id INTO v_tenant_id FROM chart_of_accounts WHERE id = v_parent_id;

    -- حساب التسلسل (تجاهل الحساب الملخص)
    SELECT COUNT(*) + 1 INTO v_seq
    FROM chart_of_accounts 
    WHERE parent_id = v_parent_id 
      AND is_party_account = true;

    v_new_code := (SELECT account_code FROM chart_of_accounts WHERE id = v_parent_id)
                  || '-' || LPAD(v_seq::TEXT, 3, '0');

    v_emp_name_ar := TRIM(NEW.first_name_ar || ' ' || COALESCE(NEW.last_name_ar, ''));
    v_emp_name_en := TRIM(COALESCE(NEW.first_name_en, '') || ' ' || COALESCE(NEW.last_name_en, ''));

    INSERT INTO chart_of_accounts (
        id, account_code, name_ar, name_en,
        parent_id, company_id, tenant_id, account_type_id,
        is_group, is_detail, is_system, is_party_account,
        party_id, party_type, current_balance
    ) VALUES (
        gen_random_uuid(), v_new_code, v_emp_name_ar, v_emp_name_en,
        v_parent_id, NEW.company_id, v_tenant_id, v_type_id,
        false, true, false, true, NEW.id, 'employee', 0
    ) RETURNING id INTO v_new_id;

    NEW.payable_account_id := v_new_id;

    RAISE NOTICE '✅ حساب فرعي للموظف: % (كود: %)', v_emp_name_ar, v_new_code;
    RETURN NEW;
END;
$$;


--
-- Name: auto_create_supplier_sub_account(); Type: FUNCTION; Schema: public; Owner: -
--

