--

CREATE FUNCTION public.belongs_to_tenant(p_tenant_id uuid) RETURNS boolean
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
BEGIN
    RETURN get_current_tenant_id() = p_tenant_id;
END;
$$;


--
-- Name: calc_transaction_balance(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calc_transaction_balance() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    NEW.balance := COALESCE(NEW.total_amount, 0) - COALESCE(NEW.paid_amount, 0);
    NEW.updated_at := NOW();
    RETURN NEW;
END;
$$;


--
-- Name: calculate_import_job_stats(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_import_job_stats(p_job_id uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_stats RECORD;
BEGIN
    SELECT 
        COUNT(*) as total,
        COUNT(*) FILTER (WHERE status = 'valid') as valid,
        COUNT(*) FILTER (WHERE status = 'invalid') as invalid,
        COUNT(*) FILTER (WHERE status = 'imported') as imported,
        COUNT(*) FILTER (WHERE status = 'skipped') as skipped,
        COUNT(*) FILTER (WHERE status = 'failed') as failed
    INTO v_stats
    FROM import_rows
    WHERE job_id = p_job_id;
    
    UPDATE import_jobs
    SET 
        total_rows = v_stats.total,
        valid_rows = v_stats.valid,
        invalid_rows = v_stats.invalid,
        imported_rows = v_stats.imported,
        skipped_rows = v_stats.skipped,
        failed_rows = v_stats.failed,
        updated_at = NOW()
    WHERE id = p_job_id;
END;
$$;


--
-- Name: calculate_next_execution_date(character varying, date, integer, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_next_execution_date(p_frequency character varying, p_current_date date, p_day_of_week integer DEFAULT NULL::integer, p_day_of_month integer DEFAULT NULL::integer, p_month_of_year integer DEFAULT NULL::integer) RETURNS date
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_next_date DATE;
    v_temp_date DATE;
BEGIN
    CASE p_frequency
        WHEN 'daily' THEN
            v_next_date := p_current_date + INTERVAL '1 day';
            
        WHEN 'weekly' THEN
            -- الأسبوع القادم في نفس اليوم
            v_next_date := p_current_date + INTERVAL '7 days';
            -- إذا تم تحديد يوم معين
            IF p_day_of_week IS NOT NULL THEN
                v_next_date := p_current_date + ((7 + p_day_of_week - EXTRACT(DOW FROM p_current_date)::INT) % 7 + 7)::INT;
            END IF;
            
        WHEN 'monthly' THEN
            -- الشهر القادم
            v_temp_date := p_current_date + INTERVAL '1 month';
            IF p_day_of_month IS NOT NULL THEN
                -- تحديد اليوم المطلوب
                v_next_date := DATE_TRUNC('month', v_temp_date) + (LEAST(p_day_of_month, 
                    EXTRACT(DAY FROM (DATE_TRUNC('month', v_temp_date) + INTERVAL '1 month' - INTERVAL '1 day'))::INT) - 1) * INTERVAL '1 day';
            ELSE
                v_next_date := v_temp_date;
            END IF;
            
        WHEN 'quarterly' THEN
            -- الربع القادم
            v_temp_date := p_current_date + INTERVAL '3 months';
            IF p_day_of_month IS NOT NULL THEN
                v_next_date := DATE_TRUNC('month', v_temp_date) + (LEAST(p_day_of_month, 28) - 1) * INTERVAL '1 day';
            ELSE
                v_next_date := v_temp_date;
            END IF;
            
        WHEN 'yearly' THEN
            -- السنة القادمة
            v_temp_date := p_current_date + INTERVAL '1 year';
            IF p_month_of_year IS NOT NULL AND p_day_of_month IS NOT NULL THEN
                v_next_date := MAKE_DATE(
                    EXTRACT(YEAR FROM v_temp_date)::INT,
                    p_month_of_year,
                    LEAST(p_day_of_month, 28)
                );
            ELSE
                v_next_date := v_temp_date;
            END IF;
            
        ELSE
            v_next_date := p_current_date + INTERVAL '1 month';
    END CASE;
    
    RETURN v_next_date;
END;
$$;


--
-- Name: calculate_sales_commission(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_sales_commission(p_invoice_id uuid, p_employee_id uuid DEFAULT NULL::uuid) RETURNS TABLE(employee_id uuid, plan_id uuid, commission_amount numeric, tier_applied integer, base_amount numeric, rate_applied numeric)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_invoice RECORD;
    v_assignment RECORD;
    v_plan RECORD;
    v_tier RECORD;
    v_base_amount DECIMAL(15,2);
    v_commission DECIMAL(15,2);
    v_rate DECIMAL(10,4);
    v_tier_num INT;
BEGIN
    -- الحصول على معلومات الفاتورة
    SELECT i.*, 
           i.total_amount as invoice_total,
           i.salesperson_id,
           i.company_id,
           i.tenant_id
    INTO v_invoice
    FROM invoices i
    WHERE i.id = p_invoice_id;
    
    IF v_invoice IS NULL THEN
        RETURN;
    END IF;
    
    -- تحديد الموظف (من الفاتورة أو المُمرر)
    IF p_employee_id IS NULL THEN
        p_employee_id := v_invoice.salesperson_id;
    END IF;
    
    IF p_employee_id IS NULL THEN
        RETURN;
    END IF;
    
    -- البحث عن خطط الحوافز المفعلة للموظف
    FOR v_assignment IN 
        SELECT ea.*, ip.*,
               COALESCE(ea.custom_rate, ip.base_rate) as effective_rate,
               COALESCE(ea.custom_cap, ip.max_cap) as effective_cap
        FROM employee_incentive_assignments ea
        JOIN incentive_plans ip ON ip.id = ea.plan_id
        WHERE ea.employee_id = p_employee_id
          AND ea.is_active = true
          AND ea.company_id = v_invoice.company_id
          AND ip.is_active = true
          AND ip.target_type IN ('sales', 'mixed')
          AND v_invoice.invoice_date BETWEEN ea.start_date AND COALESCE(ea.end_date, '9999-12-31')
          AND v_invoice.invoice_date BETWEEN ip.effective_from AND COALESCE(ip.effective_to, '9999-12-31')
    LOOP
        -- حساب المبلغ الأساسي
        v_base_amount := v_invoice.invoice_total;
        
        -- خصم الضريبة إذا لم تكن مشمولة
        IF NOT v_assignment.include_discounts THEN
            v_base_amount := v_base_amount - COALESCE(v_invoice.discount_amount, 0);
        END IF;
        
        -- التحقق من الحد الأدنى
        IF v_base_amount < v_assignment.min_threshold THEN
            CONTINUE;
        END IF;
        
        v_commission := 0;
        v_tier_num := NULL;
        v_rate := v_assignment.effective_rate;
        
        -- حساب العمولة حسب طريقة الحساب
        CASE v_assignment.calculation_method
            WHEN 'percentage' THEN
                v_commission := v_base_amount * v_rate / 100;
                
            WHEN 'fixed_per_unit' THEN
                -- يحتاج عدد الوحدات من الفاتورة
                SELECT COALESCE(SUM(quantity), 0) INTO v_commission
                FROM invoice_items WHERE invoice_id = p_invoice_id;
                v_commission := v_commission * v_rate;
                
            WHEN 'tiered', 'slab' THEN
                -- البحث عن الدرجة المناسبة
                SELECT * INTO v_tier
                FROM incentive_plan_tiers
                WHERE plan_id = v_assignment.plan_id
                  AND from_amount <= v_base_amount
                  AND (to_amount IS NULL OR to_amount >= v_base_amount)
                ORDER BY tier_number DESC
                LIMIT 1;
                
                IF v_tier IS NOT NULL THEN
                    v_tier_num := v_tier.tier_number;
                    IF v_tier.rate_type = 'percentage' THEN
                        v_commission := v_base_amount * v_tier.rate / 100;
                    ELSE
                        v_commission := v_tier.rate;
                    END IF;
                    v_commission := v_commission + v_tier.bonus_amount;
                    v_rate := v_tier.rate;
                END IF;
                
            ELSE
                v_commission := v_base_amount * v_rate / 100;
        END CASE;
        
        -- تطبيق الحد الأقصى
        IF v_assignment.effective_cap IS NOT NULL AND v_commission > v_assignment.effective_cap THEN
            v_commission := v_assignment.effective_cap;
        END IF;
        
        -- إرجاع النتيجة
        employee_id := p_employee_id;
        plan_id := v_assignment.plan_id;
        commission_amount := v_commission;
        tier_applied := v_tier_num;
        base_amount := v_base_amount;
        rate_applied := v_rate;
        
        RETURN NEXT;
    END LOOP;
    
    RETURN;
END;
$$;


--
-- Name: calculate_worked_hours(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_worked_hours() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NEW.check_in IS NOT NULL AND NEW.check_out IS NOT NULL THEN
        NEW.worked_hours := ROUND(EXTRACT(EPOCH FROM (NEW.check_out - NEW.check_in)) / 3600.0, 2);
    END IF;
    RETURN NEW;
END;
$$;


--
-- Name: can_access_company(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.can_access_company(p_company_id uuid, p_user_id uuid DEFAULT auth.uid()) RETURNS boolean
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_user_company_id UUID;
    v_user_tenant_id UUID;
    v_company_tenant_id UUID;
BEGIN
    -- Super Admin يرى كل شيء
    IF is_super_admin(p_user_id) THEN
        RETURN true;
    END IF;
    
    -- Get user's company and tenant
    SELECT company_id, tenant_id INTO v_user_company_id, v_user_tenant_id
    FROM user_profiles
    WHERE id = p_user_id;
    
    -- Get company's tenant
    SELECT tenant_id INTO v_company_tenant_id
    FROM companies
    WHERE id = p_company_id;
    
    -- Tenant Owner: يرى كل شركات الـ Tenant
    IF is_tenant_owner(p_user_id) THEN
        RETURN v_user_tenant_id = v_company_tenant_id;
    END IF;
    
    -- Regular User: يرى شركته فقط
    RETURN v_user_company_id = p_company_id;
EXCEPTION WHEN OTHERS THEN
    RETURN false;
END;
$$;


--
-- Name: can_access_fund(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.can_access_fund(p_fund_account_id uuid, p_user_id uuid DEFAULT auth.uid()) RETURNS boolean
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
BEGIN
    -- Platform & Tenant admins see all
    IF is_super_admin(p_user_id) OR is_tenant_admin(p_user_id) THEN
        RETURN true;
    END IF;
    
    -- Company admins see all company funds
    IF is_company_admin(p_user_id) THEN
        RETURN true;
    END IF;
    
    -- Check direct permission
    RETURN EXISTS (
        SELECT 1 FROM user_fund_permissions
        WHERE user_id = p_user_id
          AND fund_account_id = p_fund_account_id
          AND can_view = true
    );
END;
$$;


--
-- Name: can_access_warehouse(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.can_access_warehouse(p_warehouse_id uuid, p_user_id uuid DEFAULT auth.uid()) RETURNS boolean
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
BEGIN
    IF is_super_admin(p_user_id) OR is_tenant_admin(p_user_id) THEN
        RETURN true;
    END IF;
    
    IF is_company_admin(p_user_id) THEN
        RETURN true;
    END IF;
    
    RETURN EXISTS (
        SELECT 1 FROM user_warehouse_permissions
        WHERE user_id = p_user_id
          AND warehouse_id = p_warehouse_id
          AND can_view = true
    );
END;
$$;


--
-- Name: can_delegate_to_role(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.can_delegate_to_role(p_user_id uuid, p_target_role_id uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_can_delegate BOOLEAN := false;
BEGIN
    SELECT EXISTS (
        SELECT 1
        FROM user_roles ur
        JOIN role_delegations rd ON ur.role_id = rd.delegator_role_id
        JOIN roles target_role ON rd.delegatee_role_id = target_role.id
        WHERE ur.user_id = p_user_id
          AND ur.is_active = true
          AND rd.can_manage_users = true
          AND target_role.id = p_target_role_id
    ) INTO v_can_delegate;
    
    RETURN v_can_delegate;
END;
$$;


--
-- Name: can_edit_journal_entry(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.can_edit_journal_entry(p_entry_id uuid, p_user_id uuid DEFAULT auth.uid()) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_entry RECORD;
    v_period RECORD;
    v_fiscal_year RECORD;
    v_settings JSONB;
    v_mode VARCHAR;
BEGIN
    SELECT * INTO v_entry FROM journal_entries WHERE id = p_entry_id;
    IF NOT FOUND THEN
        RETURN jsonb_build_object('can_edit', false, 'reason', 'entry_not_found', 'message', 'القيد غير موجود');
    END IF;
    
    SELECT COALESCE(accounting_settings, '{}'::jsonb) INTO v_settings FROM companies WHERE id = v_entry.company_id;
    v_mode := COALESCE(v_settings->>'fiscal_year_mode', 'independent');
    
    SELECT * INTO v_period FROM accounting_periods WHERE id = v_entry.period_id;
    SELECT * INTO v_fiscal_year FROM fiscal_years WHERE id = v_entry.fiscal_year_id;
    
    IF NOT v_entry.is_posted THEN
        RETURN jsonb_build_object('can_edit', true, 'mode', 'direct', 'message', 'القيد مسودة');
    END IF;
    
    IF (v_fiscal_year IS NULL OR v_fiscal_year.status = 'open') AND 
       (v_period IS NULL OR v_period.status = 'open') THEN
        RETURN jsonb_build_object('can_edit', true, 'mode', 'unpost_edit_repost', 'auto_unpost', true);
    END IF;
    
    IF v_fiscal_year IS NOT NULL AND v_fiscal_year.status = 'closed' AND v_mode = 'independent' THEN
        RETURN jsonb_build_object(
            'can_edit', COALESCE((v_settings->'closed_year_settings'->>'allow_edit_closed_year')::boolean, true),
            'mode', 'independent_closed_year',
            'require_reason', true
        );
    END IF;
    
    IF v_fiscal_year IS NOT NULL AND v_fiscal_year.status = 'closed' AND v_mode = 'linked' THEN
        RETURN jsonb_build_object('can_edit', false, 'mode', 'linked_closed_year');
    END IF;
    
    RETURN jsonb_build_object('can_edit', true, 'mode', 'default');
END;
$$;


--
-- Name: can_user_see_module(uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.can_user_see_module(p_user_id uuid, p_module_code text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    RETURN EXISTS (
        SELECT 1
        FROM user_roles ur
        JOIN roles r ON ur.role_id = r.id
        WHERE ur.user_id = p_user_id
          AND ur.is_active = true
          AND p_module_code = ANY(r.visible_modules)
    );
END;
$$;


--
-- Name: change_document_status(uuid, character varying, uuid, uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.change_document_status(p_tenant_id uuid, p_doc_type character varying, p_doc_id uuid, p_new_status_id uuid, p_comment text DEFAULT NULL::text) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_current_status_id UUID;
  v_history_id UUID;
BEGIN
  -- Get current status from the document (you'd need to adjust this based on your schema)
  -- This is a placeholder - implement based on your actual document tables
  
  -- Insert history record
  INSERT INTO status_history (tenant_id, doc_type, doc_id, from_status_id, to_status_id, changed_by, comment)
  VALUES (p_tenant_id, p_doc_type, p_doc_id, v_current_status_id, p_new_status_id, auth.uid(), p_comment)
  RETURNING id INTO v_history_id;
  
  RETURN v_history_id;
END;
$$;


--
-- Name: check_access_policy(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_access_policy(p_user_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_policy RECORD;
    v_user RECORD;
    v_current_day TEXT;
    v_current_time TIME;
    v_result JSONB;
BEGIN
    -- الحصول على بيانات المستخدم
    SELECT * INTO v_user FROM user_profiles WHERE id = p_user_id;
    
    -- التحقق من الحظر
    IF v_user.is_suspended = TRUE THEN
        IF v_user.suspended_until IS NOT NULL AND v_user.suspended_until < NOW() THEN
            -- انتهى التعليق المؤقت، إعادة تفعيل
            UPDATE user_profiles 
            SET is_suspended = FALSE, suspended_at = NULL, 
                suspended_until = NULL, suspended_reason = NULL 
            WHERE id = p_user_id;
        ELSE
            RETURN jsonb_build_object(
                'allowed', false,
                'reason', 'suspended',
                'message', COALESCE(v_user.suspended_reason, 'Account suspended'),
                'until', v_user.suspended_until
            );
        END IF;
    END IF;
    
    -- التحقق من is_active
    IF v_user.is_active = FALSE THEN
        RETURN jsonb_build_object(
            'allowed', false,
            'reason', 'deactivated',
            'message', 'Account deactivated'
        );
    END IF;
    
    -- البحث عن السياسة المطبقة
    v_current_day := LOWER(to_char(NOW() AT TIME ZONE COALESCE(v_user.timezone, 'Asia/Riyadh'), 'Dy'));
    v_current_time := (NOW() AT TIME ZONE COALESCE(v_user.timezone, 'Asia/Riyadh'))::TIME;
    
    SELECT * INTO v_policy 
    FROM access_policies 
    WHERE company_id = v_user.company_id 
    AND is_active = TRUE
    AND (
        v_user.role = ANY(applies_to_roles) 
        OR p_user_id = ANY(applies_to_users)
        OR (array_length(applies_to_roles, 1) IS NULL AND array_length(applies_to_users, 1) IS NULL)
    )
    ORDER BY priority DESC
    LIMIT 1;
    
    -- لا توجد سياسة = السماح
    IF v_policy IS NULL THEN
        RETURN jsonb_build_object('allowed', true, 'reason', 'no_policy');
    END IF;
    
    -- التحقق من اليوم
    IF NOT (v_current_day = ANY(v_policy.allowed_days)) THEN
        IF v_policy.outside_hours_action = 'block' THEN
            RETURN jsonb_build_object('allowed', false, 'reason', 'day_blocked', 'action', 'block');
        ELSE
            RETURN jsonb_build_object('allowed', true, 'reason', 'day_notify', 'action', v_policy.outside_hours_action);
        END IF;
    END IF;
    
    -- التحقق من الساعات
    IF v_current_time < v_policy.work_start_time OR v_current_time > v_policy.work_end_time THEN
        IF v_policy.outside_hours_action = 'block' THEN
            RETURN jsonb_build_object('allowed', false, 'reason', 'hours_blocked', 'action', 'block');
        ELSE
            RETURN jsonb_build_object('allowed', true, 'reason', 'hours_notify', 'action', v_policy.outside_hours_action);
        END IF;
    END IF;
    
    RETURN jsonb_build_object('allowed', true, 'reason', 'policy_ok');
END;
$$;


--
-- Name: check_document_expiry(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_document_expiry() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NEW.expiry_date IS NOT NULL AND NEW.expiry_date < CURRENT_DATE AND NEW.status = 'active' THEN
        NEW.status = 'expired';
    END IF;
    RETURN NEW;
END;
$$;


--
-- Name: check_journal_entry_balance(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_journal_entry_balance() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_total_debit DECIMAL(15,2);
    v_total_credit DECIMAL(15,2);
BEGIN
    SELECT 
        COALESCE(SUM(debit), 0),
        COALESCE(SUM(credit), 0)
    INTO v_total_debit, v_total_credit
    FROM journal_entry_lines
    WHERE entry_id = COALESCE(NEW.entry_id, OLD.entry_id);
    
    UPDATE journal_entries
    SET total_debit = v_total_debit,
        total_credit = v_total_credit
    WHERE id = COALESCE(NEW.entry_id, OLD.entry_id);
    
    RETURN COALESCE(NEW, OLD);
END;
$$;


--
-- Name: check_special_permission(uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_special_permission(p_user_id uuid, p_perm_name text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_has_permission BOOLEAN := false;
BEGIN
    SELECT EXISTS (
        SELECT 1
        FROM user_roles ur
        JOIN roles r ON ur.role_id = r.id
        WHERE ur.user_id = p_user_id
          AND ur.is_active = true
          AND (ur.expires_at IS NULL OR ur.expires_at > NOW())
          AND (
              -- super_admin / tenant_owner / company_owner always have all permissions
              r.code IN ('super_admin', 'tenant_owner', 'company_owner')
              -- Or the role explicitly has this special permission
              OR (r.special_permissions IS NOT NULL 
                  AND (r.special_permissions ->> p_perm_name)::boolean = true)
          )
    ) INTO v_has_permission;
    
    RETURN v_has_permission;
END;
$$;


--
-- Name: check_subscription_access(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_subscription_access(p_tenant_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_tenant_id UUID;
    v_subscription RECORD;
    v_days_remaining INT;
    v_access_level TEXT;
    v_result JSONB;
BEGIN
    v_tenant_id := COALESCE(p_tenant_id, get_current_tenant_id());
    
    IF v_tenant_id IS NULL THEN
        RETURN jsonb_build_object(
            'access_level', 'denied',
            'reason', 'no_tenant'
        );
    END IF;
    
    -- الحصول على الاشتراك
    SELECT * INTO v_subscription
    FROM subscriptions
    WHERE tenant_id = v_tenant_id
    ORDER BY created_at DESC
    LIMIT 1;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'access_level', 'denied',
            'reason', 'no_subscription'
        );
    END IF;
    
    -- التحقق من القفل
    IF v_subscription.locked_at IS NOT NULL THEN
        RETURN jsonb_build_object(
            'access_level', 'locked',
            'reason', v_subscription.lock_reason,
            'locked_at', v_subscription.locked_at
        );
    END IF;
    
    -- حساب الأيام المتبقية
    v_days_remaining := GREATEST(0, 
        (v_subscription.current_period_end::date - CURRENT_DATE)
    );
    
    -- تحديد مستوى الوصول
    IF v_days_remaining <= 0 THEN
        v_access_level := 'expired';
    ELSIF v_days_remaining <= 3 THEN
        v_access_level := 'critical_warning';
    ELSIF v_days_remaining <= 7 THEN
        v_access_level := 'warning';
    ELSE
        v_access_level := 'full';
    END IF;
    
    RETURN jsonb_build_object(
        'access_level', v_access_level,
        'status', v_subscription.status,
        'days_remaining', v_days_remaining,
        'period_end', v_subscription.current_period_end,
        'plan_id', v_subscription.plan_id
    );
END;
$$;


--
-- Name: check_user_permission(uuid, character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_user_permission(p_user_id uuid, p_module character varying, p_permission character varying) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_has_permission BOOLEAN := false;
BEGIN
    SELECT EXISTS (
        SELECT 1
        FROM user_roles ur
        JOIN roles r ON ur.role_id = r.id
        WHERE ur.user_id = p_user_id
          AND ur.is_active = true
          AND (ur.expires_at IS NULL OR ur.expires_at > NOW())
          AND (
              r.permissions->>'all' = 'true'
              OR p_permission = ANY(SELECT jsonb_array_elements_text(r.permissions->p_module))
          )
    ) INTO v_has_permission;
    
    RETURN v_has_permission;
END;
$$;


--
-- Name: check_user_resource_access(uuid, character varying, uuid, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_user_resource_access(p_user_id uuid, p_resource_type character varying, p_resource_id uuid, p_permission character varying DEFAULT 'read'::character varying) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_has_access BOOLEAN := false;
BEGIN
    SELECT EXISTS (
        SELECT 1
        FROM user_resource_access ura
        WHERE ura.user_id = p_user_id
          AND ura.resource_type = p_resource_type
          AND ura.resource_id = p_resource_id
          AND (ura.expires_at IS NULL OR ura.expires_at > NOW())
          AND (ura.permissions->>p_permission)::boolean = true
    ) INTO v_has_access;
    
    RETURN v_has_access;
END;
$$;


--
-- Name: check_visibility(uuid, character varying, character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_visibility(p_user_id uuid, p_rule_type character varying, p_target_type character varying, p_target_name character varying) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_is_visible BOOLEAN := true;
    v_user_roles UUID[];
BEGIN
    -- Get user's role IDs
    SELECT ARRAY_AGG(role_id) INTO v_user_roles
    FROM user_roles
    WHERE user_id = p_user_id AND is_active = true;
    
    -- Check if any visibility rule applies
    SELECT NOT EXISTS (
        SELECT 1
        FROM visibility_rules vr
        WHERE vr.rule_type = p_rule_type
          AND vr.target_type = p_target_type
          AND vr.target_name = p_target_name
          AND vr.is_active = true
          AND NOT (vr.visible_to_roles && v_user_roles)
    ) INTO v_is_visible;
    
    RETURN v_is_visible;
END;
$$;


--
-- Name: cleanup_container_transit_account(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.cleanup_container_transit_account() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_has_entries BOOLEAN;
BEGIN
    -- Skip if no container_account_id
    IF OLD.container_account_id IS NULL THEN
        RETURN OLD;
    END IF;

    -- Check if the account has any journal entry lines
    SELECT EXISTS(
        SELECT 1 FROM journal_entry_lines 
        WHERE account_id = OLD.container_account_id
        LIMIT 1
    ) INTO v_has_entries;

    IF v_has_entries THEN
        -- Account has transactions → deactivate only (preserve audit trail)
        UPDATE chart_of_accounts 
        SET is_active = false
        WHERE id = OLD.container_account_id;
    ELSE
        -- No transactions → safe to delete the account
        -- Clear references in container_expenses first
        UPDATE container_expenses SET container_account_id = NULL 
        WHERE container_account_id = OLD.container_account_id;
        
        DELETE FROM chart_of_accounts 
        WHERE id = OLD.container_account_id;
    END IF;

    RETURN OLD;
END;
$$;


--
-- Name: cleanup_expired_sessions(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.cleanup_expired_sessions() RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    DELETE FROM active_sessions 
    WHERE last_active_at < NOW() - INTERVAL '24 hours';
    
    UPDATE user_profiles 
    SET is_online = FALSE 
    WHERE is_online = TRUE 
    AND last_active_at < NOW() - INTERVAL '5 minutes';
END;
$$;


--
-- Name: cleanup_old_login_history(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.cleanup_old_login_history() RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    DELETE FROM login_history 
    WHERE login_at < NOW() - INTERVAL '90 days';
END;
$$;


--
-- Name: confirm_delivery(uuid, character varying, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.confirm_delivery(p_note_id uuid, p_receiver_name character varying DEFAULT NULL::character varying, p_signature text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    UPDATE delivery_notes
    SET 
        status = 'delivered',
        delivered_at = NOW(),
        receiver_name = COALESCE(p_receiver_name, receiver_name),
        receiver_signature = COALESCE(p_signature, receiver_signature)
    WHERE id = p_note_id;
    
    UPDATE delivery_note_items
    SET quantity_delivered = quantity_to_deliver
    WHERE delivery_note_id = p_note_id;
    
    RETURN jsonb_build_object(
        'success', true,
        'note_id', p_note_id,
        'status', 'delivered'
    );
END;
$$;


--
-- Name: create_container_transit_account(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_container_transit_account() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $_$
DECLARE
    v_company_id UUID;
    v_tenant_id UUID;
    v_chart_type VARCHAR(30);
    v_git_parent_id UUID;
    v_new_account_id UUID;
    v_next_seq INT;
    v_new_code VARCHAR(20);
    v_container_ref VARCHAR(100);
    v_current_asset_type UUID;
BEGIN
    v_company_id := NEW.company_id;
    SELECT c.tenant_id, c.chart_type INTO v_tenant_id, v_chart_type
    FROM companies c WHERE c.id = v_company_id;

    -- Only for extended charts (simple doesn't have GIT 1143)
    IF v_chart_type != 'extended' THEN
        RAISE NOTICE '⏭️ الشجرة القياسية لا تدعم حسابات الكونتينرات — تخطي';
        RETURN NEW;
    END IF;

    SELECT id INTO v_git_parent_id
    FROM chart_of_accounts
    WHERE company_id = v_company_id AND account_code = '1143'
      AND is_detail = false AND is_active = true
    LIMIT 1;

    IF v_git_parent_id IS NULL THEN
        RAISE NOTICE '⚠️ حساب 1143 غير موجود — لم يتم إنشاء حساب';
        RETURN NEW;
    END IF;

    SELECT COALESCE(MAX(
        CASE WHEN account_code ~ '^1143[0-9]+$'
             THEN CAST(SUBSTRING(account_code FROM 5) AS INT) ELSE 0 END
    ), 0) + 1 INTO v_next_seq
    FROM chart_of_accounts WHERE company_id = v_company_id AND parent_id = v_git_parent_id;

    v_new_code := '1143' || v_next_seq::TEXT;
    v_container_ref := COALESCE(NEW.container_number, NEW.shipment_number, 'CNT-' || v_next_seq);

    SELECT id INTO v_current_asset_type FROM account_types WHERE code = 'CURRENT_ASSET';

    INSERT INTO chart_of_accounts (
        tenant_id, company_id, account_code, name_ar, name_en,
        account_type_id, parent_id, is_detail, is_active
    ) VALUES (
        v_tenant_id, v_company_id, v_new_code,
        'كونتينر ' || v_container_ref, 'Container ' || v_container_ref,
        v_current_asset_type, v_git_parent_id, true, true
    ) RETURNING id INTO v_new_account_id;

    NEW.container_account_id := v_new_account_id;
    RETURN NEW;
END;
$_$;


--
-- Name: create_customer_account(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_customer_account() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_parent_id UUID;
    v_account_type_id UUID;
    v_new_code VARCHAR(50);
    v_new_account_id UUID;
    v_full_code VARCHAR(200);
BEGIN
    -- الحصول على حساب العملاء الأب (1130)
    SELECT id INTO v_parent_id 
    FROM chart_of_accounts 
    WHERE company_id = NEW.company_id 
      AND account_code = '1130';
    
    IF v_parent_id IS NULL THEN
        -- لا توجد شجرة حسابات، تخطي
        RAISE NOTICE 'لا توجد شجرة حسابات للشركة، تخطي إنشاء حساب العميل';
        RETURN NEW;
    END IF;
    
    -- الحصول على نوع الحساب
    SELECT id INTO v_account_type_id FROM account_types WHERE code = 'CURRENT_ASSET';
    
    -- توليد رقم الحساب الجديد
    v_new_code := generate_next_account_code(NEW.tenant_id, NEW.company_id, '1130');
    v_full_code := '1000.1100.1130.' || v_new_code;
    
    -- إنشاء الحساب الفرعي للعميل
    INSERT INTO chart_of_accounts (
        tenant_id, company_id, account_code, 
        name_ar, name_en, 
        account_type_id, parent_id, 
        is_group, is_detail, level, full_code, 
        currency, is_active, is_receivable
    )
    VALUES (
        NEW.tenant_id, NEW.company_id, v_new_code,
        NEW.name_ar, COALESCE(NEW.name_en, NEW.name_ar),
        v_account_type_id, v_parent_id,
        false, true, 4, v_full_code,
        COALESCE(NEW.currency, 'SAR'), true, true
    )
    RETURNING id INTO v_new_account_id;
    
    -- تحديث العميل بربط الحساب
    NEW.receivable_account_id := v_new_account_id;
    
    RAISE NOTICE 'تم إنشاء حساب للعميل: % - رقم الحساب: %', NEW.name_ar, v_new_code;
    
    RETURN NEW;
END;
$$;


