--
-- Name: create_monthly_targets(uuid, integer, integer, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_monthly_targets(p_company_id uuid, p_year integer, p_month integer, p_copy_from_previous boolean DEFAULT true) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_assignment RECORD;
    v_prev_target RECORD;
    v_created INT := 0;
    v_tenant_id UUID;
BEGIN
    -- الحصول على tenant_id
    SELECT tenant_id INTO v_tenant_id FROM companies WHERE id = p_company_id;
    
    -- لكل موظف لديه تعيين نشط
    FOR v_assignment IN 
        SELECT DISTINCT ea.employee_id, ea.tenant_id, ea.target_amount
        FROM employee_incentive_assignments ea
        WHERE ea.company_id = p_company_id
          AND ea.is_active = true
          AND MAKE_DATE(p_year, p_month, 1) BETWEEN ea.start_date AND COALESCE(ea.end_date, '9999-12-31')
    LOOP
        -- التحقق من عدم وجود هدف مسبق
        IF NOT EXISTS (
            SELECT 1 FROM employee_targets
            WHERE employee_id = v_assignment.employee_id
              AND period_year = p_year
              AND period_month = p_month
              AND target_type = 'sales_amount'
        ) THEN
            -- محاولة نسخ من الشهر السابق
            IF p_copy_from_previous THEN
                SELECT * INTO v_prev_target
                FROM employee_targets
                WHERE employee_id = v_assignment.employee_id
                  AND target_type = 'sales_amount'
                  AND (
                      (period_year = p_year AND period_month = p_month - 1)
                      OR (p_month = 1 AND period_year = p_year - 1 AND period_month = 12)
                  )
                LIMIT 1;
            END IF;
            
            -- إنشاء الهدف
            INSERT INTO employee_targets (
                tenant_id, company_id, employee_id,
                target_type, period_type, period_year, period_month,
                target_amount,
                bonus_on_achievement, bonus_on_exceed,
                status
            )
            VALUES (
                v_tenant_id, p_company_id, v_assignment.employee_id,
                'sales_amount', 'monthly', p_year, p_month,
                COALESCE(v_prev_target.target_amount, v_assignment.target_amount, 0),
                COALESCE(v_prev_target.bonus_on_achievement, 0),
                COALESCE(v_prev_target.bonus_on_exceed, 0),
                'active'
            );
            
            v_created := v_created + 1;
        END IF;
    END LOOP;
    
    RETURN v_created;
END;
$$;


--
-- Name: create_payment_receipt_journal_entry(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_payment_receipt_journal_entry() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_entry_id UUID;
    v_entry_number VARCHAR(50);
    v_customer_account_id UUID;
    v_cash_account_id UUID;
    v_fiscal_year_id UUID;
BEGIN
    -- فقط للسندات المؤكدة
    IF NEW.status != 'confirmed' THEN
        RETURN NEW;
    END IF;
    
    -- تخطي إذا كان القيد موجود مسبقاً
    IF NEW.journal_entry_id IS NOT NULL THEN
        RETURN NEW;
    END IF;
    
    -- الحصول على حساب العميل
    v_customer_account_id := (
        SELECT receivable_account_id 
        FROM customers 
        WHERE id = NEW.customer_id
    );
    
    IF v_customer_account_id IS NULL THEN
        v_customer_account_id := get_account_by_code(NEW.company_id, '1130');
    END IF;
    
    -- تحديد حساب النقدية بناءً على طريقة الدفع
    IF NEW.payment_method IN ('cash', 'نقدي', 'نقداً') THEN
        v_cash_account_id := get_account_by_code(NEW.company_id, '1110');
    ELSE
        v_cash_account_id := get_account_by_code(NEW.company_id, '1120');
    END IF;
    
    IF v_cash_account_id IS NULL THEN
        v_cash_account_id := get_account_by_code(NEW.company_id, '1110');
    END IF;
    
    -- الحصول على السنة المالية الحالية
    SELECT id INTO v_fiscal_year_id
    FROM fiscal_years
    WHERE company_id = NEW.company_id
      AND is_current = true
    LIMIT 1;
    
    -- توليد رقم القيد
    v_entry_number := 'JE-PR-' || NEW.receipt_number;
    
    -- إنشاء القيد اليومي
    INSERT INTO journal_entries (
        tenant_id, company_id, branch_id,
        entry_number, entry_date,
        fiscal_year_id,
        entry_type,
        reference_type, reference_id, reference_number,
        description,
        currency, exchange_rate,
        total_debit, total_credit,
        status, is_posted, posted_at,
        created_by, created_at
    )
    VALUES (
        NEW.tenant_id, NEW.company_id, NEW.branch_id,
        v_entry_number, NEW.receipt_date,
        v_fiscal_year_id,
        'payment_receipt',
        'payment_receipt', NEW.id, NEW.receipt_number,
        'سند قبض رقم ' || NEW.receipt_number || ' - ' || COALESCE(NEW.customer_name, ''),
        NEW.currency, NEW.exchange_rate,
        NEW.amount, NEW.amount,
        'posted', true, NOW(),
        NEW.created_by, NOW()
    )
    RETURNING id INTO v_entry_id;
    
    -- إضافة بنود القيد
    -- 1. مدين: حساب النقدية
    INSERT INTO journal_entry_lines (
        tenant_id, entry_id, line_number,
        account_id, debit, credit,
        currency, exchange_rate,
        description,
        reference_type, reference_id
    )
    VALUES (
        NEW.tenant_id, v_entry_id, 1,
        v_cash_account_id, NEW.amount, 0,
        NEW.currency, NEW.exchange_rate,
        'تحصيل من العميل - سند ' || NEW.receipt_number,
        'payment_receipt', NEW.id
    );
    
    -- 2. دائن: حساب العميل
    INSERT INTO journal_entry_lines (
        tenant_id, entry_id, line_number,
        account_id, debit, credit,
        currency, exchange_rate,
        description,
        party_type, party_id,
        reference_type, reference_id
    )
    VALUES (
        NEW.tenant_id, v_entry_id, 2,
        v_customer_account_id, 0, NEW.amount,
        NEW.currency, NEW.exchange_rate,
        'تسديد ذمة العميل - سند ' || NEW.receipt_number,
        'customer', NEW.customer_id,
        'payment_receipt', NEW.id
    );
    
    -- تحديث السند بربط القيد
    NEW.journal_entry_id := v_entry_id;
    
    RAISE NOTICE 'تم إنشاء قيد سند القبض: % - المبلغ: %', v_entry_number, NEW.amount;
    
    RETURN NEW;
END;
$$;


--
-- Name: create_payment_voucher_journal_entry(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_payment_voucher_journal_entry() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_entry_id UUID;
    v_entry_number VARCHAR(50);
    v_supplier_account_id UUID;
    v_cash_account_id UUID;
    v_fiscal_year_id UUID;
BEGIN
    -- فقط للسندات المؤكدة
    IF NEW.status != 'confirmed' THEN
        RETURN NEW;
    END IF;
    
    -- تخطي إذا كان القيد موجود مسبقاً
    IF NEW.journal_entry_id IS NOT NULL THEN
        RETURN NEW;
    END IF;
    
    -- الحصول على حساب المورد
    v_supplier_account_id := (
        SELECT payable_account_id 
        FROM suppliers 
        WHERE id = NEW.supplier_id
    );
    
    IF v_supplier_account_id IS NULL THEN
        v_supplier_account_id := get_account_by_code(NEW.company_id, '2110');
    END IF;
    
    -- تحديد حساب النقدية بناءً على طريقة الدفع
    IF NEW.payment_method IN ('cash', 'نقدي', 'نقداً') THEN
        v_cash_account_id := get_account_by_code(NEW.company_id, '1110');
    ELSE
        v_cash_account_id := get_account_by_code(NEW.company_id, '1120');
    END IF;
    
    IF v_cash_account_id IS NULL THEN
        v_cash_account_id := get_account_by_code(NEW.company_id, '1110');
    END IF;
    
    -- الحصول على السنة المالية الحالية
    SELECT id INTO v_fiscal_year_id
    FROM fiscal_years
    WHERE company_id = NEW.company_id
      AND is_current = true
    LIMIT 1;
    
    -- توليد رقم القيد
    v_entry_number := 'JE-PV-' || NEW.voucher_number;
    
    -- إنشاء القيد اليومي
    INSERT INTO journal_entries (
        tenant_id, company_id, branch_id,
        entry_number, entry_date,
        fiscal_year_id,
        entry_type,
        reference_type, reference_id, reference_number,
        description,
        currency, exchange_rate,
        total_debit, total_credit,
        status, is_posted, posted_at,
        created_by, created_at
    )
    VALUES (
        NEW.tenant_id, NEW.company_id, NEW.branch_id,
        v_entry_number, NEW.voucher_date,
        v_fiscal_year_id,
        'payment_voucher',
        'payment_voucher', NEW.id, NEW.voucher_number,
        'سند صرف رقم ' || NEW.voucher_number || ' - ' || COALESCE(NEW.supplier_name, ''),
        NEW.currency, NEW.exchange_rate,
        NEW.amount, NEW.amount,
        'posted', true, NOW(),
        NEW.created_by, NOW()
    )
    RETURNING id INTO v_entry_id;
    
    -- إضافة بنود القيد
    -- 1. مدين: حساب المورد
    INSERT INTO journal_entry_lines (
        tenant_id, entry_id, line_number,
        account_id, debit, credit,
        currency, exchange_rate,
        description,
        party_type, party_id,
        reference_type, reference_id
    )
    VALUES (
        NEW.tenant_id, v_entry_id, 1,
        v_supplier_account_id, NEW.amount, 0,
        NEW.currency, NEW.exchange_rate,
        'تسديد ذمة المورد - سند ' || NEW.voucher_number,
        'supplier', NEW.supplier_id,
        'payment_voucher', NEW.id
    );
    
    -- 2. دائن: حساب النقدية
    INSERT INTO journal_entry_lines (
        tenant_id, entry_id, line_number,
        account_id, debit, credit,
        currency, exchange_rate,
        description,
        reference_type, reference_id
    )
    VALUES (
        NEW.tenant_id, v_entry_id, 2,
        v_cash_account_id, 0, NEW.amount,
        NEW.currency, NEW.exchange_rate,
        'دفع للمورد - سند ' || NEW.voucher_number,
        'payment_voucher', NEW.id
    );
    
    -- تحديث السند بربط القيد
    NEW.journal_entry_id := v_entry_id;
    
    RAISE NOTICE 'تم إنشاء قيد سند الصرف: % - المبلغ: %', v_entry_number, NEW.amount;
    
    RETURN NEW;
END;
$$;


--
-- Name: create_recurring_template(uuid, uuid, character varying, character varying, character varying, date, numeric, uuid, uuid, integer, character varying, text, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_recurring_template(p_tenant_id uuid, p_company_id uuid, p_template_code character varying, p_template_name character varying, p_frequency character varying, p_start_date date, p_total_amount numeric, p_debit_account_id uuid, p_credit_account_id uuid, p_day_of_month integer DEFAULT NULL::integer, p_category character varying DEFAULT 'other'::character varying, p_description text DEFAULT NULL::text, p_auto_post boolean DEFAULT false) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_template_id UUID;
BEGIN
    -- إنشاء القالب
    INSERT INTO recurring_entry_templates (
        tenant_id, company_id,
        template_code, template_name, description,
        frequency, day_of_month,
        start_date, next_execution_date,
        total_amount,
        category,
        auto_post, is_active
    )
    VALUES (
        p_tenant_id, p_company_id,
        p_template_code, p_template_name, p_description,
        p_frequency, p_day_of_month,
        p_start_date, p_start_date,
        p_total_amount,
        p_category,
        p_auto_post, true
    )
    RETURNING id INTO v_template_id;
    
    -- إضافة بند المدين
    INSERT INTO recurring_entry_lines (
        tenant_id, template_id, line_number,
        account_id, debit, credit,
        description
    )
    VALUES (
        p_tenant_id, v_template_id, 1,
        p_debit_account_id, p_total_amount, 0,
        p_template_name || ' - مدين'
    );
    
    -- إضافة بند الدائن
    INSERT INTO recurring_entry_lines (
        tenant_id, template_id, line_number,
        account_id, debit, credit,
        description
    )
    VALUES (
        p_tenant_id, v_template_id, 2,
        p_credit_account_id, 0, p_total_amount,
        p_template_name || ' - دائن'
    );
    
    RAISE NOTICE 'تم إنشاء قالب القيد المتكرر: %', p_template_name;
    
    RETURN v_template_id;
END;
$$;


--
-- Name: create_sales_invoice_journal_entry(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_sales_invoice_journal_entry() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_entry_id UUID;
    v_entry_number VARCHAR(50);
    v_customer_account_id UUID;
    v_sales_account_id UUID;
    v_vat_account_id UUID;
    v_fiscal_year_id UUID;
BEGIN
    -- فقط عند تأكيد الفاتورة (posted)
    IF NEW.status != 'posted' OR NEW.is_posted = false THEN
        RETURN NEW;
    END IF;
    
    -- تخطي إذا كان القيد موجود مسبقاً
    IF NEW.journal_entry_id IS NOT NULL THEN
        RETURN NEW;
    END IF;
    
    -- الحصول على حساب العميل
    v_customer_account_id := (
        SELECT receivable_account_id 
        FROM customers 
        WHERE id = NEW.customer_id
    );
    
    IF v_customer_account_id IS NULL THEN
        -- استخدام حساب العملاء العام
        v_customer_account_id := get_account_by_code(NEW.company_id, '1130');
    END IF;
    
    -- الحصول على حساب المبيعات
    v_sales_account_id := get_account_by_code(NEW.company_id, '4100');
    IF v_sales_account_id IS NULL THEN
        RAISE EXCEPTION 'حساب المبيعات (4100) غير موجود';
    END IF;
    
    -- الحصول على حساب ضريبة القيمة المضافة
    v_vat_account_id := get_account_by_code(NEW.company_id, '2130');
    
    -- الحصول على السنة المالية الحالية
    SELECT id INTO v_fiscal_year_id
    FROM fiscal_years
    WHERE company_id = NEW.company_id
      AND is_current = true
    LIMIT 1;
    
    -- توليد رقم القيد
    v_entry_number := 'JE-SI-' || NEW.invoice_number;
    
    -- إنشاء القيد اليومي
    INSERT INTO journal_entries (
        tenant_id, company_id, branch_id,
        entry_number, entry_date,
        fiscal_year_id,
        entry_type,
        reference_type, reference_id, reference_number,
        description,
        currency, exchange_rate,
        total_debit, total_credit,
        status, is_posted, posted_at,
        created_by, created_at
    )
    VALUES (
        NEW.tenant_id, NEW.company_id, NEW.branch_id,
        v_entry_number, NEW.invoice_date,
        v_fiscal_year_id,
        'sales_invoice',
        'sales_invoice', NEW.id, NEW.invoice_number,
        'قيد فاتورة مبيعات رقم ' || NEW.invoice_number,
        NEW.currency, NEW.exchange_rate,
        NEW.total_amount, NEW.total_amount,
        'posted', true, NOW(),
        NEW.created_by, NOW()
    )
    RETURNING id INTO v_entry_id;
    
    -- إضافة بنود القيد
    -- 1. مدين: حساب العميل
    INSERT INTO journal_entry_lines (
        tenant_id, entry_id, line_number,
        account_id, debit, credit,
        currency, exchange_rate,
        description,
        party_type, party_id,
        reference_type, reference_id
    )
    VALUES (
        NEW.tenant_id, v_entry_id, 1,
        v_customer_account_id, NEW.total_amount, 0,
        NEW.currency, NEW.exchange_rate,
        CASE WHEN NEW.notes IS NOT NULL AND NEW.notes != '' THEN 'ذمة العميل - فاتورة ' || NEW.invoice_number || ' - ' || NEW.notes ELSE 'ذمة العميل - فاتورة ' || NEW.invoice_number END,
        'customer', NEW.customer_id,
        'sales_invoice', NEW.id
    );
    
    -- 2. دائن: حساب المبيعات (المبلغ قبل الضريبة)
    INSERT INTO journal_entry_lines (
        tenant_id, entry_id, line_number,
        account_id, debit, credit,
        currency, exchange_rate,
        description,
        reference_type, reference_id
    )
    VALUES (
        NEW.tenant_id, v_entry_id, 2,
        v_sales_account_id, 0, NEW.taxable_amount,
        NEW.currency, NEW.exchange_rate,
        CASE WHEN NEW.notes IS NOT NULL AND NEW.notes != '' THEN 'إيراد مبيعات - فاتورة ' || NEW.invoice_number || ' - ' || NEW.notes ELSE 'إيراد مبيعات - فاتورة ' || NEW.invoice_number END,
        'sales_invoice', NEW.id
    );
    
    -- 3. دائن: حساب ضريبة القيمة المضافة (إذا وجدت)
    IF NEW.tax_amount > 0 AND v_vat_account_id IS NOT NULL THEN
        INSERT INTO journal_entry_lines (
            tenant_id, entry_id, line_number,
            account_id, debit, credit,
            currency, exchange_rate,
            description,
            reference_type, reference_id
        )
        VALUES (
            NEW.tenant_id, v_entry_id, 3,
            v_vat_account_id, 0, NEW.tax_amount,
            NEW.currency, NEW.exchange_rate,
            'ضريبة القيمة المضافة - فاتورة ' || NEW.invoice_number,
            'sales_invoice', NEW.id
        );
    END IF;
    
    -- تحديث الفاتورة بربط القيد
    NEW.journal_entry_id := v_entry_id;
    NEW.posted_at := NOW();
    
    -- تحديث رصيد العميل
    UPDATE customers
    SET balance = balance + NEW.total_amount,
        total_sales = total_sales + NEW.total_amount
    WHERE id = NEW.customer_id;
    
    RAISE NOTICE 'تم إنشاء قيد فاتورة المبيعات: % - المبلغ: %', v_entry_number, NEW.total_amount;
    
    RETURN NEW;
END;
$$;


--
-- Name: create_shipment_document(uuid, character varying, uuid, character varying, character varying, character varying, character varying, character varying, character varying, text, character varying, character varying, character varying, character varying, character varying, character varying, numeric, integer, numeric, numeric, text, numeric, numeric, numeric, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_shipment_document(p_company_id uuid, p_source_table character varying, p_source_id uuid, p_carrier_code character varying, p_recipient_name character varying, p_recipient_phone character varying, p_recipient_city character varying DEFAULT NULL::character varying, p_recipient_city_ref character varying DEFAULT NULL::character varying, p_recipient_address_ref character varying DEFAULT NULL::character varying, p_recipient_address_street text DEFAULT NULL::text, p_recipient_building character varying DEFAULT NULL::character varying, p_recipient_flat character varying DEFAULT NULL::character varying, p_service_type character varying DEFAULT 'WarehouseWarehouse'::character varying, p_cargo_type character varying DEFAULT 'Parcel'::character varying, p_payer_type character varying DEFAULT 'Sender'::character varying, p_payment_method character varying DEFAULT 'NonCash'::character varying, p_weight numeric DEFAULT 1.0, p_seats_amount integer DEFAULT 1, p_declared_value numeric DEFAULT 0, p_cod_amount numeric DEFAULT 0, p_description text DEFAULT NULL::text, p_length numeric DEFAULT NULL::numeric, p_width numeric DEFAULT NULL::numeric, p_height numeric DEFAULT NULL::numeric, p_created_by uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_tenant_id UUID;
    v_carrier RECORD;
    v_doc_id UUID;
    v_np_request JSONB;
BEGIN
    -- Get tenant_id from company
    SELECT tenant_id INTO v_tenant_id FROM companies WHERE id = p_company_id;
    IF v_tenant_id IS NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'Company not found');
    END IF;
    
    -- Get carrier config
    SELECT * INTO v_carrier 
    FROM shipping_carriers 
    WHERE company_id = p_company_id 
      AND carrier_code = p_carrier_code 
      AND is_active = true
    LIMIT 1;
    
    IF v_carrier.id IS NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'Carrier not configured: ' || p_carrier_code);
    END IF;
    
    -- Create shipment document record
    INSERT INTO shipment_documents (
        tenant_id, company_id, carrier_id,
        source_table, source_id, carrier_code,
        status,
        -- Sender (from carrier config)
        sender_ref, sender_city_ref, sender_address_ref,
        sender_contact_ref, sender_phone,
        -- Recipient
        recipient_city_name, recipient_city_ref,
        recipient_address_ref, recipient_address_street,
        recipient_building, recipient_flat,
        recipient_contact_name, recipient_phone,
        -- Details
        service_type, cargo_type, payer_type, payment_method,
        weight, seats_amount,
        length, width, height,
        declared_value, cod_amount,
        description,
        created_by
    ) VALUES (
        v_tenant_id, p_company_id, v_carrier.id,
        p_source_table, p_source_id, p_carrier_code,
        'pending',
        -- Sender
        v_carrier.np_sender_ref, v_carrier.np_sender_city_ref, v_carrier.np_sender_address_ref,
        v_carrier.np_sender_contact_ref, v_carrier.np_sender_phone,
        -- Recipient
        p_recipient_city, p_recipient_city_ref,
        p_recipient_address_ref, p_recipient_address_street,
        p_recipient_building, p_recipient_flat,
        p_recipient_name, p_recipient_phone,
        -- Details
        p_service_type, p_cargo_type, p_payer_type, p_payment_method,
        p_weight, p_seats_amount,
        p_length, p_width, p_height,
        p_declared_value, p_cod_amount,
        p_description,
        p_created_by
    )
    RETURNING id INTO v_doc_id;
    
    -- Build Nova Poshta API request (for n8n to send)
    IF p_carrier_code = 'nova_poshta' THEN
        v_np_request := jsonb_build_object(
            'apiKey', '__API_KEY__',  -- n8n يستبدله بمفتاح API المشفر
            'modelName', 'InternetDocument',
            'calledMethod', 'save',
            'methodProperties', jsonb_build_object(
                'PayerType', p_payer_type,
                'PaymentMethod', p_payment_method,
                'DateTime', to_char(NOW(), 'DD.MM.YYYY'),
                'CargoType', p_cargo_type,
                'Weight', p_weight::text,
                'SeatsAmount', p_seats_amount::text,
                'ServiceType', p_service_type,
                'Description', COALESCE(p_description, 'Shipment from TexaCore'),
                'Cost', p_declared_value::text,
                -- Sender
                'Sender', v_carrier.np_sender_ref,
                'CitySender', v_carrier.np_sender_city_ref,
                'SenderAddress', v_carrier.np_sender_address_ref,
                'ContactSender', v_carrier.np_sender_contact_ref,
                'SendersPhone', v_carrier.np_sender_phone,
                -- Recipient (dynamic)
                'RecipientCityName', COALESCE(p_recipient_city, ''),
                'RecipientAddressName', COALESCE(p_recipient_address_ref, ''),
                'RecipientName', p_recipient_name,
                'RecipientsPhone', p_recipient_phone,
                -- Volume
                'VolumeGeneral', CASE 
                    WHEN p_length IS NOT NULL AND p_width IS NOT NULL AND p_height IS NOT NULL 
                    THEN ((p_length * p_width * p_height) / 1000000)::text
                    ELSE '0.001'
                END
            )
        );
        
        -- Add BackwardDeliveryData if COD
        IF p_cod_amount > 0 THEN
            v_np_request := jsonb_set(
                v_np_request,
                '{methodProperties,BackwardDeliveryData}',
                jsonb_build_array(
                    jsonb_build_object(
                        'PayerType', 'Recipient',
                        'CargoType', 'Money',
                        'RedeliveryString', p_cod_amount::text
                    )
                )
            );
        END IF;
        
        -- Add dimensions if provided
        IF p_length IS NOT NULL THEN
            v_np_request := jsonb_set(
                v_np_request,
                '{methodProperties,OptionsSeat}',
                jsonb_build_array(
                    jsonb_build_object(
                        'volumetricLength', p_length::text,
                        'volumetricWidth', p_width::text,
                        'volumetricHeight', p_height::text,
                        'weight', p_weight::text
                    )
                )
            );
        END IF;
        
        -- Save the request template
        UPDATE shipment_documents SET api_request = v_np_request WHERE id = v_doc_id;
    END IF;
    
    -- Return everything n8n needs
    RETURN jsonb_build_object(
        'success', true,
        'shipment_document_id', v_doc_id,
        'carrier_code', p_carrier_code,
        'carrier_id', v_carrier.id,
        'api_endpoint', COALESCE(v_carrier.api_endpoint, 'https://api.novaposhta.ua/v2.0/json/'),
        'n8n_webhook', v_carrier.n8n_create_shipment_webhook,
        'np_api_request', v_np_request,
        'tracking_url_template', v_carrier.tracking_url_template
    );
END;
$$;


--
-- Name: create_simple_chart(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_simple_chart(p_company_id uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_tenant_id UUID;
    v_base_currency VARCHAR(10);
    v_intl_currency VARCHAR(10);
    v_asset_type UUID; v_current_asset_type UUID; v_fixed_asset_type UUID;
    v_liability_type UUID; v_current_liability_type UUID; v_long_liability_type UUID;
    v_equity_type UUID; v_revenue_type UUID; v_expense_type UUID; v_cogs_type UUID;
    v_assets_id UUID; v_current_assets_id UUID;
    v_cash_grp UUID; v_banks_grp UUID; v_inv_grp UUID;
    v_fixed_assets_id UUID;
    v_exchange_assets_id UUID;
    v_liabilities_id UUID; v_current_liab_id UUID; v_long_liab_id UUID;
    v_exchange_liab_id UUID;
    v_equity_id UUID;
    v_revenue_id UUID; v_rev_ops_id UUID; v_rev_other_id UUID; v_rev_exchange_id UUID;
    v_expenses_id UUID; v_cogs_grp UUID; v_purchases_grp UUID;
    v_opex_grp UUID; v_exchange_exp_id UUID;
    v_freight_grp UUID; v_misc_grp UUID;
BEGIN
    SELECT tenant_id INTO v_tenant_id FROM companies WHERE id = p_company_id;
    IF v_tenant_id IS NULL THEN RAISE EXCEPTION 'Company not found: %', p_company_id; END IF;
    IF EXISTS (SELECT 1 FROM chart_of_accounts WHERE company_id = p_company_id LIMIT 1) THEN RETURN; END IF;

    -- V6: العملة الديناميكية
    SELECT COALESCE(cas.base_currency, c.default_currency, 'USD'),
           COALESCE((c.accounting_settings->>'default_international_purchase_currency'), 'USD')
    INTO v_base_currency, v_intl_currency
    FROM companies c LEFT JOIN company_accounting_settings cas ON cas.company_id = c.id
    WHERE c.id = p_company_id;
    IF v_base_currency IS NULL THEN v_base_currency := 'USD'; END IF;
    IF v_intl_currency IS NULL THEN v_intl_currency := 'USD'; END IF;
    IF v_base_currency = v_intl_currency THEN v_intl_currency := v_base_currency; END IF;

    -- Account types
    SELECT id INTO v_asset_type FROM account_types WHERE code = 'ASSET';
    SELECT id INTO v_current_asset_type FROM account_types WHERE code = 'CURRENT_ASSET';
    SELECT id INTO v_fixed_asset_type FROM account_types WHERE code = 'FIXED_ASSET';
    SELECT id INTO v_liability_type FROM account_types WHERE code = 'LIABILITY';
    SELECT id INTO v_current_liability_type FROM account_types WHERE code = 'CURRENT_LIABILITY';
    SELECT id INTO v_long_liability_type FROM account_types WHERE code IN ('LONG_TERM_LIABILITY','NON_CURRENT_LIABILITY','LIABILITY');
    IF v_long_liability_type IS NULL THEN v_long_liability_type := v_liability_type; END IF;
    SELECT id INTO v_equity_type FROM account_types WHERE code = 'EQUITY';
    SELECT id INTO v_revenue_type FROM account_types WHERE code = 'REVENUE';
    SELECT id INTO v_expense_type FROM account_types WHERE code = 'EXPENSE';
    SELECT id INTO v_cogs_type FROM account_types WHERE code = 'COGS';
    IF v_cogs_type IS NULL THEN v_cogs_type := v_expense_type; END IF;

    -- ═══ 1️⃣ الأصول ═══
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active, currency)
    VALUES (v_tenant_id, p_company_id, '1', 'الأصول', 'Assets', v_asset_type, NULL, false, true, v_base_currency) RETURNING id INTO v_assets_id;

    -- 11 الأصول المتداولة
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active, currency)
    VALUES (v_tenant_id, p_company_id, '11', 'الأصول المتداولة', 'Current Assets', v_current_asset_type, v_assets_id, false, true, v_base_currency) RETURNING id INTO v_current_assets_id;

    -- 111 الصندوق
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active, currency)
    VALUES (v_tenant_id, p_company_id, '111', 'الصندوق', 'Cash', v_current_asset_type, v_current_assets_id, false, true, v_base_currency) RETURNING id INTO v_cash_grp;
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active, is_cash_account, currency)
    VALUES
        (v_tenant_id, p_company_id, '1111', 'صندوق - عملة محلية', 'Cash - Local Currency', v_current_asset_type, v_cash_grp, true, true, true, v_base_currency),
        (v_tenant_id, p_company_id, '1112', 'صندوق - عملة أساسية', 'Cash - Base Currency', v_current_asset_type, v_cash_grp, true, true, true, v_intl_currency);

    -- 112 البنوك
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active, currency)
