--
-- Name: create_supplier_account(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_supplier_account() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_parent_id UUID;
    v_account_type_id UUID;
    v_new_code VARCHAR(50);
    v_new_account_id UUID;
    v_full_code VARCHAR(200);
BEGIN
    -- الحصول على حساب الموردين الأب (2110)
    SELECT id INTO v_parent_id 
    FROM chart_of_accounts 
    WHERE company_id = NEW.company_id 
      AND account_code = '2110';
    
    IF v_parent_id IS NULL THEN
        -- لا توجد شجرة حسابات، تخطي
        RAISE NOTICE 'لا توجد شجرة حسابات للشركة، تخطي إنشاء حساب المورد';
        RETURN NEW;
    END IF;
    
    -- الحصول على نوع الحساب
    SELECT id INTO v_account_type_id FROM account_types WHERE code = 'CURRENT_LIABILITY';
    
    -- توليد رقم الحساب الجديد
    v_new_code := generate_next_account_code(NEW.tenant_id, NEW.company_id, '2110');
    v_full_code := '2000.2100.2110.' || v_new_code;
    
    -- إنشاء الحساب الفرعي للمورد
    INSERT INTO chart_of_accounts (
        tenant_id, company_id, account_code, 
        name_ar, name_en, 
        account_type_id, parent_id, 
        is_group, is_detail, level, full_code, 
        currency, is_active, is_payable
    )
    VALUES (
        NEW.tenant_id, NEW.company_id, v_new_code,
        NEW.name_ar, COALESCE(NEW.name_en, NEW.name_ar),
        v_account_type_id, v_parent_id,
        false, true, 4, v_full_code,
        COALESCE(NEW.currency, 'SAR'), true, true
    )
    RETURNING id INTO v_new_account_id;
    
    -- تحديث المورد بربط الحساب
    NEW.payable_account_id := v_new_account_id;
    
    RAISE NOTICE 'تم إنشاء حساب للمورد: % - رقم الحساب: %', NEW.name_ar, v_new_code;
    
    RETURN NEW;
END;
$$;


--
-- Name: deduct_inventory_on_sale(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.deduct_inventory_on_sale() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_item RECORD;
    v_movement_number VARCHAR(50);
    v_warehouse_id UUID;
BEGIN
    -- فقط عند تأكيد الفاتورة
    IF NEW.status != 'posted' THEN
        RETURN NEW;
    END IF;
    
    -- تخطي إذا تم معالجة المخزون مسبقاً
    IF OLD.status = 'posted' THEN
        RETURN NEW;
    END IF;
    
    -- الحصول على المستودع الافتراضي
    v_warehouse_id := NEW.warehouse_id;
    IF v_warehouse_id IS NULL THEN
        SELECT id INTO v_warehouse_id
        FROM warehouses
        WHERE company_id = NEW.company_id
          AND is_active = true
        ORDER BY created_at
        LIMIT 1;
    END IF;
    
    IF v_warehouse_id IS NULL THEN
        RAISE NOTICE 'لا يوجد مستودع، تخطي خصم المخزون';
        RETURN NEW;
    END IF;
    
    -- معالجة كل صنف في الفاتورة
    FOR v_item IN 
        SELECT * FROM sales_invoice_items 
        WHERE invoice_id = NEW.id 
          AND product_id IS NOT NULL
    LOOP
        -- توليد رقم الحركة
        v_movement_number := 'MV-SI-' || NEW.invoice_number || '-' || v_item.line_number;
        
        -- إنشاء حركة مخزون (صادر - بيع)
        INSERT INTO inventory_movements (
            tenant_id, company_id,
            movement_number, movement_date,
            movement_type,
            product_id, variant_id,
            from_warehouse_id,
            quantity, unit_id,
            unit_cost, total_cost,
            reference_type, reference_id, reference_number,
            notes,
            created_by
        )
        VALUES (
            NEW.tenant_id, NEW.company_id,
            v_movement_number, NEW.invoice_date,
            'sale',
            v_item.product_id, v_item.variant_id,
            COALESCE(v_item.warehouse_id, v_warehouse_id),
            v_item.quantity, v_item.unit_id,
            v_item.unit_cost, v_item.total_cost,
            'sales_invoice', NEW.id, NEW.invoice_number,
            'خصم مخزون - فاتورة مبيعات ' || NEW.invoice_number,
            NEW.created_by
        );
        
        RAISE NOTICE 'تم خصم المخزون للصنف: % - الكمية: %', v_item.product_id, v_item.quantity;
    END LOOP;
    
    RETURN NEW;
END;
$$;


--
-- Name: execute_readonly_query(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.execute_readonly_query(query_text text) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET statement_timeout TO '5000'
    AS $$
DECLARE
  result JSON;
  clean_query TEXT;
BEGIN
  -- Security: Normalize and validate
  clean_query := LOWER(TRIM(query_text));
  
  -- Only allow SELECT and WITH (CTE) statements
  IF NOT (clean_query LIKE 'select%' OR clean_query LIKE 'with%') THEN
    RAISE EXCEPTION 'Only SELECT queries are allowed';
  END IF;
  
  -- Block any mutation keywords
  IF clean_query ~ '\b(insert|update|delete|drop|alter|create|truncate|grant|revoke|execute|copy|pg_)\b' THEN
    RAISE EXCEPTION 'Mutation or system queries are not allowed';
  END IF;
  
  -- Execute with row limit
  EXECUTE 'SELECT COALESCE(json_agg(t), ''[]''::json) FROM (' || query_text || ' LIMIT 500) t' INTO result;
  
  RETURN result;
END;
$$;


--
-- Name: fn_container_status_notification(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_container_status_notification() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    rule JSONB;
    rule_user_id UUID;
    rule_trigger TEXT;
    rule_enabled BOOLEAN;
    rule_role TEXT;
    v_container_name TEXT;
    v_container_number TEXT;
    new_status_label_ar TEXT;
    new_status_label_en TEXT;
    notification_title_ar TEXT;
    notification_title_en TEXT;
    notification_body_ar TEXT;
    notification_body_en TEXT;
BEGIN
    IF OLD.status IS NOT DISTINCT FROM NEW.status THEN RETURN NEW; END IF;
    IF NEW.notification_rules IS NULL OR NEW.notification_rules = '[]'::JSONB OR jsonb_array_length(NEW.notification_rules) = 0 THEN RETURN NEW; END IF;
    
    v_container_number := COALESCE(NEW.container_number, NEW.shipment_number, 'N/A');
    v_container_name := COALESCE(NEW.container_name, v_container_number);
    
    new_status_label_ar := CASE NEW.status
        WHEN 'draft' THEN 'مسودة' WHEN 'booked' THEN 'تم الحجز' WHEN 'loading' THEN 'جاري التحميل'
        WHEN 'in_transit' THEN 'بالبحر' WHEN 'at_port' THEN 'وصل الميناء' WHEN 'customs' THEN 'بالجمركة'
        WHEN 'cleared' THEN 'تم التخليص' WHEN 'delivered' THEN 'تم التسليم' WHEN 'received' THEN 'تم الاستلام'
        ELSE NEW.status END;
    
    new_status_label_en := CASE NEW.status
        WHEN 'draft' THEN 'Draft' WHEN 'booked' THEN 'Booked' WHEN 'loading' THEN 'Loading'
        WHEN 'in_transit' THEN 'In Transit' WHEN 'at_port' THEN 'At Port' WHEN 'customs' THEN 'At Customs'
        WHEN 'cleared' THEN 'Cleared' WHEN 'delivered' THEN 'Delivered' WHEN 'received' THEN 'Received'
        ELSE NEW.status END;
    
    FOR rule IN SELECT jsonb_array_elements(NEW.notification_rules)
    LOOP
        rule_enabled := COALESCE((rule ->> 'enabled')::BOOLEAN, false);
        rule_trigger := rule ->> 'trigger_status';
        rule_user_id := (rule ->> 'user_id')::UUID;
        rule_role := COALESCE(rule ->> 'role', 'unknown');
        
        IF NOT rule_enabled THEN CONTINUE; END IF;
        IF rule_trigger IS NULL OR rule_trigger != NEW.status THEN CONTINUE; END IF;
        IF rule_user_id IS NULL THEN CONTINUE; END IF;
        
        notification_title_ar := 'كونتينر ' || v_container_number || ' — ' || new_status_label_ar;
        notification_title_en := 'Container ' || v_container_number || ' — ' || new_status_label_en;
        
        IF rule_role = 'warehouse' THEN
            notification_body_ar := 'الكونتينر "' || v_container_name || '" أصبح جاهزاً للاستلام في المستودع';
            notification_body_en := 'Container "' || v_container_name || '" is ready for warehouse receiving';
        ELSIF rule_role = 'sales' THEN
            notification_body_ar := 'الكونتينر "' || v_container_name || '" وصل للحالة: ' || new_status_label_ar;
            notification_body_en := 'Container "' || v_container_name || '" reached status: ' || new_status_label_en;
        ELSE
            notification_body_ar := 'حالة الكونتينر تغيرت إلى: ' || new_status_label_ar;
            notification_body_en := 'Container status changed to: ' || new_status_label_en;
        END IF;
        
        INSERT INTO notifications (tenant_id, user_id, title, body, type, source_type, source_id, metadata)
        VALUES (
            NEW.company_id, rule_user_id,
            notification_title_ar || ' | ' || notification_title_en,
            notification_body_ar || ' | ' || notification_body_en,
            CASE WHEN NEW.status IN ('cleared','received','delivered') THEN 'success'
                 WHEN NEW.status = 'customs' THEN 'warning' ELSE 'info' END,
            'container', NEW.id,
            jsonb_build_object(
                'container_number', v_container_number, 'container_name', v_container_name,
                'old_status', OLD.status, 'new_status', NEW.status, 'role', rule_role,
                'status_label_ar', new_status_label_ar, 'status_label_en', new_status_label_en
            )
        );
    END LOOP;
    RETURN NEW;
END;
$$;


--
-- Name: fn_mark_all_notifications_read(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_mark_all_notifications_read() RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE affected INTEGER;
BEGIN
    UPDATE notifications SET is_read = true, read_at = now(), updated_at = now()
    WHERE user_id = auth.uid() AND is_read = false;
    GET DIAGNOSTICS affected = ROW_COUNT;
    RETURN affected;
END;
$$;


--
-- Name: fn_mark_notifications_read(uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_mark_notifications_read(notification_ids uuid[]) RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE affected INTEGER;
BEGIN
    UPDATE notifications SET is_read = true, read_at = now(), updated_at = now()
    WHERE id = ANY(notification_ids) AND user_id = auth.uid() AND is_read = false;
    GET DIAGNOSTICS affected = ROW_COUNT;
    RETURN affected;
END;
$$;


--
-- Name: fn_mark_overdue_installments(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_mark_overdue_installments() RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE payment_schedule_items
    SET status = 'overdue', updated_at = NOW()
    WHERE status = 'pending'
      AND due_date < CURRENT_DATE;
END;
$$;


--
-- Name: fn_purchase_invoice_notification(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_purchase_invoice_notification() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    status_ar TEXT; status_en TEXT; notif_type TEXT; v_invoice_num TEXT;
BEGIN
    IF OLD.status IS NOT DISTINCT FROM NEW.status THEN RETURN NEW; END IF;
    IF NEW.created_by IS NULL THEN RETURN NEW; END IF;
    v_invoice_num := COALESCE(NEW.invoice_number, 'N/A');
    
    status_ar := CASE NEW.status
        WHEN 'draft' THEN 'مسودة' WHEN 'pending' THEN 'بانتظار الموافقة'
        WHEN 'approved' THEN 'تمت الموافقة' WHEN 'confirmed' THEN 'مؤكدة'
        WHEN 'posted' THEN 'مرحّلة' WHEN 'paid' THEN 'مدفوعة'
        WHEN 'partial_paid' THEN 'مدفوعة جزئياً' WHEN 'cancelled' THEN 'ملغاة'
        WHEN 'rejected' THEN 'مرفوضة' ELSE NEW.status END;
    
    status_en := CASE NEW.status
        WHEN 'draft' THEN 'Draft' WHEN 'pending' THEN 'Pending Approval'
        WHEN 'approved' THEN 'Approved' WHEN 'confirmed' THEN 'Confirmed'
        WHEN 'posted' THEN 'Posted' WHEN 'paid' THEN 'Paid'
        WHEN 'partial_paid' THEN 'Partially Paid' WHEN 'cancelled' THEN 'Cancelled'
        WHEN 'rejected' THEN 'Rejected' ELSE NEW.status END;
    
    notif_type := CASE 
        WHEN NEW.status IN ('approved','posted','paid') THEN 'success'
        WHEN NEW.status IN ('cancelled','rejected') THEN 'error'
        WHEN NEW.status = 'pending' THEN 'warning' ELSE 'info' END;
    
    INSERT INTO notifications (tenant_id, user_id, title, body, type, source_type, source_id, metadata)
    VALUES (
        NEW.company_id, NEW.created_by,
        'فاتورة مشتريات ' || v_invoice_num || ' — ' || status_ar || ' | Purchase Invoice ' || v_invoice_num || ' — ' || status_en,
        'حالة فاتورة المشتريات تغيرت إلى: ' || status_ar || ' | Purchase invoice status changed to: ' || status_en,
        notif_type, 'purchase_invoice', NEW.id,
        jsonb_build_object('invoice_number', v_invoice_num, 'old_status', OLD.status, 'new_status', NEW.status, 'status_label_ar', status_ar, 'status_label_en', status_en)
    );
    RETURN NEW;
END;
$$;


