--
-- Name: get_account_ledger_fc(uuid, uuid, date, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_account_ledger_fc(p_account_id uuid, p_company_id uuid, p_from_date date DEFAULT NULL::date, p_to_date date DEFAULT NULL::date) RETURNS TABLE(line_id uuid, entry_id uuid, entry_number text, entry_date date, description text, debit numeric, credit numeric, running_balance numeric, currency text, original_currency text, exchange_rate numeric, entry_type text, status text)
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_running_balance NUMERIC := 0;
    v_record RECORD;
BEGIN
    FOR v_record IN
        SELECT
            jel.id AS line_id,
            je.id AS entry_id,
            je.entry_number,
            je.entry_date,
            COALESCE(jel.description, je.description, '') AS description,
            CASE
                WHEN jel.debit_fc IS NOT NULL AND (jel.debit_fc > 0 OR jel.debit = 0) THEN jel.debit_fc
                WHEN COALESCE(jel.exchange_rate, 1) > 1 THEN jel.debit / jel.exchange_rate
                ELSE jel.debit
            END AS fc_debit,
            CASE
                WHEN jel.credit_fc IS NOT NULL AND (jel.credit_fc > 0 OR jel.credit = 0) THEN jel.credit_fc
                WHEN COALESCE(jel.exchange_rate, 1) > 1 THEN jel.credit / jel.exchange_rate
                ELSE jel.credit
            END AS fc_credit,
            jel.currency AS original_currency,
            COALESCE(jel.exchange_rate, 1) AS exchange_rate,
            je.entry_type,
            je.status
        FROM journal_entry_lines jel
        INNER JOIN journal_entries je
            ON je.id = jel.entry_id
           AND je.company_id = p_company_id
           AND je.is_posted = true
           AND je.status = 'posted'
        WHERE jel.account_id = p_account_id
          AND (p_from_date IS NULL OR je.entry_date >= p_from_date)
          AND (p_to_date IS NULL OR je.entry_date <= p_to_date)
        ORDER BY je.entry_date ASC, je.entry_number ASC, jel.line_number ASC
    LOOP
        v_running_balance := v_running_balance + v_record.fc_debit - v_record.fc_credit;
        
        line_id := v_record.line_id;
        entry_id := v_record.entry_id;
        entry_number := v_record.entry_number;
        entry_date := v_record.entry_date;
        description := v_record.description;
        debit := ROUND(v_record.fc_debit, 2);
        credit := ROUND(v_record.fc_credit, 2);
        running_balance := ROUND(v_running_balance, 2);
        currency := v_record.original_currency;
        original_currency := v_record.original_currency;
        exchange_rate := v_record.exchange_rate;
        entry_type := v_record.entry_type;
        status := v_record.status;
        
        RETURN NEXT;
    END LOOP;
END;
$$;


--
-- Name: get_account_statement(uuid, date, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_account_statement(p_account_id uuid, p_from_date date DEFAULT NULL::date, p_to_date date DEFAULT NULL::date) RETURNS TABLE(entry_date date, entry_number character varying, reference_type character varying, reference_number character varying, description text, debit numeric, credit numeric, balance numeric)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_from_date DATE;
    v_to_date DATE;
    v_opening_balance DECIMAL(15,2);
    v_normal_balance VARCHAR(10);
BEGIN
    -- تحديد التواريخ
    v_from_date := COALESCE(p_from_date, DATE_TRUNC('year', CURRENT_DATE)::DATE);
    v_to_date := COALESCE(p_to_date, CURRENT_DATE);
    
    -- الحصول على الطبيعة الطبيعية للحساب
    SELECT at.normal_balance INTO v_normal_balance
    FROM chart_of_accounts coa
    JOIN account_types at ON coa.account_type_id = at.id
    WHERE coa.id = p_account_id;
    
    -- حساب الرصيد الافتتاحي
    SELECT 
        COALESCE(coa.opening_balance, 0) +
        CASE 
            WHEN v_normal_balance = 'debit' THEN 
                COALESCE(SUM(jel.debit - jel.credit), 0)
            ELSE 
                COALESCE(SUM(jel.credit - jel.debit), 0)
        END
    INTO v_opening_balance
    FROM chart_of_accounts coa
    LEFT JOIN journal_entry_lines jel ON coa.id = jel.account_id
    LEFT JOIN journal_entries je ON jel.entry_id = je.id 
        AND je.is_posted = true
        AND je.entry_date < v_from_date
    WHERE coa.id = p_account_id
    GROUP BY coa.id, coa.opening_balance;
    
    v_opening_balance := COALESCE(v_opening_balance, 0);
    
    RETURN QUERY
    WITH movements AS (
        SELECT 
            je.entry_date,
            je.entry_number,
            je.reference_type,
            je.reference_number,
            COALESCE(jel.description, je.description) as description,
            jel.debit,
            jel.credit,
            ROW_NUMBER() OVER (ORDER BY je.entry_date, je.created_at) as rn
        FROM journal_entry_lines jel
        JOIN journal_entries je ON jel.entry_id = je.id
        WHERE jel.account_id = p_account_id
          AND je.is_posted = true
          AND je.entry_date BETWEEN v_from_date AND v_to_date
    )
    -- الرصيد الافتتاحي
    SELECT 
        v_from_date as entry_date,
        'OPENING'::VARCHAR(50) as entry_number,
        'opening_balance'::VARCHAR(50) as reference_type,
        ''::VARCHAR(100) as reference_number,
        'رصيد افتتاحي'::TEXT as description,
        CASE WHEN v_opening_balance > 0 AND v_normal_balance = 'debit' THEN v_opening_balance ELSE 0::DECIMAL(15,2) END as debit,
        CASE WHEN v_opening_balance > 0 AND v_normal_balance = 'credit' THEN v_opening_balance ELSE 0::DECIMAL(15,2) END as credit,
        v_opening_balance as balance
    
    UNION ALL
    
    -- الحركات
    SELECT 
        m.entry_date,
        m.entry_number,
        m.reference_type,
        m.reference_number,
        m.description,
        m.debit,
        m.credit,
        v_opening_balance + SUM(
            CASE WHEN v_normal_balance = 'debit' THEN m.debit - m.credit ELSE m.credit - m.debit END
        ) OVER (ORDER BY m.rn) as balance
    FROM movements m
    
    ORDER BY entry_date, entry_number;
END;
$$;


--
-- Name: get_account_summary(uuid, date, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_account_summary(p_account_id uuid, p_from_date date DEFAULT NULL::date, p_to_date date DEFAULT NULL::date) RETURNS TABLE(account_code character varying, account_name_ar character varying, opening_balance numeric, total_debit numeric, total_credit numeric, closing_balance numeric, transactions_count integer)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_from_date DATE;
    v_to_date DATE;
BEGIN
    v_from_date := COALESCE(p_from_date, DATE_TRUNC('year', CURRENT_DATE)::DATE);
    v_to_date := COALESCE(p_to_date, CURRENT_DATE);
    
    RETURN QUERY
    SELECT 
        coa.account_code,
        coa.name_ar as account_name_ar,
        COALESCE(coa.opening_balance, 0) + COALESCE(SUM(
            CASE WHEN je.entry_date < v_from_date THEN 
                CASE WHEN at.normal_balance = 'debit' THEN jel.debit - jel.credit ELSE jel.credit - jel.debit END
            ELSE 0 END
        ), 0) as opening_balance,
        COALESCE(SUM(CASE WHEN je.entry_date BETWEEN v_from_date AND v_to_date THEN jel.debit ELSE 0 END), 0) as total_debit,
        COALESCE(SUM(CASE WHEN je.entry_date BETWEEN v_from_date AND v_to_date THEN jel.credit ELSE 0 END), 0) as total_credit,
        COALESCE(coa.opening_balance, 0) + COALESCE(SUM(
            CASE WHEN at.normal_balance = 'debit' THEN jel.debit - jel.credit ELSE jel.credit - jel.debit END
        ), 0) as closing_balance,
        COUNT(DISTINCT CASE WHEN je.entry_date BETWEEN v_from_date AND v_to_date THEN je.id END)::INT as transactions_count
    FROM chart_of_accounts coa
    JOIN account_types at ON coa.account_type_id = at.id
    LEFT JOIN journal_entry_lines jel ON coa.id = jel.account_id
    LEFT JOIN journal_entries je ON jel.entry_id = je.id 
        AND je.is_posted = true
        AND je.entry_date <= v_to_date
    WHERE coa.id = p_account_id
    GROUP BY coa.id, coa.account_code, coa.name_ar, coa.opening_balance, at.normal_balance;
END;
$$;


--
-- Name: get_account_type_id(character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_account_type_id(p_account_type character varying) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_type_id UUID;
    v_classification VARCHAR(50);
    v_normal_balance VARCHAR(10);
BEGIN
    -- تحديد classification و normal_balance حسب account_type
    CASE p_account_type
        WHEN 'asset' THEN
            v_classification := 'assets';
            v_normal_balance := 'debit';
        WHEN 'liability' THEN
            v_classification := 'liabilities';
            v_normal_balance := 'credit';
        WHEN 'equity' THEN
            v_classification := 'equity';
            v_normal_balance := 'credit';
        WHEN 'revenue' THEN
            v_classification := 'income';
            v_normal_balance := 'credit';
        WHEN 'expense' THEN
            v_classification := 'expenses';
            v_normal_balance := 'debit';
        ELSE
            v_classification := 'assets';
            v_normal_balance := 'debit';
    END CASE;
    
    -- البحث عن account_type_id المناسب
    SELECT id INTO v_type_id
    FROM account_types
    WHERE classification = v_classification
      AND normal_balance = v_normal_balance
    ORDER BY display_order
    LIMIT 1;
    
    -- إذا لم يوجد، استخدم ASSET كافتراضي
    IF v_type_id IS NULL THEN
        SELECT id INTO v_type_id FROM account_types WHERE code = 'ASSET';
    END IF;
    
    RETURN v_type_id;
END;
$$;


--
-- Name: get_accounting_dashboard(uuid, text, date, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_accounting_dashboard(p_company_id uuid, p_base_currency text, p_from_date date DEFAULT NULL::date, p_to_date date DEFAULT NULL::date) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_from date := COALESCE(p_from_date, date_trunc('month', CURRENT_DATE)::date);
  v_to date := COALESCE(p_to_date, CURRENT_DATE);
  v_result jsonb;
  v_trial_balance jsonb;
  v_top_accounts jsonb;
  v_alerts jsonb;
  v_kpis jsonb;
  v_monthly jsonb;
  v_total_debit numeric := 0;
  v_total_credit numeric := 0;
  v_journal_count int := 0;
  v_draft_count int := 0;
  v_posted_count int := 0;
BEGIN
  -- 1. KPIs
  WITH account_balances AS (
    SELECT
      at.classification,
      at.code as type_code,
      SUM(CASE WHEN at.normal_balance = 'debit' THEN jel.debit - jel.credit ELSE jel.credit - jel.debit END) as balance
    FROM journal_entry_lines jel
    JOIN journal_entries je ON je.id = jel.entry_id
    JOIN chart_of_accounts a ON a.id = jel.account_id
    JOIN account_types at ON at.id = a.account_type_id
    WHERE je.company_id = p_company_id
      AND je.is_posted = true
      AND je.entry_date >= v_from AND je.entry_date <= v_to
    GROUP BY at.classification, at.code
  )
  SELECT jsonb_build_object(
    'revenue', COALESCE((SELECT SUM(balance) FROM account_balances WHERE classification = 'income'), 0),
    'expenses', COALESCE((SELECT SUM(balance) FROM account_balances WHERE classification = 'expenses'), 0),
    'cashBalance', COALESCE((
      SELECT SUM(jel.debit - jel.credit)
      FROM journal_entry_lines jel
      JOIN journal_entries je ON je.id = jel.entry_id
      JOIN chart_of_accounts a ON a.id = jel.account_id
      WHERE je.company_id = p_company_id AND je.is_posted = true
        AND (a.account_code LIKE '111%' OR a.account_code LIKE '112%')
    ), 0),
    'receivables', COALESCE((
      SELECT SUM(jel.debit - jel.credit)
      FROM journal_entry_lines jel
      JOIN journal_entries je ON je.id = jel.entry_id
      JOIN chart_of_accounts a ON a.id = jel.account_id
      WHERE je.company_id = p_company_id AND je.is_posted = true
        AND a.account_code LIKE '113%'
    ), 0),
    'payables', COALESCE((
      SELECT SUM(jel.credit - jel.debit)
      FROM journal_entry_lines jel
      JOIN journal_entries je ON je.id = jel.entry_id
      JOIN chart_of_accounts a ON a.id = jel.account_id
      WHERE je.company_id = p_company_id AND je.is_posted = true
        AND a.account_code LIKE '2%'
    ), 0)
  ) INTO v_kpis;

  -- 2. Journal Stats
  SELECT COUNT(*), 
    COUNT(*) FILTER (WHERE status = 'draft'),
    COUNT(*) FILTER (WHERE status = 'posted')
  INTO v_journal_count, v_draft_count, v_posted_count
  FROM journal_entries
  WHERE company_id = p_company_id
    AND entry_date >= v_from AND entry_date <= v_to;

  -- 3. Trial Balance
  SELECT SUM(jel.debit), SUM(jel.credit)
  INTO v_total_debit, v_total_credit
  FROM journal_entry_lines jel
  JOIN journal_entries je ON je.id = jel.entry_id
  WHERE je.company_id = p_company_id AND je.is_posted = true;

  v_trial_balance := jsonb_build_object(
    'totalDebit', COALESCE(v_total_debit, 0),
    'totalCredit', COALESCE(v_total_credit, 0),
    'difference', COALESCE(v_total_debit - v_total_credit, 0),
    'isBalanced', COALESCE(v_total_debit = v_total_credit, true)
  );

  -- 4. Top 8 Accounts
  SELECT COALESCE(jsonb_agg(row_to_json(sub)::jsonb ORDER BY sub.activity DESC), '[]'::jsonb)
  INTO v_top_accounts
  FROM (
    SELECT
      a.account_code as "accountCode",
      a.name_ar as "accountName",
      at.name_ar as "typeName",
      at.classification,
      SUM(jel.debit + jel.credit) as activity,
      SUM(CASE WHEN at.normal_balance = 'debit' THEN jel.debit - jel.credit ELSE jel.credit - jel.debit END) as balance
    FROM journal_entry_lines jel
    JOIN journal_entries je ON je.id = jel.entry_id
    JOIN chart_of_accounts a ON a.id = jel.account_id AND a.is_detail = true
    JOIN account_types at ON at.id = a.account_type_id
    WHERE je.company_id = p_company_id AND je.is_posted = true
      AND je.entry_date >= v_from AND je.entry_date <= v_to
    GROUP BY a.account_code, a.name_ar, at.name_ar, at.classification
    ORDER BY activity DESC
    LIMIT 8
  ) sub;

  -- 5. Alerts
  SELECT jsonb_build_object(
    'draftEntries', v_draft_count,
    'isBalanced', COALESCE(v_total_debit = v_total_credit, true),
    'accountsCount', (SELECT COUNT(*) FROM chart_of_accounts WHERE company_id = p_company_id AND is_detail = true),
    'recurringPending', 0
  ) INTO v_alerts;

  -- 6. Monthly Revenue vs Expenses
  WITH months AS (
    SELECT generate_series(
      date_trunc('month', CURRENT_DATE - INTERVAL '5 months')::date,
      date_trunc('month', CURRENT_DATE)::date,
      '1 month'::interval
    )::date as month_start
  ),
  monthly_data AS (
    SELECT
      date_trunc('month', je.entry_date)::date as month_start,
      SUM(CASE WHEN at.classification = 'income' THEN jel.credit - jel.debit ELSE 0 END) as revenue,
      SUM(CASE WHEN at.classification = 'expenses' THEN jel.debit - jel.credit ELSE 0 END) as expenses
    FROM journal_entry_lines jel
    JOIN journal_entries je ON je.id = jel.entry_id
    JOIN chart_of_accounts a ON a.id = jel.account_id
    JOIN account_types at ON at.id = a.account_type_id
    WHERE je.company_id = p_company_id AND je.is_posted = true
      AND je.entry_date >= (CURRENT_DATE - INTERVAL '6 months')
      AND at.classification IN ('income', 'expenses')
    GROUP BY 1
  )
  SELECT COALESCE(jsonb_agg(
    jsonb_build_object(
      'month', to_char(m.month_start, 'YYYY-MM'),
      'label', to_char(m.month_start, 'Mon'),
      'revenue', ABS(COALESCE(md.revenue, 0)),
      'expenses', ABS(COALESCE(md.expenses, 0))
    ) ORDER BY m.month_start
  ), '[]'::jsonb)
  INTO v_monthly
  FROM months m
  LEFT JOIN monthly_data md ON md.month_start = m.month_start;

  -- Build result
  v_result := jsonb_build_object(
    'kpis', v_kpis,
    'journalStats', jsonb_build_object('total', v_journal_count, 'draft', v_draft_count, 'posted', v_posted_count),
    'trialBalance', v_trial_balance,
    'topAccounts', v_top_accounts,
    'alerts', v_alerts,
    'monthly', v_monthly
  );

  RETURN v_result;
END;
$$;


--
-- Name: get_accounting_dashboard_kpis(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_accounting_dashboard_kpis(p_company_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE result JSONB;
BEGIN
  SELECT jsonb_build_object(
    'total_assets', 0,
    'total_liabilities', 0,
    'total_equity', 0,
    'total_revenue', COALESCE((SELECT SUM(total_amount) FROM sales_transactions WHERE company_id = p_company_id), 0),
    'total_expenses', COALESCE((SELECT SUM(total_amount) FROM purchase_transactions WHERE company_id = p_company_id), 0),
    'net_income', 0,
    'accounts_receivable', COALESCE((SELECT SUM(balance) FROM customers WHERE company_id = p_company_id), 0),
    'accounts_payable', COALESCE((SELECT SUM(balance) FROM suppliers WHERE company_id = p_company_id), 0),
    'journal_entries_count', COALESCE((SELECT COUNT(*) FROM journal_entries WHERE company_id = p_company_id), 0),
    'unposted_entries', COALESCE((SELECT COUNT(*) FROM journal_entries WHERE company_id = p_company_id AND status = 'draft'), 0)
  ) INTO result;
  RETURN COALESCE(result, '{}'::jsonb);
END; $$;


--
-- Name: get_aging_report(uuid, character varying, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_aging_report(p_company_id uuid, p_party_type character varying DEFAULT 'customer'::character varying, p_as_of_date date DEFAULT CURRENT_DATE) RETURNS TABLE(party_id uuid, party_code character varying, party_name character varying, current_balance numeric, days_31_60 numeric, days_61_90 numeric, days_91_120 numeric, over_120_days numeric, total_balance numeric)
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF p_party_type = 'customer' THEN
        RETURN QUERY
        SELECT 
            c.id as party_id,
            c.code as party_code,
            c.name_ar as party_name,
            COALESCE(SUM(CASE WHEN p_as_of_date - si.invoice_date <= 30 THEN si.balance_due ELSE 0 END), 0) as current_balance,
            COALESCE(SUM(CASE WHEN p_as_of_date - si.invoice_date BETWEEN 31 AND 60 THEN si.balance_due ELSE 0 END), 0) as days_31_60,
            COALESCE(SUM(CASE WHEN p_as_of_date - si.invoice_date BETWEEN 61 AND 90 THEN si.balance_due ELSE 0 END), 0) as days_61_90,
            COALESCE(SUM(CASE WHEN p_as_of_date - si.invoice_date BETWEEN 91 AND 120 THEN si.balance_due ELSE 0 END), 0) as days_91_120,
            COALESCE(SUM(CASE WHEN p_as_of_date - si.invoice_date > 120 THEN si.balance_due ELSE 0 END), 0) as over_120_days,
            COALESCE(SUM(si.balance_due), 0) as total_balance
        FROM customers c
        LEFT JOIN sales_invoices si ON c.id = si.customer_id 
            AND si.company_id = p_company_id
            AND si.status = 'posted'
            AND si.balance_due > 0
            AND si.invoice_date <= p_as_of_date
        WHERE c.company_id = p_company_id
          AND c.status = 'active'
        GROUP BY c.id, c.code, c.name_ar
        HAVING COALESCE(SUM(si.balance_due), 0) > 0
        ORDER BY total_balance DESC;
    ELSE
        RETURN QUERY
        SELECT 
            s.id as party_id,
            s.code as party_code,
            s.name_ar as party_name,
            COALESCE(SUM(CASE WHEN p_as_of_date - pi.invoice_date <= 30 THEN pi.balance_due ELSE 0 END), 0) as current_balance,
            COALESCE(SUM(CASE WHEN p_as_of_date - pi.invoice_date BETWEEN 31 AND 60 THEN pi.balance_due ELSE 0 END), 0) as days_31_60,
            COALESCE(SUM(CASE WHEN p_as_of_date - pi.invoice_date BETWEEN 61 AND 90 THEN pi.balance_due ELSE 0 END), 0) as days_61_90,
            COALESCE(SUM(CASE WHEN p_as_of_date - pi.invoice_date BETWEEN 91 AND 120 THEN pi.balance_due ELSE 0 END), 0) as days_91_120,
            COALESCE(SUM(CASE WHEN p_as_of_date - pi.invoice_date > 120 THEN pi.balance_due ELSE 0 END), 0) as over_120_days,
            COALESCE(SUM(pi.balance_due), 0) as total_balance
        FROM suppliers s
        LEFT JOIN purchase_invoices pi ON s.id = pi.supplier_id 
            AND pi.company_id = p_company_id
            AND pi.status = 'posted'
            AND pi.balance_due > 0
            AND pi.invoice_date <= p_as_of_date
        WHERE s.company_id = p_company_id
          AND s.status = 'active'
        GROUP BY s.id, s.code, s.name_ar
        HAVING COALESCE(SUM(pi.balance_due), 0) > 0
        ORDER BY total_balance DESC;
    END IF;
END;
$$;


--
-- Name: get_all_account_balances_fc(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_all_account_balances_fc(p_company_id uuid) RETURNS TABLE(account_id uuid, total_debit numeric, total_credit numeric, balance numeric, balance_base numeric, currency text, transaction_count bigint, last_activity date)
    LANGUAGE sql STABLE SECURITY DEFINER
    AS $$
WITH
-- Step 1: Get account currencies from chart_of_accounts
account_currencies_raw AS (
    SELECT
        coa.id AS account_id,
        coa.currency AS db_currency
    FROM chart_of_accounts coa
    WHERE coa.company_id = p_company_id
      AND coa.is_group = false
),
-- Step 2: Detect actual currency from journal lines (for NULL db_currency)
line_currencies AS (
    SELECT DISTINCT ON (jel.account_id)
        jel.account_id,
        jel.currency AS line_currency
    FROM journal_entry_lines jel
    INNER JOIN journal_entries je
        ON je.id = jel.entry_id
       AND je.company_id = p_company_id
       AND je.is_posted = true
       AND je.status = 'posted'
    WHERE jel.currency IS NOT NULL AND jel.currency != ''
    GROUP BY jel.account_id, jel.currency
    ORDER BY jel.account_id, COUNT(*) DESC
),
-- Step 3: Detect mixed-currency accounts
-- An account is "mixed" if journal lines have > 1 distinct currency
mixed_currency_accounts AS (
    SELECT jel.account_id,
           COUNT(DISTINCT jel.currency) AS num_currencies
    FROM journal_entry_lines jel
    INNER JOIN journal_entries je
        ON je.id = jel.entry_id
       AND je.company_id = p_company_id
       AND je.is_posted = true
       AND je.status = 'posted'
    WHERE jel.currency IS NOT NULL AND jel.currency != ''
    GROUP BY jel.account_id
    HAVING COUNT(DISTINCT jel.currency) > 1
),
-- Step 4: For mixed-currency accounts, find the BASE currency
-- The base currency = currency of entries with exchange_rate = 1
-- when other entries have exchange_rate > 1
-- (e.g., UAH entries with rate=1 + USD entries with rate=43.89 → base=UAH)
mixed_base_currency AS (
    SELECT DISTINCT ON (jel.account_id)
        jel.account_id,
        jel.currency AS base_currency
    FROM journal_entry_lines jel
    INNER JOIN journal_entries je
        ON je.id = jel.entry_id
       AND je.company_id = p_company_id
       AND je.is_posted = true
       AND je.status = 'posted'
    INNER JOIN mixed_currency_accounts mca ON mca.account_id = jel.account_id
    WHERE jel.currency IS NOT NULL
      AND jel.currency != ''
      AND COALESCE(jel.exchange_rate, 1) = 1
    GROUP BY jel.account_id, jel.currency
    ORDER BY jel.account_id, COUNT(*) DESC
),
-- Step 5: Merge currencies
account_currencies AS (
    SELECT
        acr.account_id,
        CASE
            -- Mixed currencies: use detected base currency
            WHEN mca.account_id IS NOT NULL
            THEN COALESCE(mbc.base_currency,
                         (SELECT default_currency FROM companies WHERE id = p_company_id),
                         'USD')
            -- Single currency: use DB or line currency
            ELSE COALESCE(
                NULLIF(acr.db_currency, ''),
                lc.line_currency,
                (SELECT default_currency FROM companies WHERE id = p_company_id),
                'USD'
            )
        END AS account_currency,
        (mca.account_id IS NOT NULL) AS is_mixed_currency
    FROM account_currencies_raw acr
    LEFT JOIN line_currencies lc ON lc.account_id = acr.account_id
    LEFT JOIN mixed_currency_accounts mca ON mca.account_id = acr.account_id
    LEFT JOIN mixed_base_currency mbc ON mbc.account_id = acr.account_id
),
-- Step 6: Calculate balances
posted_lines AS (
    SELECT
        jel.account_id,
        CASE
            WHEN jel.debit_fc IS NOT NULL AND jel.debit_fc > 0 THEN jel.debit_fc
            WHEN COALESCE(jel.exchange_rate, 1) > 1 THEN jel.debit / jel.exchange_rate
            ELSE jel.debit
        END AS fc_debit,
        CASE
            WHEN jel.credit_fc IS NOT NULL AND jel.credit_fc > 0 THEN jel.credit_fc
            WHEN COALESCE(jel.exchange_rate, 1) > 1 THEN jel.credit / jel.exchange_rate
            ELSE jel.credit
        END AS fc_credit,
        jel.debit AS base_debit,
        jel.credit AS base_credit,
        je.entry_date
    FROM journal_entry_lines jel
    INNER JOIN journal_entries je
        ON je.id = jel.entry_id
       AND je.company_id = p_company_id
       AND je.is_posted = true
       AND je.status = 'posted'
)
SELECT
    ac.account_id::UUID,
    COALESCE(SUM(pl.fc_debit), 0)::NUMERIC AS total_debit,
    COALESCE(SUM(pl.fc_credit), 0)::NUMERIC AS total_credit,
    -- For mixed-currency accounts: use balance_base (consistent currency)
    -- For single-currency accounts: use FC balance (native currency)
    CASE
        WHEN ac.is_mixed_currency THEN
            (COALESCE(SUM(pl.base_debit), 0) - COALESCE(SUM(pl.base_credit), 0))::NUMERIC
        ELSE
            (COALESCE(SUM(pl.fc_debit), 0) - COALESCE(SUM(pl.fc_credit), 0))::NUMERIC
    END AS balance,
    (COALESCE(SUM(pl.base_debit), 0) - COALESCE(SUM(pl.base_credit), 0))::NUMERIC AS balance_base,
    ac.account_currency::TEXT AS currency,
    COUNT(pl.fc_debit)::BIGINT AS transaction_count,
    MAX(pl.entry_date)::DATE AS last_activity
FROM account_currencies ac
LEFT JOIN posted_lines pl ON pl.account_id = ac.account_id
GROUP BY ac.account_id, ac.account_currency, ac.is_mixed_currency;
$$;


--
-- Name: get_all_import_entity_definitions(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_all_import_entity_definitions() RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_definitions JSONB;
BEGIN
    SELECT jsonb_agg(
        jsonb_build_object(
            'entity_type', entity_type,
            'target_table', target_table,
            'display_name_ar', display_name_ar,
            'display_name_en', display_name_en,
            'icon', icon,
            'fields', fields,
            'required_fields', required_fields,
            'unique_fields', unique_fields,
            'lookup_fields', lookup_fields
        ) ORDER BY display_order
    ) INTO v_definitions
    FROM import_entity_definitions
    WHERE is_active = true;
    
    RETURN COALESCE(v_definitions, '[]'::JSONB);
END;
$$;


--
-- Name: get_balance_sheet(uuid, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_balance_sheet(p_company_id uuid, p_as_of_date date DEFAULT CURRENT_DATE) RETURNS TABLE(category character varying, category_ar character varying, account_id uuid, account_code character varying, account_name_ar character varying, account_name_en character varying, balance numeric, is_subtotal boolean)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    WITH balance_data AS (
        SELECT 
            coa.id as account_id,
            coa.account_code,
            coa.name_ar as account_name_ar,
            coa.name_en as account_name_en,
            at.classification,
            at.normal_balance,
            coa.opening_balance,
            COALESCE(SUM(jel.debit), 0) as total_debit,
            COALESCE(SUM(jel.credit), 0) as total_credit
        FROM chart_of_accounts coa
        JOIN account_types at ON coa.account_type_id = at.id
        LEFT JOIN journal_entry_lines jel ON coa.id = jel.account_id
        LEFT JOIN journal_entries je ON jel.entry_id = je.id 
            AND je.is_posted = true
            AND je.entry_date <= p_as_of_date
        WHERE coa.company_id = p_company_id
          AND coa.is_active = true
          AND coa.is_detail = true
          AND at.classification IN ('assets', 'liabilities', 'equity')
        GROUP BY coa.id, coa.account_code, coa.name_ar, coa.name_en, at.classification, at.normal_balance, coa.opening_balance
    ),
    calculated_balances AS (
        SELECT 
            bd.*,
            CASE 
                WHEN bd.normal_balance = 'debit' THEN 
                    COALESCE(bd.opening_balance, 0) + bd.total_debit - bd.total_credit
                ELSE 
                    COALESCE(bd.opening_balance, 0) + bd.total_credit - bd.total_debit
            END as balance
        FROM balance_data bd
    )
    -- الأصول
    SELECT 
        'assets'::VARCHAR(50) as category,
        'الأصول'::VARCHAR(100) as category_ar,
        cb.account_id,
        cb.account_code,
        cb.account_name_ar,
        cb.account_name_en,
        cb.balance,
        false as is_subtotal
    FROM calculated_balances cb
    WHERE cb.classification = 'assets' AND cb.balance != 0
    
    UNION ALL
    
    -- إجمالي الأصول
    SELECT 
        'assets_total'::VARCHAR(50),
        'إجمالي الأصول'::VARCHAR(100),
        NULL::UUID,
        ''::VARCHAR(50),
        'إجمالي الأصول'::VARCHAR(200),
        'Total Assets'::VARCHAR(200),
        COALESCE(SUM(balance), 0),
        true
    FROM calculated_balances
    WHERE classification = 'assets'
    
    UNION ALL
    
    -- الخصوم
    SELECT 
        'liabilities'::VARCHAR(50),
        'الخصوم'::VARCHAR(100),
        cb.account_id,
        cb.account_code,
        cb.account_name_ar,
        cb.account_name_en,
        cb.balance,
        false
    FROM calculated_balances cb
    WHERE cb.classification = 'liabilities' AND cb.balance != 0
    
    UNION ALL
    
    -- إجمالي الخصوم
    SELECT 
        'liabilities_total'::VARCHAR(50),
        'إجمالي الخصوم'::VARCHAR(100),
        NULL::UUID,
        ''::VARCHAR(50),
        'إجمالي الخصوم'::VARCHAR(200),
        'Total Liabilities'::VARCHAR(200),
        COALESCE(SUM(balance), 0),
        true
    FROM calculated_balances
    WHERE classification = 'liabilities'
    
    UNION ALL
    
    -- حقوق الملكية
    SELECT 
        'equity'::VARCHAR(50),
        'حقوق الملكية'::VARCHAR(100),
        cb.account_id,
        cb.account_code,
        cb.account_name_ar,
        cb.account_name_en,
        cb.balance,
        false
    FROM calculated_balances cb
    WHERE cb.classification = 'equity' AND cb.balance != 0
    
    UNION ALL
    
    -- إجمالي حقوق الملكية
    SELECT 
        'equity_total'::VARCHAR(50),
        'إجمالي حقوق الملكية'::VARCHAR(100),
        NULL::UUID,
        ''::VARCHAR(50),
        'إجمالي حقوق الملكية'::VARCHAR(200),
        'Total Equity'::VARCHAR(200),
        COALESCE(SUM(balance), 0),
        true
    FROM calculated_balances
    WHERE classification = 'equity'
    
    UNION ALL
    
    -- إجمالي الخصوم وحقوق الملكية
    SELECT 
        'liabilities_equity_total'::VARCHAR(50),
        'إجمالي الخصوم وحقوق الملكية'::VARCHAR(100),
        NULL::UUID,
        ''::VARCHAR(50),
        'إجمالي الخصوم وحقوق الملكية'::VARCHAR(200),
        'Total Liabilities & Equity'::VARCHAR(200),
        COALESCE(SUM(balance), 0),
        true
    FROM calculated_balances
    WHERE classification IN ('liabilities', 'equity')
    
    ORDER BY 
        CASE category 
            WHEN 'assets' THEN 1 
            WHEN 'assets_total' THEN 2
            WHEN 'liabilities' THEN 3 
            WHEN 'liabilities_total' THEN 4
            WHEN 'equity' THEN 5
            WHEN 'equity_total' THEN 6
            WHEN 'liabilities_equity_total' THEN 7
        END,
        account_code;
END;
$$;


--
-- Name: get_company_accounting_settings(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_company_accounting_settings(p_company_id uuid) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
BEGIN
    RETURN COALESCE(
        (SELECT accounting_settings FROM companies WHERE id = p_company_id),
        '{}'::jsonb
    );
END;
$$;


--
-- Name: get_current_tenant(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_current_tenant() RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_tenant_id UUID;
    v_result JSONB;
BEGIN
    v_tenant_id := get_current_tenant_id();
    
    IF v_tenant_id IS NULL THEN
        RETURN NULL;
    END IF;
    
    SELECT jsonb_build_object(
        'id', t.id,
        'code', t.code,
        'name', t.name,
        'status', t.status,
        'default_language', t.default_language,
        'settings', t.settings
    ) INTO v_result
    FROM tenants t
    WHERE t.id = v_tenant_id;
    
    RETURN v_result;
END;
$$;


--
-- Name: get_current_tenant_id(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_current_tenant_id() RETURNS uuid
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_tenant_id UUID;
    v_user_id UUID;
BEGIN
    -- المحاولة 1: من JWT metadata مباشرة
    v_tenant_id := NULLIF(
        COALESCE(
            auth.jwt() -> 'user_metadata' ->> 'tenant_id',
            auth.jwt() -> 'app_metadata' ->> 'tenant_id'
        ),
        ''
    )::UUID;
    
    IF v_tenant_id IS NOT NULL THEN
        RETURN v_tenant_id;
    END IF;
    
    -- المحاولة 2: من user_profiles
    v_user_id := auth.uid();
    IF v_user_id IS NOT NULL THEN
        SELECT tenant_id INTO v_tenant_id
        FROM user_profiles
        WHERE id = v_user_id
        LIMIT 1;
        
        IF v_tenant_id IS NOT NULL THEN
            RETURN v_tenant_id;
        END IF;
    END IF;
    
    -- المحاولة 3: من companies عبر user_profiles
    IF v_user_id IS NOT NULL THEN
        SELECT c.tenant_id INTO v_tenant_id
        FROM companies c
        JOIN user_profiles up ON up.company_id = c.id
        WHERE up.id = v_user_id
        LIMIT 1;
    END IF;
    
    RETURN v_tenant_id;
EXCEPTION
    WHEN OTHERS THEN
        RETURN NULL;
END;
$$;


--
-- Name: get_dashboard_attention_items(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_dashboard_attention_items(p_company_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_result jsonb;
BEGIN
  SELECT COALESCE(jsonb_agg(item), '[]'::jsonb) INTO v_result
  FROM (
      SELECT jsonb_build_object(
        'id', 'unposted_' || id,
        'title', 'قيد لم يرحل: ' || reference_number,
        'description', 'أنشئ بتاريخ ' || to_char(created_at, 'YYYY/MM/DD'),
        'type', 'warning',
        'badge', 'مراجعة',
        'action', '/accounting/journal-entries/' || id
      ) as item
      FROM journal_entries
      WHERE company_id = p_company_id AND is_posted = false
      ORDER BY created_at DESC
      LIMIT 4
  ) sub;
  
  RETURN v_result;
END;
$$;


--
-- Name: get_dashboard_cash_flow(uuid, text, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_dashboard_cash_flow(p_company_id uuid, p_base_currency text, p_days integer DEFAULT 30) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_result jsonb;
BEGIN
  WITH dates AS (
    SELECT generate_series(CURRENT_DATE - (p_days - 1) * INTERVAL '1 day', CURRENT_DATE, '1 day'::interval)::date as d
  ),
  daily_flow AS (
    SELECT 
      je.entry_date,
      SUM(CASE WHEN jel.debit > 0 THEN jel.debit ELSE 0 END) as inflow,
      SUM(CASE WHEN jel.credit > 0 THEN jel.credit ELSE 0 END) as outflow
    FROM journal_entries je
    JOIN journal_entry_lines jel ON jel.entry_id = je.id
    JOIN chart_of_accounts a ON a.id = jel.account_id AND a.tenant_id = je.tenant_id
    WHERE je.company_id = p_company_id 
      AND je.is_posted = true 
      AND je.entry_date >= CURRENT_DATE - (p_days - 1) * INTERVAL '1 day'
      AND a.account_code LIKE '11%' -- cash and banks
    GROUP BY je.entry_date
  )
  SELECT COALESCE(jsonb_agg(
    jsonb_build_object(
      'date', to_char(d.d, 'YYYY-MM-DD"T"HH24:MI:SS"Z"'),
      'income', COALESCE(df.inflow, 0),
      'expense', COALESCE(df.outflow, 0)
    ) ORDER BY d.d
  ), '[]'::jsonb)
  INTO v_result
  FROM dates d
  LEFT JOIN daily_flow df ON df.entry_date = d.d;

  RETURN v_result;
END;
$$;


--
-- Name: get_dashboard_currency_exposure(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_dashboard_currency_exposure(p_company_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_result jsonb;
  v_base_currency text;
BEGIN
  -- Get base currency from accounting settings
  SELECT base_currency INTO v_base_currency
  FROM company_accounting_settings
  WHERE company_id = p_company_id;

  WITH balances AS (
    SELECT 
      COALESCE(jel.currency, a.currency, v_base_currency) as currency,
      SUM(jel.debit - jel.credit) as net_balance
    FROM journal_entry_lines jel
    JOIN journal_entries je ON je.id = jel.entry_id
    JOIN chart_of_accounts a ON a.id = jel.account_id AND a.tenant_id = je.tenant_id
    WHERE je.company_id = p_company_id 
      AND je.is_posted = true
      AND (a.account_code LIKE '111%' OR a.account_code LIKE '112%')
    GROUP BY COALESCE(jel.currency, a.currency, v_base_currency)
    HAVING SUM(jel.debit - jel.credit) > 0
  ),
  total AS (
    SELECT SUM(net_balance) as tot FROM balances
  )
  SELECT COALESCE(jsonb_agg(
    jsonb_build_object(
      'currency', b.currency,
      'valueBase', b.net_balance,
      'pct', ROUND((b.net_balance / NULLIF(t.tot, 0) * 100)::numeric, 1)
    ) ORDER BY b.net_balance DESC
  ), '[]'::jsonb)
  INTO v_result
  FROM balances b
  CROSS JOIN total t;

  RETURN v_result;
END;
$$;


--
-- Name: get_dashboard_kpis(uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_dashboard_kpis(p_company_id uuid, p_base_currency text DEFAULT 'USD'::text) RETURNS jsonb
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_result JSONB;
  v_live_inventory_val NUMERIC := 0;
BEGIN
    -- Query the physical live inventory safely honoring RLS and Live Deductions automatically
    SELECT COALESCE(SUM(s.quantity_on_hand * COALESCE(NULLIF(s.average_cost, 0), m.purchase_price)), 0)
    INTO v_live_inventory_val
    FROM inventory_stock s
    JOIN fabric_materials m ON s.material_id = m.id
    WHERE s.company_id = p_company_id;

    WITH categories(category, label) AS (
        VALUES 
            ('cash', 'النقد والبنوك'), 
            ('receivables', 'الذمم المدينة'), 
            ('payables', 'الذمم الدائنة'), 
            ('inventory', 'قيمة المخزون')
    ),
    calendar AS (
        SELECT 
            dt::DATE as dt, 
            cat.category 
        FROM generate_series(CURRENT_DATE - INTERVAL '6 days', CURRENT_DATE, '1 day'::interval) dt
        CROSS JOIN categories cat
    ),
    category_daily_movements AS (
        SELECT 
            CASE
                WHEN a.account_code LIKE '111%' OR a.account_code LIKE '112%' THEN 'cash'
                WHEN a.account_code LIKE '113%' THEN 'receivables'
                WHEN a.account_code LIKE '211%' OR a.account_code LIKE '21%' THEN 'payables'
                WHEN a.account_code LIKE '114%' THEN 'inventory'
            END AS category,
            je.entry_date::DATE as entry_date,
            SUM(
                CASE 
                    WHEN a.account_code LIKE '211%' OR a.account_code LIKE '21%' THEN jel.credit - jel.debit
                    ELSE jel.debit - jel.credit
                END
            ) AS net_movement
        FROM journal_entry_lines jel
        JOIN journal_entries je ON je.id = jel.entry_id
        JOIN chart_of_accounts a ON a.id = jel.account_id
        WHERE je.company_id = p_company_id
          AND je.is_posted = true
          AND (a.account_code LIKE '111%' OR a.account_code LIKE '112%' OR a.account_code LIKE '113%' OR a.account_code LIKE '21%' OR a.account_code LIKE '114%')
        GROUP BY 1, 2
    ),
    sparkline_data AS (
        SELECT 
            c.category,
            c.dt,
            COALESCE((
                SELECT SUM(net_movement) 
                FROM category_daily_movements m 
                WHERE m.category = c.category AND m.entry_date <= c.dt
            ), 0) AS balance
        FROM calendar c
    ),
    sparklines_agg AS (
        SELECT 
            category,
            jsonb_agg(balance ORDER BY dt ASC) AS sparkline,
            MAX(CASE WHEN dt = CURRENT_DATE THEN balance ELSE 0 END) AS current_balance,
            MAX(CASE WHEN dt = CURRENT_DATE - INTERVAL '6 days' THEN balance ELSE 0 END) AS past_balance
        FROM sparkline_data
        GROUP BY category
    ),
    currency_balances AS (
        SELECT 
            CASE
                WHEN a.account_code LIKE '111%' OR a.account_code LIKE '112%' THEN 'cash'
                WHEN a.account_code LIKE '113%' THEN 'receivables'
                WHEN a.account_code LIKE '211%' OR a.account_code LIKE '21%' THEN 'payables'
                WHEN a.account_code LIKE '114%' THEN 'inventory'
            END AS category,
            COALESCE(a.currency, p_base_currency) AS currency_code,
            SUM(
                CASE 
                    WHEN a.account_code LIKE '211%' OR a.account_code LIKE '21%' THEN jel.credit - jel.debit
                    ELSE jel.debit - jel.credit
                END
            ) AS balance
        FROM journal_entry_lines jel
        JOIN journal_entries je ON je.id = jel.entry_id
        JOIN chart_of_accounts a ON a.id = jel.account_id
        WHERE je.company_id = p_company_id
          AND je.is_posted = true
          AND je.entry_date <= CURRENT_DATE
          AND (a.account_code LIKE '111%' OR a.account_code LIKE '112%' OR a.account_code LIKE '113%' OR a.account_code LIKE '21%' OR a.account_code LIKE '114%')
        GROUP BY 1, 2
    ),
    category_totals AS (
        SELECT category, SUM(balance) as total_balance
        FROM currency_balances
        GROUP BY category
    ),
    breakdown_agg AS (
        SELECT 
            cb.category,
            jsonb_agg(
                jsonb_build_object(
                    'key', cb.currency_code,
                    'label', cb.currency_code,
                    'pct', CASE WHEN ct.total_balance > 0 THEN ROUND((cb.balance / ct.total_balance * 100)::numeric, 1) ELSE 0 END
                ) ORDER BY cb.balance DESC
            ) AS breakdown
        FROM currency_balances cb
        JOIN category_totals ct ON cb.category = ct.category
        WHERE cb.balance > 0
        GROUP BY cb.category
    ),
    final_output AS (
        SELECT 
            s.category,
            jsonb_build_object(
                'id', s.category,
                'label', c.label,
                -- Override Inventory strictly with live physical value mapping
                'value', CASE WHEN s.category = 'inventory' THEN v_live_inventory_val ELSE COALESCE(s.current_balance, 0) END,
                'currency', p_base_currency,
                'deltaPct7d', 
                    CASE 
                        WHEN COALESCE(s.past_balance, 0) = 0 THEN 0
                        ELSE ROUND((( (CASE WHEN s.category = 'inventory' THEN v_live_inventory_val ELSE COALESCE(s.current_balance, 0) END) - s.past_balance) / NULLIF(ABS(s.past_balance), 0) * 100)::numeric, 1)
                    END,
                'sparkline', COALESCE(s.sparkline, '[]'::jsonb),
                'breakdown', COALESCE(b.breakdown, '[]'::jsonb)
            ) AS kpi_json
        FROM sparklines_agg s
        JOIN categories c ON c.category = s.category
        LEFT JOIN breakdown_agg b ON s.category = b.category
        ORDER BY 
            CASE s.category 
                WHEN 'cash' THEN 1 
                WHEN 'receivables' THEN 2 
                WHEN 'payables' THEN 3 
                WHEN 'inventory' THEN 4 
            END
    )
    SELECT jsonb_agg(kpi_json) INTO v_result FROM final_output;
    
    RETURN COALESCE(v_result, '[]'::jsonb);
END;
$$;


--
-- Name: get_dashboard_net_position(uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_dashboard_net_position(p_company_id uuid, p_base_currency text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_result jsonb;
BEGIN
  -- We calculate Assets (1) and Liabilities (2) for the last 7 days cumulatively
  WITH dates AS (
    SELECT generate_series(CURRENT_DATE - INTERVAL '6 days', CURRENT_DATE, '1 day'::interval)::date as d
  ),
  daily_movements AS (
    SELECT 
      d.d as activity_date,
      a.account_code,
      jel.debit - jel.credit as net_amount_base
    FROM dates d
    LEFT JOIN journal_entries je ON je.company_id = p_company_id AND je.is_posted = true AND je.entry_date <= d.d
    LEFT JOIN journal_entry_lines jel ON jel.entry_id = je.id
    LEFT JOIN chart_of_accounts a ON a.id = jel.account_id AND a.tenant_id = je.tenant_id
    WHERE a.account_code LIKE '1%' OR a.account_code LIKE '2%'
  ),
  daily_totals AS (
    SELECT 
      activity_date,
      SUM(CASE WHEN account_code LIKE '1%' THEN net_amount_base ELSE 0 END) as total_assets,
      SUM(CASE WHEN account_code LIKE '2%' THEN -net_amount_base ELSE 0 END) as total_liabilities
    FROM daily_movements
    GROUP BY activity_date
  ),
  net_positions AS (
    SELECT 
      activity_date,
      COALESCE(total_assets - total_liabilities, 0) as net_position
    FROM daily_totals
    ORDER BY activity_date
  )
  SELECT jsonb_build_object(
    'valueBase', COALESCE((SELECT net_position FROM net_positions WHERE activity_date = CURRENT_DATE), 0),
    'baseCurrency', p_base_currency,
    'deltaPct7d', CASE 
      WHEN (SELECT net_position FROM net_positions WHERE activity_date = CURRENT_DATE - INTERVAL '6 days') = 0 THEN 0
      ELSE ROUND((((SELECT net_position FROM net_positions WHERE activity_date = CURRENT_DATE) - (SELECT net_position FROM net_positions WHERE activity_date = CURRENT_DATE - INTERVAL '6 days')) / ABS(NULLIF((SELECT net_position FROM net_positions WHERE activity_date = CURRENT_DATE - INTERVAL '6 days'), 0)) * 100)::numeric, 1)
    END,
    'deltaAbs7d', COALESCE((SELECT net_position FROM net_positions WHERE activity_date = CURRENT_DATE), 0) - COALESCE((SELECT net_position FROM net_positions WHERE activity_date = CURRENT_DATE - INTERVAL '6 days'), 0),
    'sparkline', COALESCE((SELECT jsonb_agg(net_position ORDER BY activity_date) FROM net_positions), '[]'::jsonb),
    'todayMovement', COALESCE((SELECT net_position FROM net_positions WHERE activity_date = CURRENT_DATE), 0) - COALESCE((SELECT net_position FROM net_positions WHERE activity_date = CURRENT_DATE - INTERVAL '1 day'), 0),
    'todayTxCount', COALESCE((SELECT COUNT(*) FROM journal_entries WHERE company_id = p_company_id AND is_posted = true AND entry_date = CURRENT_DATE), 0)
  ) INTO v_result;

  RETURN v_result;
END;
$$;


--
-- Name: get_dashboard_recent_activity(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_dashboard_recent_activity(p_company_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_result jsonb;
BEGIN
  SELECT COALESCE(jsonb_agg(
    jsonb_build_object(
      'id', je.id,
      'title', 'قيد محاسبي: ' || je.reference_number,
      'user', COALESCE(u.full_name, 'النظام'),
      'timestamp', to_char(je.created_at, 'YYYY-MM-DD"T"HH24:MI:SS"Z"'),
      'type', 'journal',
      'amount', je.total_debit
    ) ORDER BY je.created_at DESC
  ), '[]'::jsonb)
  INTO v_result
  FROM journal_entries je
  LEFT JOIN user_profiles u ON u.id = je.created_by
  WHERE je.company_id = p_company_id
  LIMIT 6;

  RETURN v_result;
END;
$$;


--
-- Name: get_dashboard_top_customers(uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_dashboard_top_customers(p_company_id uuid, p_base_currency text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_result jsonb;
BEGIN
  WITH cust_balances AS (
    SELECT 
      c.id,
      c.name_ar,
      SUM(jel.debit - jel.credit) as outstanding
    FROM customers c
    JOIN journal_entry_lines jel ON jel.account_id = c.receivable_account_id
    JOIN journal_entries je ON je.id = jel.entry_id
    WHERE je.company_id = p_company_id 
      AND je.is_posted = true
      AND je.status = 'posted'
    GROUP BY c.id, c.name_ar
    HAVING SUM(jel.debit - jel.credit) > 0
  )
  SELECT COALESCE(jsonb_agg(
    jsonb_build_object(
      'id', id,
      'name', name_ar,
      'outstanding', outstanding,
      'currency', p_base_currency,
      'daysOverdue', 0
    ) ORDER BY outstanding DESC
  ), '[]'::jsonb)
  INTO v_result
  FROM (
    SELECT * FROM cust_balances ORDER BY outstanding DESC LIMIT 5
  ) sub;

  RETURN v_result;
END;
$$;


--
-- Name: get_ecommerce_products(uuid, text, text, boolean, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_ecommerce_products(p_store_id uuid, p_category_slug text DEFAULT NULL::text, p_search text DEFAULT NULL::text, p_featured_only boolean DEFAULT false, p_limit integer DEFAULT 20, p_offset integer DEFAULT 0) RETURNS TABLE(id uuid, material_id uuid, marketing_title jsonb, marketing_description jsonb, short_description jsonb, gallery_images text[], seo_slug text, tags text[], is_featured boolean, is_new boolean, is_bestseller boolean, is_on_sale boolean, sale_price numeric, sale_unit text, min_order_quantity numeric, view_count integer, order_count integer, published_at timestamp with time zone, material_code text, material_name_ar text, material_name_en text, unit_price numeric, material_image text, effective_price numeric, category_slugs text[])
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        ep.id,
        ep.material_id,
        ep.marketing_title,
        ep.marketing_description,
        ep.short_description,
        ep.gallery_images,
        ep.seo_slug,
        ep.tags,
        ep.is_featured,
        ep.is_new,
        ep.is_bestseller,
        ep.is_on_sale,
        ep.sale_price,
        ep.sale_unit,
        ep.min_order_quantity,
        ep.view_count,
        ep.order_count,
        ep.published_at,
        -- Live from fabric_materials
        fm.code AS material_code,
        fm.name_ar AS material_name_ar,
        fm.name_en AS material_name_en,
        fm.unit_price,
        fm.image_url AS material_image,
        -- Effective price: sale_price if on sale, otherwise unit_price
        COALESCE(
            CASE WHEN ep.is_on_sale AND ep.sale_price IS NOT NULL 
                 AND (ep.sale_start_date IS NULL OR ep.sale_start_date <= now())
                 AND (ep.sale_end_date IS NULL OR ep.sale_end_date >= now())
            THEN ep.sale_price 
            ELSE NULL END,
            fm.unit_price
        ) AS effective_price,
        -- Category slugs
        ARRAY(
            SELECT ec.slug FROM ecommerce_product_categories epc
            JOIN ecommerce_categories ec ON ec.id = epc.category_id
            WHERE epc.product_id = ep.id
        ) AS category_slugs
    FROM ecommerce_products ep
    JOIN fabric_materials fm ON fm.id = ep.material_id
    WHERE ep.store_id = p_store_id
      AND ep.is_published = true
      AND (p_featured_only = false OR ep.is_featured = true)
      AND (p_search IS NULL OR (
          fm.name_ar ILIKE '%' || p_search || '%' OR
          fm.name_en ILIKE '%' || p_search || '%' OR
          fm.code ILIKE '%' || p_search || '%' OR
          ep.marketing_title::text ILIKE '%' || p_search || '%' OR
          p_search = ANY(ep.tags)
      ))
      AND (p_category_slug IS NULL OR EXISTS (
          SELECT 1 FROM ecommerce_product_categories epc
          JOIN ecommerce_categories ec ON ec.id = epc.category_id
          WHERE epc.product_id = ep.id AND ec.slug = p_category_slug
      ))
    ORDER BY ep.display_order ASC, ep.published_at DESC
    LIMIT p_limit OFFSET p_offset;
END;
$$;


--
-- Name: get_employee_commission_report(uuid, date, date, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_employee_commission_report(p_company_id uuid, p_from_date date, p_to_date date, p_employee_id uuid DEFAULT NULL::uuid) RETURNS TABLE(employee_id uuid, employee_name character varying, total_sales numeric, total_commission numeric, total_bonus numeric, net_commission numeric, invoice_count integer, avg_commission_rate numeric, status_summary jsonb)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        ec.employee_id,
        'موظف'::VARCHAR as employee_name, -- يمكن ربطه بجدول الموظفين
        COALESCE(SUM(ec.base_amount), 0)::DECIMAL(15,2) as total_sales,
        COALESCE(SUM(ec.commission_amount), 0)::DECIMAL(15,2) as total_commission,
        COALESCE(SUM(ec.bonus_amount), 0)::DECIMAL(15,2) as total_bonus,
        COALESCE(SUM(ec.net_amount), 0)::DECIMAL(15,2) as net_commission,
        COUNT(DISTINCT ec.source_id)::INT as invoice_count,
        CASE 
            WHEN SUM(ec.base_amount) > 0 
            THEN (SUM(ec.commission_amount) / SUM(ec.base_amount) * 100)::DECIMAL(10,4)
            ELSE 0 
        END as avg_commission_rate,
        jsonb_build_object(
            'calculated', COUNT(*) FILTER (WHERE ec.status = 'calculated'),
            'approved', COUNT(*) FILTER (WHERE ec.status = 'approved'),
            'paid', COUNT(*) FILTER (WHERE ec.status = 'paid'),
            'cancelled', COUNT(*) FILTER (WHERE ec.status = 'cancelled')
        ) as status_summary
    FROM employee_commissions ec
    WHERE ec.company_id = p_company_id
      AND ec.period_start >= p_from_date
      AND ec.period_end <= p_to_date
      AND (p_employee_id IS NULL OR ec.employee_id = p_employee_id)
    GROUP BY ec.employee_id
    ORDER BY net_commission DESC;
END;
$$;


