--
-- Name: get_import_entity_definition(character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_import_entity_definition(p_entity_type character varying) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_definition JSONB;
BEGIN
    SELECT jsonb_build_object(
        'entity_type', entity_type,
        'target_table', target_table,
        'display_name_ar', display_name_ar,
        'display_name_en', display_name_en,
        'icon', icon,
        'fields', fields,
        'required_fields', required_fields,
        'unique_fields', unique_fields,
        'lookup_fields', lookup_fields
    ) INTO v_definition
    FROM import_entity_definitions
    WHERE entity_type = p_entity_type AND is_active = true;
    
    RETURN v_definition;
END;
$$;


--
-- Name: get_income_statement(uuid, date, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_income_statement(p_company_id uuid, p_from_date date, p_to_date date) RETURNS TABLE(category character varying, category_ar character varying, account_id uuid, account_code character varying, account_name_ar character varying, account_name_en character varying, amount numeric, is_subtotal boolean)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    WITH income_data AS (
        SELECT 
            coa.id as account_id,
            coa.account_code,
            coa.name_ar as account_name_ar,
            coa.name_en as account_name_en,
            at.classification,
            at.code as type_code,
            COALESCE(SUM(jel.credit - jel.debit), 0) as net_amount
        FROM chart_of_accounts coa
        JOIN account_types at ON coa.account_type_id = at.id
        LEFT JOIN journal_entry_lines jel ON coa.id = jel.account_id
        LEFT JOIN journal_entries je ON jel.entry_id = je.id 
            AND je.is_posted = true
            AND je.entry_date BETWEEN p_from_date AND p_to_date
        WHERE coa.company_id = p_company_id
          AND coa.is_active = true
          AND coa.is_detail = true
          AND at.classification IN ('income', 'expenses')
        GROUP BY coa.id, coa.account_code, coa.name_ar, coa.name_en, at.classification, at.code
        HAVING COALESCE(SUM(jel.credit - jel.debit), 0) != 0
    )
    -- الإيرادات
    SELECT 
        'revenue'::VARCHAR(50) as category,
        'الإيرادات'::VARCHAR(100) as category_ar,
        id.account_id,
        id.account_code,
        id.account_name_ar,
        id.account_name_en,
        id.net_amount as amount,
        false as is_subtotal
    FROM income_data id
    WHERE id.classification = 'income'
    
    UNION ALL
    
    -- إجمالي الإيرادات
    SELECT 
        'revenue_total'::VARCHAR(50),
        'إجمالي الإيرادات'::VARCHAR(100),
        NULL::UUID,
        ''::VARCHAR(50),
        'إجمالي الإيرادات'::VARCHAR(200),
        'Total Revenue'::VARCHAR(200),
        COALESCE(SUM(net_amount), 0),
        true
    FROM income_data
    WHERE classification = 'income'
    
    UNION ALL
    
    -- المصروفات
    SELECT 
        'expenses'::VARCHAR(50),
        'المصروفات'::VARCHAR(100),
        id.account_id,
        id.account_code,
        id.account_name_ar,
        id.account_name_en,
        ABS(id.net_amount),
        false
    FROM income_data id
    WHERE id.classification = 'expenses'
    
    UNION ALL
    
    -- إجمالي المصروفات
    SELECT 
        'expenses_total'::VARCHAR(50),
        'إجمالي المصروفات'::VARCHAR(100),
        NULL::UUID,
        ''::VARCHAR(50),
        'إجمالي المصروفات'::VARCHAR(200),
        'Total Expenses'::VARCHAR(200),
        COALESCE(ABS(SUM(net_amount)), 0),
        true
    FROM income_data
    WHERE classification = 'expenses'
    
    UNION ALL
    
    -- صافي الربح/الخسارة
    SELECT 
        'net_income'::VARCHAR(50),
        'صافي الربح/الخسارة'::VARCHAR(100),
        NULL::UUID,
        ''::VARCHAR(50),
        CASE 
            WHEN COALESCE(SUM(CASE WHEN classification = 'income' THEN net_amount ELSE -net_amount END), 0) >= 0 
            THEN 'صافي الربح'::VARCHAR(200)
            ELSE 'صافي الخسارة'::VARCHAR(200)
        END,
        CASE 
            WHEN COALESCE(SUM(CASE WHEN classification = 'income' THEN net_amount ELSE -net_amount END), 0) >= 0 
            THEN 'Net Profit'::VARCHAR(200)
            ELSE 'Net Loss'::VARCHAR(200)
        END,
        COALESCE(SUM(CASE WHEN classification = 'income' THEN net_amount ELSE -net_amount END), 0),
        true
    FROM income_data
    
    ORDER BY 
        CASE category 
            WHEN 'revenue' THEN 1 
            WHEN 'revenue_total' THEN 2
            WHEN 'expenses' THEN 3 
            WHEN 'expenses_total' THEN 4
            WHEN 'net_income' THEN 5
        END,
        account_code;
END;
$$;


--
-- Name: get_material_inventory_stats_batch(uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_material_inventory_stats_batch(material_ids uuid[]) RETURNS TABLE(material_id uuid, rolls_count bigint, rolls_total_length numeric, reserved_length numeric, available_length numeric)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        fr.material_id,
        COUNT(fr.id)::BIGINT as rolls_count,
        COALESCE(SUM(fr.current_length), 0)::DECIMAL(15,3) as rolls_total_length,
        COALESCE(SUM(fr.reserved_length), 0)::DECIMAL(15,3) as reserved_length,
        COALESCE(SUM(fr.available_length), 0)::DECIMAL(15,3) as available_length
    FROM 
        fabric_rolls fr
    WHERE 
        fr.material_id = ANY(material_ids)
        AND fr.status != 'consumed'
        AND fr.current_length > 0
    GROUP BY 
        fr.material_id;
END;
$$;


--
-- Name: get_mfa_status(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_mfa_status(p_user_id uuid DEFAULT auth.uid()) RETURNS TABLE(service_enabled boolean, is_required boolean, user_enabled boolean, can_enable boolean, preferred_method text)
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        COALESCE(ss.is_enabled, false),
        is_mfa_required(p_user_id),
        COALESCE(us.is_enabled, false),
        COALESCE(ss.is_enabled, false),
        COALESCE(us.preferred_method, 'totp')::TEXT
    FROM mfa_system_settings ss
    LEFT JOIN mfa_user_settings us ON us.user_id = p_user_id
    LIMIT 1;
EXCEPTION
    WHEN OTHERS THEN
        -- Return default values if error
        RETURN QUERY SELECT false, false, false, false, 'totp'::TEXT;
END;
$$;


--
-- Name: get_party_balances_bulk(uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_party_balances_bulk(p_company_id uuid, p_party_type text) RETURNS TABLE(party_id uuid, total_debit numeric, total_credit numeric, balance numeric, transaction_count bigint, last_transaction_date date)
    LANGUAGE sql STABLE SECURITY DEFINER
    AS $$
WITH party_accounts AS (
    SELECT id AS party_id, payable_account_id AS account_id
    FROM suppliers
    WHERE company_id = p_company_id
      AND p_party_type = 'supplier'
      AND payable_account_id IS NOT NULL
    UNION ALL
    SELECT id AS party_id, receivable_account_id AS account_id
    FROM customers
    WHERE company_id = p_company_id
      AND p_party_type = 'customer'
      AND receivable_account_id IS NOT NULL
),
posted_lines AS (
    SELECT jel.account_id,
           CASE
               WHEN jel.debit_fc IS NOT NULL AND (jel.debit_fc > 0 OR jel.debit = 0) THEN jel.debit_fc
               WHEN COALESCE(jel.exchange_rate, 1) > 1 THEN jel.debit / jel.exchange_rate
               ELSE jel.debit
           END AS debit,
           CASE
               WHEN jel.credit_fc IS NOT NULL AND (jel.credit_fc > 0 OR jel.credit = 0) THEN jel.credit_fc
               WHEN COALESCE(jel.exchange_rate, 1) > 1 THEN jel.credit / jel.exchange_rate
               ELSE jel.credit
           END AS credit,
           je.entry_date
    FROM journal_entry_lines jel
    INNER JOIN journal_entries je
        ON je.id       = jel.entry_id
       AND je.company_id = p_company_id
       AND je.is_posted  = true
       AND je.status     = 'posted'
)
SELECT
    pa.party_id::UUID,
    COALESCE(SUM(pl.debit),  0)::NUMERIC AS total_debit,
    COALESCE(SUM(pl.credit), 0)::NUMERIC AS total_credit,
    CASE
        WHEN p_party_type = 'supplier'
            THEN (COALESCE(SUM(pl.credit), 0) - COALESCE(SUM(pl.debit), 0))::NUMERIC
        ELSE
            (COALESCE(SUM(pl.debit), 0) - COALESCE(SUM(pl.credit), 0))::NUMERIC
    END AS balance,
    COUNT(pl.debit)::BIGINT      AS transaction_count,
    MAX(pl.entry_date)::DATE     AS last_transaction_date
FROM party_accounts pa
LEFT JOIN posted_lines pl ON pl.account_id = pa.account_id
GROUP BY pa.party_id;
$$;


