--
-- Name: get_schema_info(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_schema_info() RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  result JSON;
BEGIN
  SELECT json_agg(json_build_object(
    'table', t.table_name,
    'columns', (
      SELECT json_agg(json_build_object(
        'name', c.column_name,
        'type', c.data_type,
        'nullable', c.is_nullable
      ) ORDER BY c.ordinal_position)
      FROM information_schema.columns c
      WHERE c.table_schema = 'public' AND c.table_name = t.table_name
    )
  ) ORDER BY t.table_name)
  INTO result
  FROM information_schema.tables t
  WHERE t.table_schema = 'public' 
    AND t.table_type = 'BASE TABLE'
    AND t.table_name NOT LIKE 'pg_%'
    AND t.table_name NOT LIKE '_%;';
  
  RETURN result;
END;
$$;


--
-- Name: get_status_color_class(character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_status_color_class(color character varying) RETURNS character varying
    LANGUAGE plpgsql IMMUTABLE
    AS $$
BEGIN
  RETURN CASE color
    WHEN 'gray' THEN 'bg-gray-100 text-gray-700'
    WHEN 'blue' THEN 'bg-blue-100 text-blue-700'
    WHEN 'green' THEN 'bg-green-100 text-green-700'
    WHEN 'red' THEN 'bg-red-100 text-red-700'
    WHEN 'yellow' THEN 'bg-yellow-100 text-yellow-700'
    WHEN 'orange' THEN 'bg-orange-100 text-orange-700'
    WHEN 'purple' THEN 'bg-purple-100 text-purple-700'
    WHEN 'pink' THEN 'bg-pink-100 text-pink-700'
    WHEN 'indigo' THEN 'bg-indigo-100 text-indigo-700'
    WHEN 'teal' THEN 'bg-teal-100 text-teal-700'
    ELSE 'bg-gray-100 text-gray-700'
  END;
END;
$$;


--
-- Name: get_subscription_status(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_subscription_status(p_tenant_id uuid) RETURNS TABLE(subscription_id uuid, plan_name character varying, status character varying, days_remaining integer, is_expired boolean, is_locked boolean, is_in_grace_period boolean, grace_days_remaining integer, access_level character varying)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_sub RECORD;
    v_days_remaining INT;
    v_grace_days_remaining INT;
    v_access_level VARCHAR;
BEGIN
    SELECT s.*, sp.name_ar as plan_name_ar, sp.name_en as plan_name_en
    INTO v_sub
    FROM subscriptions s
    LEFT JOIN subscription_plans sp ON s.plan_id = sp.id
    WHERE s.tenant_id = p_tenant_id
    AND s.status != 'cancelled'
    ORDER BY s.created_at DESC
    LIMIT 1;
    
    IF NOT FOUND THEN
        RETURN QUERY SELECT 
            NULL::UUID,
            'No Plan'::VARCHAR,
            'none'::VARCHAR,
            0,
            true,
            true,
            false,
            0,
            'locked'::VARCHAR;
        RETURN;
    END IF;
    
    -- حساب الأيام المتبقية
    v_days_remaining := EXTRACT(DAY FROM (v_sub.current_period_end - NOW()));
    
    -- حساب أيام فترة السماح المتبقية
    IF v_sub.current_period_end < NOW() THEN
        v_grace_days_remaining := COALESCE(v_sub.grace_period_days, 7) - 
            EXTRACT(DAY FROM (NOW() - v_sub.current_period_end))::INT;
    ELSE
        v_grace_days_remaining := COALESCE(v_sub.grace_period_days, 7);
    END IF;
    
    -- تحديد مستوى الوصول
    IF v_sub.locked_at IS NOT NULL THEN
        v_access_level := 'locked';
    ELSIF v_sub.current_period_end < NOW() AND v_grace_days_remaining <= 0 THEN
        v_access_level := 'locked';
    ELSIF v_sub.current_period_end < NOW() THEN
        v_access_level := 'read_only';
    ELSIF v_days_remaining <= 3 THEN
        v_access_level := 'warning';
    ELSE
        v_access_level := 'full';
    END IF;
    
    RETURN QUERY SELECT 
        v_sub.id,
        COALESCE(v_sub.plan_name_ar, v_sub.plan_name_en, 'Unknown')::VARCHAR,
        v_sub.status,
        GREATEST(0, v_days_remaining),
        v_sub.current_period_end < NOW(),
        v_sub.locked_at IS NOT NULL OR (v_sub.current_period_end < NOW() AND v_grace_days_remaining <= 0),
        v_sub.current_period_end < NOW() AND v_grace_days_remaining > 0,
        GREATEST(0, v_grace_days_remaining),
        v_access_level;
END;
$$;


--
-- Name: get_target_achievement_report(uuid, integer, integer, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_target_achievement_report(p_company_id uuid, p_period_year integer, p_period_month integer DEFAULT NULL::integer, p_employee_id uuid DEFAULT NULL::uuid) RETURNS TABLE(employee_id uuid, target_type character varying, target_amount numeric, achieved_amount numeric, achievement_percentage numeric, remaining_amount numeric, bonus_earned numeric, status character varying)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        et.employee_id,
        et.target_type,
        et.target_amount,
        et.achieved_amount,
        et.achievement_percentage,
        GREATEST(et.target_amount - et.achieved_amount, 0)::DECIMAL(15,2) as remaining_amount,
        CASE 
            WHEN et.achievement_percentage >= 100 THEN et.bonus_on_achievement
            ELSE 0
        END + 
        CASE 
            WHEN et.achievement_percentage > 100 
            THEN (et.achieved_amount - et.target_amount) * et.bonus_on_exceed / 100
            ELSE 0
        END as bonus_earned,
        et.status
    FROM employee_targets et
    WHERE et.company_id = p_company_id
      AND et.period_year = p_period_year
      AND (p_period_month IS NULL OR et.period_month = p_period_month)
      AND (p_employee_id IS NULL OR et.employee_id = p_employee_id)
    ORDER BY et.employee_id, et.target_type;
END;
$$;


--
-- Name: get_tenant_statistics(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_tenant_statistics(p_tenant_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_tenant_id UUID;
    v_result JSONB;
BEGIN
    v_tenant_id := COALESCE(p_tenant_id, get_current_tenant_id());
    
    SELECT jsonb_build_object(
        'companies', (SELECT COUNT(*) FROM companies WHERE tenant_id = v_tenant_id),
        'users', (SELECT COUNT(*) FROM user_profiles WHERE tenant_id = v_tenant_id),
        'customers', (SELECT COUNT(*) FROM customers WHERE tenant_id = v_tenant_id),
        'suppliers', (SELECT COUNT(*) FROM suppliers WHERE tenant_id = v_tenant_id),
        'products', (SELECT COUNT(*) FROM products WHERE tenant_id = v_tenant_id),
        'journal_entries', (SELECT COUNT(*) FROM journal_entries WHERE tenant_id = v_tenant_id),
        'sales_invoices', (SELECT COUNT(*) FROM sales_invoices WHERE tenant_id = v_tenant_id),
        'documents', (SELECT COUNT(*) FROM documents WHERE tenant_id = v_tenant_id),
        'storage_used', (
            SELECT COALESCE(SUM(file_size), 0)
            FROM documents
            WHERE tenant_id = v_tenant_id
        )
    ) INTO v_result;
    
    RETURN v_result;
END;
$$;


--
-- Name: get_ticker_kpis(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_ticker_kpis(p_company_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE result JSONB;
BEGIN
  SELECT jsonb_build_object(
    'total_revenue', COALESCE((SELECT SUM(total_amount) FROM sales_transactions WHERE company_id = p_company_id), 0),
    'total_expenses', COALESCE((SELECT SUM(total_amount) FROM purchase_transactions WHERE company_id = p_company_id), 0),
    'total_customers', COALESCE((SELECT COUNT(*) FROM customers WHERE company_id = p_company_id), 0),
    'total_suppliers', COALESCE((SELECT COUNT(*) FROM suppliers WHERE company_id = p_company_id), 0),
    'cash_balance', 0, 'pending_invoices', 0
  ) INTO result;
  RETURN COALESCE(result, '{}'::jsonb);
END; $$;


--
-- Name: get_top_customers(uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_top_customers(p_company_id uuid, p_limit integer DEFAULT 10) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE result JSONB;
BEGIN
  SELECT COALESCE(jsonb_agg(row_to_json(t)), '[]'::jsonb) INTO result
  FROM (
    SELECT c.id, c.name, COALESCE(SUM(st.total_amount), 0) as total_sales
    FROM customers c
    LEFT JOIN sales_transactions st ON st.customer_id = c.id AND st.company_id = p_company_id
    WHERE c.company_id = p_company_id
    GROUP BY c.id, c.name
    ORDER BY total_sales DESC
    LIMIT p_limit
  ) t;
  RETURN result;
END; $$;


--
-- Name: get_trial_balance(uuid, date, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_trial_balance(p_company_id uuid, p_from_date date DEFAULT NULL::date, p_to_date date DEFAULT NULL::date) RETURNS TABLE(account_id uuid, account_code character varying, account_name_ar character varying, account_name_en character varying, account_type character varying, parent_code character varying, level integer, is_group boolean, opening_debit numeric, opening_credit numeric, period_debit numeric, period_credit numeric, closing_debit numeric, closing_credit numeric)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_from_date DATE;
    v_to_date DATE;
BEGIN
    -- تحديد التواريخ الافتراضية
    v_from_date := COALESCE(p_from_date, DATE_TRUNC('year', CURRENT_DATE)::DATE);
    v_to_date := COALESCE(p_to_date, CURRENT_DATE);
    
    RETURN QUERY
    WITH account_movements AS (
        -- حركات قبل الفترة (الرصيد الافتتاحي)
        SELECT 
            jel.account_id,
            SUM(CASE WHEN je.entry_date < v_from_date THEN jel.debit ELSE 0 END) as opening_debit,
            SUM(CASE WHEN je.entry_date < v_from_date THEN jel.credit ELSE 0 END) as opening_credit,
            -- حركات الفترة
            SUM(CASE WHEN je.entry_date BETWEEN v_from_date AND v_to_date THEN jel.debit ELSE 0 END) as period_debit,
            SUM(CASE WHEN je.entry_date BETWEEN v_from_date AND v_to_date THEN jel.credit ELSE 0 END) as period_credit
        FROM journal_entry_lines jel
        JOIN journal_entries je ON jel.entry_id = je.id
        WHERE je.company_id = p_company_id
          AND je.is_posted = true
          AND je.entry_date <= v_to_date
        GROUP BY jel.account_id
    ),
    account_balances AS (
        SELECT 
            coa.id as account_id,
            coa.account_code,
            coa.name_ar as account_name_ar,
            coa.name_en as account_name_en,
            at.code as account_type,
            parent.account_code as parent_code,
            coa.level,
            coa.is_group,
            COALESCE(coa.opening_balance, 0) as initial_balance,
            COALESCE(am.opening_debit, 0) as mov_opening_debit,
            COALESCE(am.opening_credit, 0) as mov_opening_credit,
            COALESCE(am.period_debit, 0) as period_debit,
            COALESCE(am.period_credit, 0) as period_credit,
            at.normal_balance
        FROM chart_of_accounts coa
        LEFT JOIN account_types at ON coa.account_type_id = at.id
        LEFT JOIN chart_of_accounts parent ON coa.parent_id = parent.id
        LEFT JOIN account_movements am ON coa.id = am.account_id
        WHERE coa.company_id = p_company_id
          AND coa.is_active = true
    )
    SELECT 
        ab.account_id,
        ab.account_code,
        ab.account_name_ar,
        ab.account_name_en,
        ab.account_type,
        ab.parent_code,
        ab.level,
        ab.is_group,
        -- الرصيد الافتتاحي
        CASE 
            WHEN ab.normal_balance = 'debit' THEN 
                GREATEST(ab.initial_balance + ab.mov_opening_debit - ab.mov_opening_credit, 0)
            ELSE 0::DECIMAL(15,2)
        END as opening_debit,
        CASE 
            WHEN ab.normal_balance = 'credit' THEN 
                GREATEST(ab.initial_balance + ab.mov_opening_credit - ab.mov_opening_debit, 0)
            ELSE 0::DECIMAL(15,2)
        END as opening_credit,
        -- حركات الفترة
        ab.period_debit,
        ab.period_credit,
        -- الرصيد الختامي
        CASE 
            WHEN ab.normal_balance = 'debit' THEN 
                GREATEST(ab.initial_balance + ab.mov_opening_debit - ab.mov_opening_credit + ab.period_debit - ab.period_credit, 0)
            ELSE 0::DECIMAL(15,2)
        END as closing_debit,
        CASE 
            WHEN ab.normal_balance = 'credit' THEN 
                GREATEST(ab.initial_balance + ab.mov_opening_credit - ab.mov_opening_debit + ab.period_credit - ab.period_debit, 0)
            ELSE 0::DECIMAL(15,2)
        END as closing_credit
    FROM account_balances ab
    ORDER BY ab.account_code;
END;
$$;


--
-- Name: get_trial_balance_base(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_trial_balance_base(p_company_id uuid) RETURNS TABLE(total_debit numeric, total_credit numeric, balance_diff numeric, is_balanced boolean, base_currency text, accounts_count bigint, entries_count bigint)
    LANGUAGE sql STABLE SECURITY DEFINER
    AS $$
SELECT
    COALESCE(SUM(jel.debit), 0)::NUMERIC AS total_debit,
    COALESCE(SUM(jel.credit), 0)::NUMERIC AS total_credit,
    ABS(COALESCE(SUM(jel.debit), 0) - COALESCE(SUM(jel.credit), 0))::NUMERIC AS balance_diff,
    (ABS(COALESCE(SUM(jel.debit), 0) - COALESCE(SUM(jel.credit), 0)) < 0.01)::BOOLEAN AS is_balanced,
    COALESCE(c.default_currency, 'USD')::TEXT AS base_currency,
    COUNT(DISTINCT jel.account_id)::BIGINT AS accounts_count,
    COUNT(DISTINCT jel.entry_id)::BIGINT AS entries_count
FROM journal_entry_lines jel
INNER JOIN journal_entries je
    ON je.id = jel.entry_id
   AND je.company_id = p_company_id
   AND je.is_posted = true
   AND je.status = 'posted'
CROSS JOIN (SELECT default_currency FROM companies WHERE id = p_company_id) c
GROUP BY c.default_currency;
$$;


--
-- Name: get_user_accessible_funds(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_user_accessible_funds(p_user_id uuid DEFAULT auth.uid()) RETURNS TABLE(fund_account_id uuid, can_deposit boolean, can_withdraw boolean, can_transfer boolean, is_primary boolean)
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
BEGIN
    -- Platform/Tenant/Company admins see all
    IF is_super_admin(p_user_id) OR is_tenant_admin(p_user_id) OR is_company_admin(p_user_id) THEN
        RETURN QUERY
        SELECT coa.id, true, true, true, false
        FROM chart_of_accounts coa
        WHERE coa.account_type IN ('cash', 'bank')
          AND coa.is_active = true
          AND coa.tenant_id = get_current_tenant_id();
        RETURN;
    END IF;
    
    -- Regular users - assigned funds only
    RETURN QUERY
    SELECT 
        ufp.fund_account_id,
        ufp.can_deposit,
        ufp.can_withdraw,
        ufp.can_transfer,
        ufp.is_primary
    FROM user_fund_permissions ufp
    WHERE ufp.user_id = p_user_id
      AND ufp.can_view = true;
END;
$$;


--
-- Name: get_user_accessible_warehouses(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_user_accessible_warehouses(p_user_id uuid DEFAULT auth.uid()) RETURNS TABLE(warehouse_id uuid, can_receive boolean, can_issue boolean, can_transfer boolean, can_count boolean, is_keeper boolean)
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
BEGIN
    IF is_super_admin(p_user_id) OR is_tenant_admin(p_user_id) OR is_company_admin(p_user_id) THEN
        RETURN QUERY
        SELECT w.id, true, true, true, true, false
        FROM warehouses w
        WHERE w.is_active = true
          AND w.tenant_id = get_current_tenant_id();
        RETURN;
    END IF;
    
    RETURN QUERY
    SELECT 
        uwp.warehouse_id,
        uwp.can_receive,
        uwp.can_issue,
        uwp.can_transfer,
        uwp.can_count,
        uwp.is_keeper
    FROM user_warehouse_permissions uwp
    WHERE uwp.user_id = p_user_id
      AND uwp.can_view = true;
END;
$$;


--
-- Name: get_user_companies(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_user_companies(p_user_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql
    AS $$
DECLARE 
  result JSONB;
  v_tenant_id uuid;
BEGIN
  SELECT tenant_id INTO v_tenant_id 
  FROM public.user_profiles 
  WHERE id = COALESCE(p_user_id, auth.uid());
  
  IF v_tenant_id IS NULL THEN
    RETURN '[]'::jsonb;
  END IF;

  SELECT jsonb_agg(
    jsonb_build_object(
      'id', c.id,
      'name', c.name,
      'name_ar', COALESCE(c.name, c.name_en, 'شركة'),
      'name_en', COALESCE(c.name_en, c.name, 'Company'),
      'tenant_id', c.tenant_id,
      'default_currency', c.default_currency,
      'logo_url', c.logo_url,
      'is_active', true,
      'is_current', (c.id = (
        SELECT company_id FROM public.user_profiles 
        WHERE id = COALESCE(p_user_id, auth.uid())
      )),
      'company_type', 'production',
      'business_type', 'general'
    ) ORDER BY c.created_at
  )
  INTO result 
  FROM public.companies c
  WHERE c.tenant_id = v_tenant_id;
  
  RETURN COALESCE(result, '[]'::jsonb);
END; $$;


--
-- Name: get_user_full_permissions(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_user_full_permissions(p_user_id uuid DEFAULT auth.uid()) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_result JSONB;
    v_roles JSONB;
    v_funds JSONB;
    v_warehouses JSONB;
    v_branches JSONB;
    v_level TEXT;
BEGIN
    -- Get role level
    v_level := get_user_role_level(p_user_id);
    
    -- Get roles
    SELECT jsonb_agg(jsonb_build_object(
        'role_code', r.code,
        'role_name', r.name_ar,
        'level', COALESCE(r.permissions->>'level', 'operations'),
        'permissions', r.permissions
    ))
    INTO v_roles
    FROM user_roles ur
    JOIN roles r ON ur.role_id = r.id
    WHERE ur.user_id = p_user_id
      AND ur.is_active = true;
    
    -- Get funds (only for non-admins)
    IF v_level NOT IN ('platform', 'tenant', 'company') THEN
        SELECT jsonb_agg(jsonb_build_object(
            'fund_id', ufp.fund_account_id,
            'can_deposit', ufp.can_deposit,
            'can_withdraw', ufp.can_withdraw,
            'is_primary', ufp.is_primary
        ))
        INTO v_funds
        FROM user_fund_permissions ufp
        WHERE ufp.user_id = p_user_id AND ufp.can_view = true;
    ELSE
        v_funds := '"all"'::jsonb;
    END IF;
    
    -- Get warehouses
    IF v_level NOT IN ('platform', 'tenant', 'company') THEN
        SELECT jsonb_agg(jsonb_build_object(
            'warehouse_id', uwp.warehouse_id,
            'is_keeper', uwp.is_keeper,
            'can_receive', uwp.can_receive,
            'can_issue', uwp.can_issue
        ))
        INTO v_warehouses
        FROM user_warehouse_permissions uwp
        WHERE uwp.user_id = p_user_id AND uwp.can_view = true;
    ELSE
        v_warehouses := '"all"'::jsonb;
    END IF;
    
    -- Get branches
    IF v_level NOT IN ('platform', 'tenant', 'company') THEN
        SELECT jsonb_agg(jsonb_build_object(
            'branch_id', ubp.branch_id,
            'is_primary', ubp.is_primary,
            'can_manage', ubp.can_manage
        ))
        INTO v_branches
        FROM user_branch_permissions ubp
        WHERE ubp.user_id = p_user_id AND ubp.can_access = true;
    ELSE
        v_branches := '"all"'::jsonb;
    END IF;
    
    -- Build result
    v_result := jsonb_build_object(
        'user_id', p_user_id,
        'is_super_admin', is_super_admin(p_user_id),
        'is_tenant_admin', is_tenant_admin(p_user_id),
        'is_company_admin', is_company_admin(p_user_id),
        'level', v_level,
        'roles', COALESCE(v_roles, '[]'::jsonb),
        'funds', COALESCE(v_funds, '[]'::jsonb),
        'warehouses', COALESCE(v_warehouses, '[]'::jsonb),
        'branches', COALESCE(v_branches, '[]'::jsonb)
    );
    
    RETURN v_result;
END;
$$;


--
-- Name: get_user_permissions(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_user_permissions(p_user_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_permissions JSONB := '{}'::jsonb;
    v_role_perms JSONB;
BEGIN
    FOR v_role_perms IN
        SELECT r.permissions
        FROM user_roles ur
        JOIN roles r ON ur.role_id = r.id
        WHERE ur.user_id = p_user_id
          AND ur.is_active = true
          AND (ur.expires_at IS NULL OR ur.expires_at > NOW())
    LOOP
        -- Merge permissions (later ones override)
        v_permissions := v_permissions || v_role_perms;
    END LOOP;
    
    RETURN v_permissions;
END;
$$;


--
-- Name: get_user_role_level(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_user_role_level(p_user_id uuid DEFAULT auth.uid()) RETURNS text
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_level TEXT;
BEGIN
    -- التحقق من super_admin أولاً
    IF is_super_admin(p_user_id) THEN
        RETURN 'platform';
    END IF;
    
    -- الحصول على أعلى مستوى
    SELECT COALESCE(
        (r.permissions->>'level')::TEXT,
        'operations'
    ) INTO v_level
    FROM user_roles ur
    JOIN roles r ON ur.role_id = r.id
    WHERE ur.user_id = p_user_id
      AND ur.is_active = true
    ORDER BY 
        CASE (r.permissions->>'level')::TEXT
            WHEN 'tenant' THEN 1
            WHEN 'company' THEN 2
            WHEN 'branch' THEN 3
            WHEN 'operations' THEN 4
            ELSE 5
        END
    LIMIT 1;
    
    RETURN COALESCE(v_level, 'none');
END;
$$;


--
-- Name: get_user_roles(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_user_roles(p_user_id uuid) RETURNS TABLE(role_id uuid, role_code text, role_name_ar text, role_name_en text, role_level text, is_active boolean)
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        r.id AS role_id,
        r.code AS role_code,
        r.name_ar AS role_name_ar,
        r.name_en AS role_name_en,
        r.level AS role_level,
        ur.is_active
    FROM user_roles ur
    JOIN roles r ON ur.role_id = r.id
    WHERE ur.user_id = p_user_id
      AND ur.is_active = true;
EXCEPTION
    WHEN OTHERS THEN
        -- Return empty on error
        RETURN;
END;
$$;


--
-- Name: get_user_special_permissions(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_user_special_permissions(p_user_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_permissions JSONB := '{}'::jsonb;
    v_role_sp JSONB;
    v_is_super BOOLEAN := false;
BEGIN
    -- Check if user is super_admin / tenant_owner / company_owner
    SELECT EXISTS (
        SELECT 1 FROM user_roles ur
        JOIN roles r ON ur.role_id = r.id
        WHERE ur.user_id = p_user_id
          AND ur.is_active = true
          AND r.code IN ('super_admin', 'tenant_owner', 'company_owner')
    ) INTO v_is_super;
    
    -- If super_admin / tenant_owner / company_owner, return all permissions as true
    IF v_is_super THEN
        RETURN '{
            "can_edit_posted_purchase": true,
            "can_edit_posted_sale": true,
            "can_edit_posted_journal": true,
            "can_delete_posted": true,
            "can_unpost": true,
            "can_edit_closed_period": true,
            "can_view_audit_log": true,
            "can_view_all_branches": true,
            "can_manage_roles": true,
            "can_approve_transactions": true,
            "can_view_cost_prices": true,
            "can_view_profit_margins": true,
            "can_export_data": true,
            "can_manage_containers": true
        }'::jsonb;
    END IF;
    
    -- Merge special_permissions from all active roles
    FOR v_role_sp IN
        SELECT COALESCE(r.special_permissions, '{}'::jsonb)
        FROM user_roles ur
        JOIN roles r ON ur.role_id = r.id
        WHERE ur.user_id = p_user_id
          AND ur.is_active = true
          AND (ur.expires_at IS NULL OR ur.expires_at > NOW())
          AND r.special_permissions IS NOT NULL
    LOOP
        -- Merge: true overrides false (permissive merge)
        v_permissions := v_permissions || v_role_sp;
    END LOOP;
    
    RETURN v_permissions;
END;
$$;


--
-- Name: get_user_visible_modules(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_user_visible_modules(p_user_id uuid) RETURNS text[]
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    result TEXT[];
BEGIN
    SELECT COALESCE(
        array_agg(DISTINCT unnest_module),
        ARRAY['dashboard']::TEXT[]
    ) INTO result
    FROM (
        SELECT unnest(r.visible_modules) as unnest_module
        FROM user_roles ur
        JOIN roles r ON ur.role_id = r.id
        WHERE ur.user_id = p_user_id
          AND ur.is_active = true
    ) sub;
    
    RETURN COALESCE(result, ARRAY['dashboard']::TEXT[]);
END;
$$;


--
-- Name: get_warehouse_settings(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_warehouse_settings(p_tenant_id uuid, p_company_id uuid) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_settings RECORD;
BEGIN
    SELECT * INTO v_settings
    FROM warehouse_settings
    WHERE tenant_id = p_tenant_id
    AND company_id = p_company_id
    LIMIT 1;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'costing_method', 'fifo',
            'require_dispatch_approval', true,
            'default_reservation_hours', 48,
            'allow_negative_stock', false,
            'warn_dye_lot_mismatch', true
        );
    END IF;
    
    RETURN to_jsonb(v_settings);
END;
$$;


--
-- Name: get_workflow_settings(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_workflow_settings(p_company_id uuid) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_settings JSONB;
BEGIN
    SELECT to_jsonb(cws.*) INTO v_settings
    FROM company_workflow_settings cws
    WHERE cws.company_id = p_company_id
    LIMIT 1;

    -- Return defaults if no settings exist
    IF v_settings IS NULL THEN
        v_settings := jsonb_build_object(
            'require_manager_approval_quotation', false,
            'require_manager_approval_order', false,
            'require_manager_approval_invoice', false,
            'require_manager_approval_reservation', false,
            'approval_amount_threshold', 0,
            'auto_create_delivery_on_confirm', true,
            'allow_edit_after_confirm', false,
            'edit_after_confirm_roles', ARRAY['company_admin', 'tenant_owner'],
            'notify_warehouse_on_confirm', true,
            'notify_manager_on_save', false,
            'notify_channel', 'internal',
            'require_payment_for_confirmation', false,
            'min_payment_percent', 0,
            -- Posting settings
            'auto_post_invoice', false,
            'auto_post_delivery', false,
            'auto_post_receipt', false,
            'auto_post_return', false,
            'require_post_confirmation', true
        );
    END IF;

    RETURN v_settings;
END;
$$;


--
-- Name: increment_reserved_quantity(uuid, numeric); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.increment_reserved_quantity(p_item_id uuid, p_quantity numeric) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    UPDATE shipment_items
    SET reserved_quantity = COALESCE(reserved_quantity, 0) + p_quantity,
        updated_at = NOW()
    WHERE id = p_item_id;
END;
$$;


--
-- Name: increment_version(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.increment_version() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    NEW.version := COALESCE(OLD.version, 0) + 1;
    RETURN NEW;
END;
$$;


--
-- Name: is_admin_user(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.is_admin_user(p_user_id uuid DEFAULT auth.uid()) RETURNS boolean
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
BEGIN
    RETURN EXISTS (
        SELECT 1 FROM user_roles ur
        JOIN roles r ON ur.role_id = r.id
        WHERE ur.user_id = p_user_id
          AND ur.is_active = true
          AND r.code IN ('super_admin', 'tenant_owner', 'company_admin')
    );
EXCEPTION
    WHEN OTHERS THEN
        RETURN false;
END;
$$;


--
-- Name: is_company_admin(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.is_company_admin(p_user_id uuid DEFAULT auth.uid(), p_company_id uuid DEFAULT NULL::uuid) RETURNS boolean
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
BEGIN
    IF is_super_admin(p_user_id) OR is_tenant_admin(p_user_id) THEN
        RETURN true;
    END IF;
    
    RETURN EXISTS (
        SELECT 1 FROM user_roles ur
        JOIN roles r ON ur.role_id = r.id
        WHERE ur.user_id = p_user_id
          AND r.code IN ('company_owner', 'company_admin')
          AND ur.is_active = true
    );
END;
$$;


--
-- Name: is_mfa_required(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.is_mfa_required(p_user_id uuid) RETURNS boolean
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_system_enforce_all BOOLEAN;
    v_system_enforce_admins BOOLEAN;
    v_enforced_roles TEXT[];
    v_user_roles TEXT[];
BEGIN
    -- Get system settings
    SELECT enforce_for_all, enforce_for_admins, enforced_roles 
    INTO v_system_enforce_all, v_system_enforce_admins, v_enforced_roles
    FROM mfa_system_settings LIMIT 1;
    
    -- If enforced for all
    IF COALESCE(v_system_enforce_all, false) THEN
        RETURN true;
    END IF;
    
    -- Get user roles from the new schema
    SELECT array_agg(r.code::TEXT) INTO v_user_roles
    FROM user_roles ur
    JOIN roles r ON ur.role_id = r.id
    WHERE ur.user_id = p_user_id
      AND ur.is_active = true;
    
    -- Check if user has an enforced role
    IF v_user_roles IS NOT NULL AND v_enforced_roles IS NOT NULL THEN
        IF v_user_roles && v_enforced_roles THEN
            RETURN true;
        END IF;
    END IF;
    
    -- If enforced for admins
    IF COALESCE(v_system_enforce_admins, false) AND v_user_roles IS NOT NULL THEN
        IF v_user_roles && ARRAY['super_admin', 'tenant_owner', 'company_admin']::TEXT[] THEN
            RETURN true;
        END IF;
    END IF;
    
    RETURN false;
EXCEPTION
    WHEN OTHERS THEN
        -- If any error, return false (don't block user)
        RETURN false;
END;
$$;


--
-- Name: is_super_admin(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.is_super_admin(p_user_id uuid DEFAULT auth.uid()) RETURNS boolean
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
BEGIN
    RETURN EXISTS (
        SELECT 1 FROM user_roles ur
        JOIN roles r ON ur.role_id = r.id
        WHERE ur.user_id = p_user_id
          AND ur.is_active = true
          AND r.code = 'super_admin'
    );
EXCEPTION
    WHEN OTHERS THEN
        RETURN false;
END;
$$;


--
-- Name: is_tenant_admin(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.is_tenant_admin(p_user_id uuid DEFAULT auth.uid()) RETURNS boolean
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
BEGIN
    IF is_super_admin(p_user_id) THEN
        RETURN true;
    END IF;
    
    RETURN EXISTS (
        SELECT 1 FROM user_roles ur
        JOIN roles r ON ur.role_id = r.id
        WHERE ur.user_id = p_user_id
          AND r.code = 'tenant_admin'
          AND ur.is_active = true
    );
END;
$$;


--
-- Name: is_tenant_owner(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.is_tenant_owner(p_user_id uuid DEFAULT auth.uid()) RETURNS boolean
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_user_email TEXT;
    v_tenant_id UUID;
    v_owner_email TEXT;
BEGIN
    -- Super Admin يرى كل شيء
    IF is_super_admin(p_user_id) THEN
        RETURN true;
    END IF;
    
    -- Get user's email and tenant_id
    SELECT email, tenant_id INTO v_user_email, v_tenant_id
    FROM user_profiles
    WHERE id = p_user_id;
    
    IF v_tenant_id IS NULL THEN
        RETURN false;
    END IF;
    
    -- Check if user is the tenant owner
    SELECT owner_email INTO v_owner_email
    FROM tenants
    WHERE id = v_tenant_id;
    
    RETURN v_user_email = v_owner_email;
EXCEPTION WHEN OTHERS THEN
    RETURN false;
END;
$$;


--
-- Name: is_valid_stage_transition(text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.is_valid_stage_transition(p_type text, p_from text, p_to text) RETURNS boolean
    LANGUAGE plpgsql IMMUTABLE
    AS $$
BEGIN
    IF p_type = 'purchase' THEN
        RETURN (p_from, p_to) IN (
            ('draft', 'quotation'),
            ('draft', 'order'),
            ('draft', 'invoice'),
            ('quotation', 'order'),
            ('quotation', 'invoice'),
            ('order', 'approved'),
            ('approved', 'receipt'),
            ('approved', 'invoice'),
            ('receipt', 'invoice'),
            ('invoice', 'posted'),
            ('posted', 'partial_paid'),
            ('posted', 'paid'),
            ('partial_paid', 'paid'),
            ('draft', 'cancelled'),
            ('quotation', 'cancelled'),
            ('order', 'cancelled'),
            ('approved', 'cancelled'),
            ('receipt', 'cancelled'),
            ('invoice', 'cancelled'),
            ('cancelled', 'draft')
        );
    END IF;

    IF p_type = 'sale' THEN
        RETURN (p_from, p_to) IN (
            ('draft', 'quotation'),
            ('draft', 'order'),
            ('draft', 'invoice'),
            ('quotation', 'reservation'),
            ('quotation', 'order'),
            ('reservation', 'order'),
            ('order', 'delivery'),
            ('order', 'invoice'),
            ('delivery', 'invoice'),
            ('invoice', 'posted'),
            ('posted', 'partial_paid'),
            ('posted', 'paid'),
            ('partial_paid', 'paid'),
            ('draft', 'cancelled'),
            ('quotation', 'cancelled'),
            ('reservation', 'cancelled'),
            ('order', 'cancelled'),
            ('delivery', 'cancelled'),
            ('invoice', 'cancelled'),
            ('cancelled', 'draft')
        );
    END IF;

    RETURN false;
END;
$$;


--
-- Name: lock_subscription(uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.lock_subscription(p_subscription_id uuid, p_reason text DEFAULT 'Payment overdue'::text) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE subscriptions
    SET 
        status = 'locked',
        locked_at = NOW(),
        lock_reason = p_reason,
        updated_at = NOW()
    WHERE id = p_subscription_id
    AND locked_at IS NULL;
    
    RETURN FOUND;
END;
$$;


--
-- Name: log_audit(character varying, character varying, uuid, character varying, jsonb, jsonb, jsonb, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.log_audit(p_action character varying, p_entity_type character varying, p_entity_id uuid DEFAULT NULL::uuid, p_entity_name character varying DEFAULT NULL::character varying, p_old_values jsonb DEFAULT NULL::jsonb, p_new_values jsonb DEFAULT NULL::jsonb, p_metadata jsonb DEFAULT '{}'::jsonb, p_severity character varying DEFAULT 'info'::character varying) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_audit_id UUID;
    v_changes JSONB;
    v_tenant_id UUID;
BEGIN
    -- حساب التغييرات
    IF p_old_values IS NOT NULL AND p_new_values IS NOT NULL THEN
        SELECT jsonb_object_agg(key, value)
        INTO v_changes
        FROM jsonb_each(p_new_values)
        WHERE p_old_values -> key IS DISTINCT FROM value;
    END IF;
    
    v_tenant_id := COALESCE(
        get_current_tenant_id(),
        (p_new_values ->> 'tenant_id')::uuid,
        (p_old_values ->> 'tenant_id')::uuid,
        (CASE WHEN p_entity_type = 'tenants' THEN p_entity_id ELSE NULL END)
    );

    INSERT INTO audit_logs (
        tenant_id,
        user_id,
        action,
        table_name,
        entity_type,
        record_id,
        entity_id,
        entity_name,
        old_values,
        new_values,
        changes,
        metadata,
        severity
    ) VALUES (
        v_tenant_id,
        auth.uid(),
        p_action,
        p_entity_type,
        p_entity_type,
        p_entity_id,
        p_entity_id,
        p_entity_name,
        p_old_values,
        p_new_values,
        v_changes,
        p_metadata,
        p_severity
    )
    RETURNING id INTO v_audit_id;
    
    RETURN v_audit_id;
END;
$$;


--
-- Name: log_subscription_status_change(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.log_subscription_status_change() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF OLD.status IS DISTINCT FROM NEW.status THEN
        INSERT INTO subscription_status_history (
            subscription_id,
            tenant_id,
            old_status,
            new_status,
            reason
        ) VALUES (
            NEW.id,
            NEW.tenant_id,
            OLD.status,
            NEW.status,
            NEW.lock_reason
        );
    END IF;
    
    RETURN NEW;
END;
$$;


