-- Name: on_company_created(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.on_company_created() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    IF NEW.accounting_settings->>'chart_type' = 'extended' THEN
        PERFORM create_extended_chart(NEW.id);
        RAISE NOTICE 'تم إنشاء شجرة الحسابات الموسعة للشركة الجديدة: %', NEW.id;
    ELSE
