--
-- Name: renew_subscription(uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.renew_subscription(p_subscription_id uuid, p_months integer DEFAULT 1) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_subscription RECORD;
    v_new_end DATE;
    v_result JSONB;
BEGIN
    -- الحصول على الاشتراك
    SELECT * INTO v_subscription
    FROM subscriptions
    WHERE id = p_subscription_id;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'subscription_not_found');
    END IF;
    
    -- حساب التاريخ الجديد
    IF v_subscription.current_period_end IS NULL OR 
       v_subscription.current_period_end < CURRENT_DATE THEN
        v_new_end := CURRENT_DATE + (p_months * INTERVAL '1 month');
    ELSE
        v_new_end := v_subscription.current_period_end + (p_months * INTERVAL '1 month');
    END IF;
    
    -- تحديث الاشتراك
    UPDATE subscriptions
    SET 
        status = 'active',
        current_period_end = v_new_end,
        locked_at = NULL,
        lock_reason = NULL,
        updated_at = NOW()
    WHERE id = p_subscription_id;
    
    -- تسجيل
    PERFORM log_audit(
        'renew',
        'subscriptions',
        p_subscription_id,
        NULL,
        NULL,
        jsonb_build_object('new_period_end', v_new_end, 'months', p_months)
    );
    
    RETURN jsonb_build_object(
        'success', true,
        'new_period_end', v_new_end,
        'months_added', p_months
    );
END;
$$;


--
-- Name: run_isolation_tests(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.run_isolation_tests() RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_results JSONB := '[]'::JSONB;
    v_test RECORD;
    v_summary JSONB;
    v_pass INT := 0;
    v_fail INT := 0;
    v_warn INT := 0;
BEGIN
    FOR v_test IN SELECT * FROM test_tenant_isolation()
    LOOP
        v_results := v_results || jsonb_build_object(
            'name', v_test.test_name,
            'result', v_test.result,
            'details', v_test.details
        );
        
        IF v_test.result LIKE '%PASS%' THEN
            v_pass := v_pass + 1;
        ELSIF v_test.result LIKE '%FAIL%' THEN
            v_fail := v_fail + 1;
        ELSE
            v_warn := v_warn + 1;
        END IF;
    END LOOP;
    
    v_summary := jsonb_build_object(
        'total', v_pass + v_fail + v_warn,
        'passed', v_pass,
        'failed', v_fail,
        'warnings', v_warn,
        'status', CASE 
            WHEN v_fail > 0 THEN 'FAILED'
            WHEN v_warn > 0 THEN 'WARNING'
            ELSE 'PASSED'
        END
    );
    
    RETURN jsonb_build_object(
        'summary', v_summary,
        'tests', v_results,
        'timestamp', NOW()
    );
END;
$$;


