--
-- Name: unlock_subscription(uuid, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.unlock_subscription(p_subscription_id uuid, p_new_period_end timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE subscriptions
    SET 
        status = 'active',
        locked_at = NULL,
        lock_reason = NULL,
        current_period_end = COALESCE(p_new_period_end, current_period_end + INTERVAL '30 days'),
        updated_at = NOW()
    WHERE id = p_subscription_id;
    
    RETURN FOUND;
END;
$$;


--
-- Name: unpost_journal_entry(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.unpost_journal_entry(p_entry_id uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_entry RECORD;
    v_line RECORD;
BEGIN
    SELECT * INTO v_entry
    FROM journal_entries
    WHERE id = p_entry_id;
    
    IF NOT FOUND THEN
        RAISE EXCEPTION 'القيد غير موجود';
    END IF;
    
    IF NOT v_entry.is_posted THEN
        RAISE EXCEPTION 'القيد غير مرحّل';
    END IF;
    
    -- Reverse: subtract Net (Dr-Cr) that was added during posting
    FOR v_line IN 
        SELECT * FROM journal_entry_lines WHERE entry_id = p_entry_id
    LOOP
        UPDATE chart_of_accounts
        SET current_balance = COALESCE(current_balance, 0) - (v_line.debit - v_line.credit),
            updated_at = NOW()
        WHERE id = v_line.account_id;
    END LOOP;
    
    UPDATE journal_entries
    SET is_posted = false,
        posted_at = NULL,
        posted_by = NULL,
        status = 'draft'
    WHERE id = p_entry_id;
    
    RETURN true;
END;
$$;


--
-- Name: unpost_journal_entry(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.unpost_journal_entry(p_entry_id uuid, p_user_id uuid DEFAULT NULL::uuid) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_entry RECORD;
    v_line RECORD;
    v_movement DECIMAL(15,2);
BEGIN
    SELECT * INTO v_entry FROM journal_entries WHERE id = p_entry_id;
    IF NOT FOUND THEN RAISE EXCEPTION 'القيد غير موجود'; END IF;
    IF NOT v_entry.is_posted THEN RETURN true; END IF;
    
    FOR v_line IN 
        SELECT jel.*, at.normal_balance
        FROM journal_entry_lines jel
        JOIN chart_of_accounts coa ON jel.account_id = coa.id
        JOIN account_types at ON coa.account_type_id = at.id
        WHERE jel.entry_id = p_entry_id
    LOOP
        IF v_line.normal_balance = 'debit' THEN
            v_movement := v_line.debit - v_line.credit;
        ELSE
            v_movement := v_line.credit - v_line.debit;
        END IF;
        UPDATE chart_of_accounts
        SET current_balance = current_balance - v_movement, updated_at = NOW()
        WHERE id = v_line.account_id;
    END LOOP;
    
    UPDATE journal_entries
    SET is_posted = false, posted_at = NULL, status = 'draft'
    WHERE id = p_entry_id;
    RETURN true;
END;
$$;


