--
-- Name: update_purchase_document_status_bypass_rls(text, uuid, text, uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_purchase_document_status_bypass_rls(p_table text, p_id uuid, p_status text, p_receipt_id uuid, p_receipt_number text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    IF p_table = 'purchase_orders' THEN
        UPDATE purchase_orders SET status = p_status, updated_at = NOW() WHERE id = p_id;
    ELSIF p_table = 'purchase_invoices' THEN
        UPDATE purchase_invoices SET status = p_status, updated_at = NOW() WHERE id = p_id;
    END IF;
END;
$$;


--
-- Name: update_shipment_document_status(uuid, character varying, text, numeric, numeric, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_shipment_document_status(p_shipment_doc_id uuid, p_new_status character varying, p_status_description text DEFAULT NULL::text, p_cod_collected numeric DEFAULT NULL::numeric, p_carrier_commission numeric DEFAULT NULL::numeric, p_api_response jsonb DEFAULT NULL::jsonb) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    UPDATE shipment_documents
    SET status = p_new_status,
        status_description = COALESCE(p_status_description, status_description),
        cod_collected = COALESCE(p_cod_collected, cod_collected),
        carrier_commission = COALESCE(p_carrier_commission, carrier_commission),
        delivered_at = CASE WHEN p_new_status = 'delivered' THEN NOW() ELSE delivered_at END,
        actual_delivery_date = CASE WHEN p_new_status = 'delivered' THEN CURRENT_DATE ELSE actual_delivery_date END,
        returned_at = CASE WHEN p_new_status = 'returned' THEN NOW() ELSE returned_at END,
        picked_up_at = CASE WHEN p_new_status = 'in_transit' THEN COALESCE(picked_up_at, NOW()) ELSE picked_up_at END,
        last_status_check = NOW(),
        status_history = status_history || jsonb_build_array(
            jsonb_build_object(
                'status', p_new_status,
                'date', to_char(NOW(), 'YYYY-MM-DD HH24:MI:SS'),
                'description', p_status_description
            )
        ),
        api_response = COALESCE(p_api_response, api_response),
        updated_at = NOW()
    WHERE id = p_shipment_doc_id;
    
    RETURN jsonb_build_object(
        'success', true,
        'new_status', p_new_status,
        'shipment_document_id', p_shipment_doc_id
    );
END;
$$;


