--
-- Name: update_storage_quota(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_storage_quota() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF TG_OP = 'INSERT' THEN
        -- زيادة الاستخدام عند رفع ملف جديد
        UPDATE storage_quotas
        SET 
            used_storage_bytes = used_storage_bytes + NEW.file_size,
            current_files_count = current_files_count + 1,
            updated_at = NOW()
        WHERE tenant_id = NEW.tenant_id;
        
        -- إنشاء سجل جديد إذا لم يكن موجوداً
        INSERT INTO storage_quotas (tenant_id, used_storage_bytes, current_files_count)
        VALUES (NEW.tenant_id, NEW.file_size, 1)
        ON CONFLICT (tenant_id) DO NOTHING;
        
        RETURN NEW;
    ELSIF TG_OP = 'DELETE' THEN
        -- تقليل الاستخدام عند حذف ملف
        UPDATE storage_quotas
        SET 
            used_storage_bytes = GREATEST(0, used_storage_bytes - OLD.file_size),
            current_files_count = GREATEST(0, current_files_count - 1),
            updated_at = NOW()
        WHERE tenant_id = OLD.tenant_id;
        
        RETURN OLD;
    END IF;
    
    RETURN NULL;
END;
$$;


--
-- Name: update_summary_account_balance(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_summary_account_balance() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    -- تحديث رصيد الحساب الملخص = مجموع أرصدة الحسابات الفرعية
    UPDATE chart_of_accounts
    SET current_balance = COALESCE((
        SELECT SUM(current_balance)
        FROM chart_of_accounts sub
        WHERE sub.parent_id = NEW.parent_id
          AND sub.is_party_account = true
    ), 0),
    updated_at = now()
    WHERE parent_id = NEW.parent_id
      AND is_summary_account = true;

    RETURN NEW;
END;
$$;


