    chart_type character varying(20) DEFAULT 'simple'::character varying,
    accounting_settings jsonb DEFAULT '{"edit_settings": {"require_edit_reason": true, "notify_on_posted_edit": false, "auto_repost_after_save": true, "allow_direct_edit_posted": true}, "notifications": {"large_adjustment_threshold": 10000, "notify_on_large_adjustments": true, "notify_cfo_on_closed_year_edit": true}, "fiscal_year_mode": "independent", "closed_year_settings": {"auto_link_adjustments": true, "allow_edit_closed_year": true, "allow_delete_closed_year": false, "require_adjustment_entry": false}, "closed_period_settings": {"allow_edit_closed_period": false, "require_manager_approval": true}}'::jsonb,
    brand_id uuid,
    integrations jsonb DEFAULT '{}'::jsonb,
