    settings jsonb DEFAULT '{}'::jsonb
);


--
-- Name: company_accounting_settings; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.company_accounting_settings AS
 SELECT id AS company_id,
    COALESCE((accounting_settings ->> 'base_currency'::text), 'USD'::text) AS base_currency,
    COALESCE((accounting_settings ->> 'local_currency'::text), 'USD'::text) AS local_currency,
    COALESCE((accounting_settings -> 'supported_currencies'::text), '["USD"]'::jsonb) AS supported_currencies,
    COALESCE((accounting_settings ->> 'fiscal_year_start'::text), 'January'::text) AS fiscal_year_start,
    accounting_settings
   FROM public.companies;


