--
-- Name: v_all_pages; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_all_pages AS
 SELECT wp.id,
    wp.tenant_id,
    wp.company_id,
    ws.name AS site_name,
    ws.slug AS site_slug,
    wp.slug AS page_slug,
    wp.page_type,
    wp.page_category,
    wp.title_ar,
    wp.title_en,
    wp.title_uk,
    wp.title_tr,
    wp.seo_title_ar,
    wp.seo_title_en,
    wp.seo_description_ar,
    wp.seo_description_en,
    wp.show_in_nav,
    wp.show_in_footer,
    wp.show_in_header,
    wp.is_published,
    wp.sort_order,
    wp.featured_image,
    wp.store_id,
    wp.created_at,
    wp.updated_at
   FROM (public.website_pages wp
     JOIN public.website_sites ws ON ((ws.id = wp.site_id)))
  WHERE (ws.is_active = true);


