--

CREATE POLICY "Admin can delete branches" ON public.branches FOR DELETE USING ((company_id IN ( SELECT user_profiles.company_id
   FROM public.user_profiles
  WHERE (user_profiles.id = auth.uid()))));


--
-- Name: branches Admin can insert branches; Type: POLICY; Schema: public; Owner: -
