-- Name: platform_announcements Super admins can manage platform announcements; Type: POLICY; Schema: public; Owner: -
--

CREATE POLICY "Super admins can manage platform announcements" ON public.platform_announcements USING ((EXISTS ( SELECT 1
   FROM public.user_profiles
  WHERE ((user_profiles.id = auth.uid()) AND ((user_profiles.role)::text = 'super_admin'::text)))));


--
-- Name: company_announcements Tenant owners can manage announcements; Type: POLICY; Schema: public; Owner: -
--

CREATE POLICY "Tenant owners can manage announcements" ON public.company_announcements USING ((tenant_id IN ( SELECT company_announcements.tenant_id
   FROM public.user_profiles
  WHERE ((user_profiles.id = auth.uid()) AND ((user_profiles.role)::text = ANY ((ARRAY['tenant_owner'::character varying, 'super_admin'::character varying])::text[]))))));


--
-- Name: documents Users can delete their uploaded documents; Type: POLICY; Schema: public; Owner: -
--

CREATE POLICY "Users can delete their uploaded documents" ON public.documents FOR DELETE USING (((uploaded_by = auth.uid()) OR (tenant_id IN ( SELECT companies.tenant_id
   FROM public.companies
  WHERE (companies.id IN ( SELECT user_profiles.company_id
           FROM public.user_profiles
          WHERE (user_profiles.id = auth.uid())))))));


